INSERT INTO public."CounterCategory" (id, slug, label, hint, "sortOrder", "createdAt", "updatedAt") VALUES (1, 'numbers', 'Số cơ bản', 'Hệ thập phân: 十（じゅう）= 10 · 百（ひゃく）= 100 · 千（せん）= 1.000 · 万（まん）= 10.000. Ghép số từ trái sang phải: 二十五 = 20 + 5. Một số âm đọc đặc biệt: 300 → さんびゃく, 600 → ろっぴゃく, 800 → はっぴゃく, 3.000 → さんぜん, 8.000 → はっせん.', 0, '2026-06-25 10:52:31.156', '2026-06-25 10:52:31.156');
INSERT INTO public."CounterCategory" (id, slug, label, hint, "sortOrder", "createdAt", "updatedAt") VALUES (2, 'objects', 'Đếm đồ vật', 'Dùng khi đếm vật thể chung (～つ). Từ 1–10 dùng âm thuần Nhật, từ 11 trở đi thường dùng số Hán + こ.', 1, '2026-06-25 10:52:31.175', '2026-06-25 10:52:31.175');
INSERT INTO public."CounterCategory" (id, slug, label, hint, "sortOrder", "createdAt", "updatedAt") VALUES (3, 'people', 'Đếm người', 'Dùng trợ từ 人（にん／り）. 1 người và 2 người đọc đặc biệt: ひとり、ふたり.', 2, '2026-06-25 10:52:31.185', '2026-06-25 10:52:31.185');
INSERT INTO public."CounterCategory" (id, slug, label, hint, "sortOrder", "createdAt", "updatedAt") VALUES (4, 'days', 'Ngày trong tháng', 'Đọc ngày trong tháng (～日). Nhiều ngày đọc không theo quy tắc — cần học thuộc.', 3, '2026-06-25 10:52:31.199', '2026-06-25 10:52:31.199');
INSERT INTO public."CounterCategory" (id, slug, label, hint, "sortOrder", "createdAt", "updatedAt") VALUES (5, 'months', 'Tháng', 'Tháng trong năm: số + がつ. Tháng 4 đọc しがつ, tháng 7 しちがつ, tháng 9 くがつ.', 4, '2026-06-25 10:52:31.213', '2026-06-25 10:52:31.213');
INSERT INTO public."CounterCategory" (id, slug, label, hint, "sortOrder", "createdAt", "updatedAt") VALUES (6, 'age', 'Tuổi', 'Đếm tuổi: số + さい. 20 tuổi đọc đặc biệt はたち.', 5, '2026-06-25 10:52:31.225', '2026-06-25 10:52:31.225');
INSERT INTO public."CounterCategory" (id, slug, label, hint, "sortOrder", "createdAt", "updatedAt") VALUES (7, 'order', 'Thứ tự', 'Diễn tả thứ hạng, vị trí: 第（だい）+ số. Ví dụ: 第一 = thứ nhất, hạng nhất.', 6, '2026-06-25 10:52:31.235', '2026-06-25 10:52:31.235');
INSERT INTO public."CounterCategory" (id, slug, label, hint, "sortOrder", "createdAt", "updatedAt") VALUES (8, 'time', 'Giờ & phút', 'Giờ: ～じ. Phút: ～ふん／ぷん (có biến âm: いっぷん, さんぷん, ろっぷん...).', 7, '2026-06-25 10:52:31.245', '2026-06-25 10:52:31.245');
