INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5310, 'N は ～月(がつ) ～日(にち)です。N là ngày ~ tháng ~. Nói năm, sau đó đến tháng và cuối cùng là ngày. Một', '1. N は ～月(がつ) ～日(にち)です。N là ngày ~ tháng ~. Nói năm, sau đó đến tháng và cuối cùng là ngày. Một số câu hỏi thường dùng: N は いつ/ 何月(なんがつ) / 何日(なんにち)ですか。 N là bao giờ / tháng mấy / mùng mấy?', 'Cách dùng: いつ (bao giờ, khi nào) có thể dùng thay thế cho các từ để hỏi có nghĩa tương tự như : なんじ、なんがつ、なんにち', 5, '2026-06-25 11:24:12.115', '2026-06-25 16:04:05.905', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5323, 'だれ に（から）Vますか。～ từ ai?', '', 'Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5335, 'どうして＋Sentence か。', 'Tại sao ~', 'Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5370, 'N (tân ngữ) は', '', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5380, 'Vたり、Vたり　します。lúc thì… lúc thì… và…', '', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5401, 'もし ＆ いくら', '', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5432, 'Thể điều kiện tiếng Nhật là 条件形（じょうけんけい)', 'Tính từ đuôi i: Bỏ い thêm ければ.', '+ Tính từ đuôi na bỏ な thêm なら + Danh từ thêm なら (cũng có ならば nhưng なら được dùng nhiều hơn) * Tính từ đuôi i: Chuyển sang thể phủ định (～くない) và chia như 1 tính từ đuôi –i * Tính từ đuôi na+ danh từ: Chuyển sang thể phủ định (～ではない／～じゃない) và chia như 1 tính từ đuôi –i Nếu…, nếu như… (giống ~と、~たら)', 35, '2026-06-25 11:24:24.742', '2026-06-25 16:04:06.545', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5452, 'Ngữ pháp V て みます。', '', 'Cách dùng: Trong mẫu câu này động từ đứng trước みます chia ở thể て. Vì みます nguyên thủy là một động từ nên cũng chia như các động từ khác.
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5458, 'Ngữ pháp Ａ／Ｎａそうです', '', 'この 料理は おいしそうです。
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5459, 'Ngữ pháp V て来ます (Cách diễn đạt đi đâu đó, làm gì đó rồi quay lại)', '', NULL, 43, '2026-06-25 11:24:28.074', '2026-06-25 16:04:06.65', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5465, 'Ngữ pháp với ~ところです (các mẫu câu với cụm từ ところです)', 'Trước đây, ở bài 8 ta đã học từ 「ところ」với ý nghĩa là nơi, chỗ (chỉ vị trí, địa điểm).', 'Cách dùng: Dùng để diễn tả ý nói một hành động sắp sửa, chuẩn bị diễn ra và nhấn mạnh vào thời điểm trước khi diễn ra hành động đó. Mẫu câu này thường đi kèm với các cụm từ chỉ thời điểm như: 「これから、」、 「(ちょうど)今から」', 46, '2026-06-25 11:24:29.333', '2026-06-25 16:04:06.661', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5385, 'Cách xác nhận thông tin nào đó với mong muốn người nghe tán đồng với ý kiến của mình', 'muốn người nghe tán đồng với ý kiến của mình', 'Cách dùng: dùng khi kỳ vọng rằng người nghe cũng biết hoặc có sự hiểu biết về chuyện mình nói và mong muốn người nghe sẽ tán thành ý kiến của mình. でしょう được đọc lên giọng giống như 1 câu hỏi để xác nhận sự đồng tình của người nghe.', 21, '2026-06-25 11:24:18.826', '2026-06-25 16:07:35.703', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5470, 'Kính ngữ tiếng Nhật là 尊敬語(そんけいご)', '1) Dùng tiền tố 「お」 và「ご」 (viết chữ Hán đều là 御 (NGỰ) Tiền tố 「お」 và「ご」 được sử dụng rất nhiều trong câu kính ngữ.', 'Cách dùng: Về hình thức, động từ thể hiện kính ngữ kiểu này có cách chia giống hệt động từ dạng bị động. Hầu hết tất cả các động từ đều có thể áp dụng được trừ động từ dạng khả năng (可能形) và một số động từ như: できます、わかります、いります 社長は さっき 出おかけられました。 Giám đốc đã đi ra ngoài lúc nãy rồi ạ. お酒をやめられたんですか。 Anh đã bỏ rượu rồi ạ? いつ ベトナムに来られましたか。 Ngài đến Việt Nam lúc nào thế ạ? 会長は 今アメリカへ 出 張されています。 Chủ tịch đang đi công tác Mỹ おＶます になります – Không áp dụng với động từ nhóm 3 và động từ 1 âm tiết như: 見ます、 寝ます、います… 社長は お帰りに なりました。 Giám đốc đã về rồi ạ. 新聞を お読みに なりますか。 Ngài/Bạn có đọc báo không ạ? 部長は 加藤さんを お呼びに なりました。 Trưởng phòng đã gọi chị Kato A: 今晩何時に 山本さんに お会いに なりますか。 Tối nay mấy giờ ngài sẽ gặp chị Yamamoto? B: ６時１５分過ぎに 会います。 Tôi sẽ gặp lúc 6 giờ 15 ( ６時１５分過ぎに お会いになります。（×） ) Ở cấp độ đơn vị danh từ, ngoài những kính ngữ đặc biệt đã liệt kê ở trên, có thể dung tiếp đầu ngữ「お」 và「ご」 để tạo thành kính ngữ. Tuy nhiên, cũng có danh từ không thể ghép 「お」 hay「ご」 .', 49, '2026-06-25 11:24:30.575', '2026-06-25 16:06:41.946', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5308, 'N (chỉ thời gian) に＋ V ます', 'làm gì vào lúc nào', '• Cách dùng: để chỉ thời điểm tiến hành một hành động. nếu thời gian không biểu hiện bằng những con số thì không thêm に. sau danh từ là các thứ trong tuần ta có thể có に hay không đều được.', 4, '2026-06-25 11:24:11.726', '2026-06-25 16:04:05.899', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5356, 'V（thể ます）しょうか。đề nghị được làm giúp ai đó việc gì', '', 'Cách dùng: người nói ngỏ ý làm gì đó giúp cho người nghe.', 14, '2026-06-25 11:24:15.896', '2026-06-25 16:04:06.152', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5309, '～から～まで', 'Từ ~ đến ~', '• Cách dùng: cách nói khoảng thời gian, trợ từ から biểu thị điểm bắt đầu của thời gian hay nơi chốn, trợ từ まで biểu thị điểm kết thúc của thời gian hay nơi chốn (2 trợ từ không nhất thiết đi cùng nhau)', 4, '2026-06-25 11:24:11.731', '2026-06-25 16:06:41.902', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5322, 'だれにVますか。', 'Làm ~ cho ai?', 'Cách dùng: に là trợ từ chỉ hướng đến của hành động “cho ai” .
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5297, 'ここ・そこ・あそこ は N ( địa điểm ) です', 'Chỗ này/đó/kia là N', 'Cách dùng: – ここ・そこ・あそこ là các đại danh từ chỉ nơi chốn – ここ chỉ chỗ của người nói. (Trong phạm vi của người nói) そこ là chỗ của người nghe. (Trong phạm vi của người nghe) あそこ chỉ nơi xa cả hai người.', 3, '2026-06-25 11:24:11.296', '2026-06-25 16:04:05.819', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3677, '~さん', 'Cách dùng: – Trong tiếng Nhật sử dụng chữ さん đứng ngay sau tên của người nghe hoặc người thứ 3 để bày tỏ sự kính trọng đối với người đó. – Chữ さん không bao giờ', 'Cách dùng: – Trong tiếng Nhật sử dụng chữ さん đứng ngay sau tên của người nghe hoặc người thứ 3 để bày tỏ sự kính trọng đối với người đó. – Chữ さん không bao giờ sử dụng sau tên của chính mình.
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3672, 'N1 は N2 です', 'N1 là N2', 'Cách dùng : – Danh từ đứng trước は là chủ đề hoặc chủ ngữ trong câu.
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3673, 'N1 は N2 ではありません。', 'N1 không phải là N2', 'Cách dùng: – ではありません là dạng phủ định của です. – Trong hội thoại người ta có thể dùng じゃありません thay cho ではありません
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3674, 'S + か', '1) Câu hỏi nghi vấn (câu hỏi Có Không)', '1) Câu hỏi nghi vấn (câu hỏi Có Không)
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3675, 'N も', 'N cũng', NULL, 1, '2026-06-25 10:52:56.127', '2026-06-25 10:52:56.127', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3676, 'N1 の N2', 'N2 của N1, N2 thuộc về N1', NULL, 1, '2026-06-25 10:52:56.133', '2026-06-25 10:52:56.133', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3678, '~さい', '~ tuổi (hậu tố chỉ tuổi)', 'Đứng sau số để chỉ tuổi. Viết bằng kanji là 歳.
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3679, 'Các từ chỉ thị', 'Cái N này/đó/kia', 'Cách dùng: – この、その、あの là các từ chỉ thị bổ nghĩa cho danh từ. Về tương quan khoảng cách thì giống với これ、それ、あれ nhưng khác về cách sử dụng vì luôn phải có danh từ đi liền đằng sau.
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3680, 'そうです/そうではありません', 'Đúng vậy/Không phải thế', 'Cách dùng: – そう được sử dụng để trả lời câu hỏi nghi vấn mà tận cùng là danh từ. – Trong câu khẳng định dùng: はい、そうです。 Trong câu phủ định dùng: いいえ、そうでは(じゃ)ありません。 Chú ý: Trong trường hợp câu nghi vấn mà tận cùng là động từ hay tính từ thì không sử dụng そうです hay そうではありません để trả lời.', 2, '2026-06-25 10:52:56.394', '2026-06-25 10:52:56.394', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3681, 'N1 ですか、N2 ですか', 'N1 hay là N2?', 'Chú ý: Khi trả lời câu hỏi này không dùng はいhay いいえ', 2, '2026-06-25 10:52:56.398', '2026-06-25 10:52:56.398', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3682, 'N1の N2 (tiếp)', 'N2 của N1', 'Cách dùng: Ở bài trước, N1 là một tổ chức mà N2 thuộc vào đó. Ở bài này trợ từ の có ý nghĩa chỉ sự sở hữu. N2 thuộc sở hữu của N1
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (3683, 'そうですか', 'Ra vậy', 'Cách dùng: Sử dụng khi người nói nhận được thông tin mới và thể hiện rằng đã hiểu về nó.', 2, '2026-06-25 10:52:56.41', '2026-06-25 10:52:56.41', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5298, 'N (địa điểm) は どこ ですか.', 'N ở đâu?', '[N (địa điểm) は] ここ・そこ・あそこです。[N] ở chỗ này/đó/kia/.', 3, '2026-06-25 11:24:11.301', '2026-06-25 16:04:05.835', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5299, 'こちら・そちら・あちら・どちら (đại danh từ chỉ phương hướng)', '', '• Cách dùng: Nghĩa và cách dùng giống với ここ・そこ・あそこ・どこ.', 3, '2026-06-25 11:24:11.304', '2026-06-25 16:04:05.846', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5300, '（お）国はどちらですか。', '', 'Okuni wa dochira desuka.
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5301, 'あなたのかいしゃは どちらですか。', '', 'Anata no kaisha wa dochira desuka.
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5355, '今何をしていますか。', 'Bây giờ bạn đang làm gì vậy?', 'Cách dùng: dùng để diễn tả một hành động đang diễn ra tại thời điểm nói.', 14, '2026-06-25 11:24:15.891', '2026-06-25 16:04:06.147', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5357, 'Bài 15', '• Ví dụ: このほんを借りてもいいですか。', 'Kono hon o karite mo īdesu ka. Tôi có thể mượn quyển sách này được không. ええ、いいですよ。 Ee, īdesu yo. Vâng, được すみません、ちょっと、、、今つかっています。 Sumimasen, chotto,,, ima tsukatte imasu. Xin lỗi, để tôi xem … bây giờ, tôi đang dùng nó. あなたはテレビをつけてもいいです。 Anata wa terebi wo tsukete mo īdesu. Bạn có thể bật tivi lên.', 15, '2026-06-25 11:24:16.277', '2026-06-25 11:24:16.277', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5302, 'これ・それ・あれ は N1 の N2 です。', 'Cái này/cái kia/cái đó là N2 của N1', 'Cách dùng: chỉ xuất xứ của một sản phẩm.', 3, '2026-06-25 11:24:11.315', '2026-06-25 16:04:05.853', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5303, 'N は いくらですか。', 'N bao nhiêu tiền?', NULL, 3, '2026-06-25 11:24:11.319', '2026-06-25 16:04:05.864', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5304, '今なんじですか', 'Bây giờ là mấy giờ? …～ 時 ～ 分 で: Bây giờ là ~ giờ ~ phút', 'Cách dùng: – じ đặt sau số đếm, dùng chỉ giờ. – ふん（ぷん）đặt sau số đếm, dùng chỉ phút.', 4, '2026-06-25 11:24:11.709', '2026-06-25 16:04:05.869', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5305, 'N (danh từ chỉ ngày) は 何曜(なんよう)日(び)ですか。', 'N là thứ mấy?', 'N (danh từ chỉ ngày) は ～曜日 です : N là thứ ~.', 4, '2026-06-25 11:24:11.714', '2026-06-25 16:04:05.876', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5306, 'Vます', 'Động từ dạng ます', '• Cách dùng: động từ biểu thị thái độ lịch sự với người nghe, thể hiện một hành động ở thì hiện tại hoặc tương lai.', 4, '2026-06-25 11:24:11.718', '2026-06-25 16:04:05.884', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5307, 'V ます／ V ません／ V ました / Vませんでした。', 'Chia thì của động từ', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5311, 'N (Danh từ chỉ địa điểm) へ いきます/ きます/ かえります', 'Đi/Đến/Về đâu đó (địa điểm N)', 'Cách dùng: Trợ từ も + thể phủ định của động từ: dùng để phủ định tất cả những gì trong phạm vi mà từ để hỏi どこ đưa ra. Có thể dùngも hoặc để cả へも đều được, nhưng dùng へも thì ý nghĩa phủ định sẽ mạnh hơn.', 5, '2026-06-25 11:24:12.119', '2026-06-25 11:24:12.119', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5319, 'なん／なに (何)', '', '• なん:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5312, '〔～へ〕 なんで ～ (động từ) か。Đi/đến đâu bằng phương tiện gì?', '', '~ で いきます/ きます / かえります : Đi/ đến/ về bằng phương tiện ~', 5, '2026-06-25 11:24:12.125', '2026-06-25 16:04:05.911', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5313, 'だれと ～ V ますか。', 'Bạn đã làm gì với ai?', 'Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5314, 'なにを Vますか。Bạn làm cái gì (ăn gì, uống gì, đọc gì…)? Hoặc なにを しますか。Bạn làm cái gì vậy? (câu hỏi chung', '1. なにを Vますか。Bạn làm cái gì (ăn gì, uống gì, đọc gì…)? Hoặc なにを しますか。Bạn làm cái gì vậy? (câu hỏi chung cho tất cả các động từ) N をVます。', 'Cách dùng: N là đối tượng của hành động, V là tha động từ (ngoại động từ), を là trợ từ (chỉ đối tượng tác động của hành động)', 6, '2026-06-25 11:24:12.521', '2026-06-25 16:04:05.928', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5315, 'なにもV ません', 'Không làm gì cả', '• Cách dùng: trợ từ も đi sau từ để hỏi và đi cùng với thể phủ định để phủ
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5316, 'どこで V ますか。', 'Bạn đã/ sẽ làm gì ở đâu?', 'N1 で N2 を V ます: Làm ~ ở/tại N1.', 6, '2026-06-25 11:24:12.536', '2026-06-25 16:04:05.937', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5317, 'いっしょにV ませんか。', 'Cùng làm ~ nhé!', 'Cách dùng: Đây không phải là câu phủ định, mà là câu mang ý mời mọc, rủ rê người khác cùng làm việc gì đó với mình.', 6, '2026-06-25 11:24:12.543', '2026-06-25 16:04:05.943', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5318, 'V ましょう', 'Cùng làm ~ nhé!', '• Cách dùng: Là một lời để nghị cùng làm với mình nhưng trên cơ sở đã biết người kia sẽ đồng ý, mang tính chất hô hào mọi người cùng làm', 6, '2026-06-25 11:24:12.549', '2026-06-25 16:04:05.947', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5320, 'なんで Vますか。Làm ~ bằng gì? N で V ます。', 'Làm ~ bằng N', 'Cách dùng: N: Danh từ chỉ phương tiện, công cụ, で: trợ tự chỉ phương tiện, phương thức, phương pháp thực hiện hành động (cả phương tiện ngôn ngữ).', 7, '2026-06-25 11:24:12.949', '2026-06-25 16:04:05.951', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5321, '(Từ/Câu) は ～語で 何ですか。“Từ/Câu” trong tiếng~ là gì?', 'là gì?', '• Cách dùng: dùng để hỏi cách nói một từ hoặc câu bằng một thứ tiếng nào đó. Khi viết, từ/câu được hỏi thường để trong dấu 「 」(dấu ngoặc kép trong tiếng Nhật)', 7, '2026-06-25 11:24:12.956', '2026-06-25 16:07:35.714', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5325, 'Tính từ', '• Tính từ đuôi い: Có đuôi tận cùng là い : 小(ちい)さい(nhỏ)、大(おお)きい(to)、熱(あつ)い(nóng)… • Tính từ đuôi な :', '1. Tính từ: • Tính từ đuôi い: Có đuôi tận cùng là い : 小(ちい)さい(nhỏ)、大(おお)きい(to)、熱(あつ)い(nóng)… • Tính từ đuôi な : Có đuôi tận cùng là な : ハンサム（な） (đẹp trai)、しんせつ（な）(tốt bụng)、 … • Chú ý: – Đuôi なcó lúc xuất hiện có lúc không xuất hiện trong từ và câu. – Một số từ dễ nhầm với tình từ đuôi い: きれい（な）(đẹp, sạch)、 きらい（な）(ghét, không thích)', 8, '2026-06-25 11:24:13.398', '2026-06-25 11:24:13.398', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5326, 'Các mẫu câu với tính từ', '', 'Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5327, 'N1 は どんな N2 ですか。', 'N1 là N2 như thế nào?', 'Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5328, 'あまり＋．．．phủ định của tính từ', 'Không ~ lắm / Không ~ mấy', '• Cách dùng: あまり đứng trước tính từ dạng phủ định thể hiện sự phủ định một phần.', 8, '2026-06-25 11:24:13.416', '2026-06-25 16:04:05.998', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5329, 'Sentence1 が、Sentence2', 'S1 nhưng mà S2', '• Cách dùng: Trợ từ が có nghĩa là “nhưng”, dùng để nối 2 mệnh đề có ý nghĩa tương phản nhau.', 8, '2026-06-25 11:24:13.42', '2026-06-25 16:04:06.002', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5330, 'Sentence1。そして Sentence2', 'S1. Và S2', '• Cách dùng: そして là liên từ có nghĩa là “và”, dùng để nối 2 câu có nội dung tương đồng. そして khác vớiと(とdùng để nối 2 danh từ).', 8, '2026-06-25 11:24:13.425', '2026-06-25 16:04:06.008', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5331, 'N はどれですか。', 'N là cái nào?', '• Cách dùng: どれ： là từ để hỏi có nghía là “cái nào”, dùng để yêu cầu người nghe chọn một trong số những cái đưa ra (từ 2 thứ trở lên).', 8, '2026-06-25 11:24:13.43', '2026-06-25 16:04:06.013', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5332, 'N が あります / わかります', 'Có/ hiểu N N が すきです / きらいです/ じょうずです / へたです: Thích/ ghét, không thích/ giỏi/', 'Cách dùng: – Trợ từ đi với các động từ あります／わかります là が. – Động từ あります chỉ sự sở hữu chỉ dùng với đồ vật, không dùng cho người và động vật. – Một số tính từ như すき、きらい、じょうず、へた… cũng sử dụng trợ từ が', 9, '2026-06-25 11:24:13.849', '2026-06-25 16:04:06.018', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5333, 'どんな N', '', '• Cách dùng: どんな được sử dụng để yêu cầu người nghe lựa chọn 1 thứ trong nhóm mà danh sách sau どんな đưa ra.', 9, '2026-06-25 11:24:13.856', '2026-06-25 16:04:06.026', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5334, 'よく／だいたい／たくさん／少し／あまり／全然', '', '• Cách dùng:
