INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5336, 'N が あります／います', 'Có N', 'Cách dùng: – あります sử dụng khi N là đồ vật – います sử dụng khi N là người và động vật', 10, '2026-06-25 11:24:14.271', '2026-06-25 16:04:06.046', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5337, 'N1 (địa điểm) に なにが ありますか / いますか。Ở N1 có cái gì/ con gì?', '', 'Cách dùng: dùng để miêu tả một sự thật. N1 là địa điểm tồn tại của N2 và được xác định bằng trợ từ に.', 10, '2026-06-25 11:24:14.277', '2026-06-25 16:04:06.052', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5338, 'N1 は N2 (địa điểm) に あります／います', 'N1 ở N2', '• Cách dùng: chỉ nơi tồn tại ở người hay vật', 10, '2026-06-25 11:24:14.283', '2026-06-25 16:04:06.06', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5339, 'N1 (vật, người, địa điểm) の N2 (danh từ chỉ vị trí)', 'thể hiện tương quan vị trí：うえ、まえ、となり、ちかく。。。', NULL, 10, '2026-06-25 11:24:14.29', '2026-06-25 16:04:06.066', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5340, 'N1 や N2', 'N1 và N2', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5341, 'Số đếm', '• Các trợ từ số đếm: Là những từ được đặt sau số để đếm các đồ vật, người… – 人 (にん): dùng đếm người (đặc biệt đếm 1, 2 n', '• Các trợ từ số đếm: Là những từ được đặt sau số để đếm các đồ vật, người… – 人 (にん): dùng đếm người (đặc biệt đếm 1, 2 người dùng ひとり, ふたり) – 番 (ばん): dùng để đếm số thứ tự – 枚 (まい ): dùng để đếm vật mỏng (tem, áo sơmi, …) – 台 (だい) : dùng để đếm máy móc, xe – 冊 (さつ): dùng để đếm sách vở – 着 (ちゃく): dùng để đếm quần áo – 個 (こ): dùng để đếm vật nhỏ – 足(そく): dùng để đếm giầy, tất – 軒 (けん): dùng để đếm nhà – 階 (かい、がい): dùng để đếm tầng của một căn nhà – 本 (ほん、ぼん、ぽん) : dùng để đếm vật thon dài – 杯 (はい、ばい、ぱい) : dùng cho đồ uống – 匹 (ひき、びき、ぴき) : dùng đếm con vật kích thước nhỏ – 回 (かい) : dùng đếm số lần. • Các từ để hỏi cho số đếm – いくつ là từ dùng để hỏi cho đồ vật đếm bằng ～つ – Các cách đếm khác dùng なん＋trợ từ số đếm.', 11, '2026-06-25 11:24:14.698', '2026-06-25 16:04:06.078', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5342, 'どのくらい V ますか。', 'Làm ~ bao lâu?', 'Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5343, 'Bài 12', 'Thì quá khứ', '• Quá khứ: – Khẳng định: N/ Na でした。 – Phủ định: N/ Na じゃ（では）ありませんでした。', 12, '2026-06-25 11:24:15.085', '2026-06-25 16:04:06.089', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5344, 'Các thì của câu kết thúc bằng tính từ đuôi', '', '• Hiện tại:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5345, 'N1はN2よりです：N1 ~ hơn N2', '', '• Cách dùng: Mẫu câu so sánh hơn, kém. N1 được so sánh với N2', 12, '2026-06-25 11:24:15.093', '2026-06-25 16:04:06.099', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5358, 'V ては いけません。', 'Không được làm ~', '• Cách dùng: sử dụng khi muốn nói ý không được phép làm gì.', 15, '2026-06-25 11:24:16.281', '2026-06-25 16:04:06.16', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5346, 'N1 と N2 と どちらが Adj ですか。', 'N1 và N2 cái nào ~ hơn?', 'Cách dùng: từ để hỏi どちら được dùng khi muốn so sánh giữa 2 vật hay người.', 12, '2026-06-25 11:24:15.098', '2026-06-25 16:04:06.102', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5347, 'N1 [のなか] で なに／どこ／だれ／いつ が いちばん Adj ですか。', 'Trong phạm vi N1 thì cái gì/ nơi nào/ ai/ khi nào thì Adj nhất?', 'N2 が いちばん Adj です。N2 ~ nhất.', 12, '2026-06-25 11:24:15.102', '2026-06-25 16:04:06.11', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5353, 'Thể て của động từ', '', 'Các động từ kết thúc bằng て、で được gọi là thể て. Cách chia của thể て phụ thuộc vào các nhóm động từ.
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5350, 'N1 (địa điểm) へなにをしにいきますか。', 'Bạn đi đến N1 để làm gì?', 'Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5351, 'Đâu đó / cái gì đó', '', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5354, 'V て + ください。', 'Hãy làm ~, Vui lòng làm ~', '• Cách dùng: dùng khi yêu cầu, nhờ ai đó làm gì một cách lịch sự.', 14, '2026-06-25 11:24:15.886', '2026-06-25 16:04:06.142', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5352, 'Các nhóm của động từ Động từ trong tiếng Nhật được chia làm 3 nhóm theo cách chia sang các thể', '', 'Các nhóm của động từ Động từ trong tiếng Nhật được chia làm 3 nhóm theo cách chia sang các thể của chúng. (1) Nhóm 1 Bao gồm các động từ đứng trước đuôi ます là các chữ cái thuộc hàng “i” Ví dụ : かきます のみます (2) Nhóm 2 Hầu hết các động từ thuộc nhóm này có dạng đứng trước đuôi ます là các chữ cái thuộc hàng “e”. Ví dụ: たべます みせます Tuy nhiên cũng có một số động từ đứng trước đuôi ます là các chữ cái thuộc hàng “i” Ví dụ: みます おきます (3) Nhóm 3 Bao gồm 2 động từ: します(làm) きます(đến)', 14, '2026-06-25 11:24:15.874', '2026-06-25 16:05:46.845', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5349, '何をしたいですかBạn muốn làm gì?', 'Bạn muốn làm gì?', 'Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5348, '何(なに)が ほしいですか。Bạn mong muốn, muốn có cái gì? （私は）N が ほしいです。(Tôi) muốn/ muốn có/ mong có N', 'Bạn mong muốn, muốn có cái gì? （私は）N が ほしいです。(Tôi) muốn/ muốn có/ mong có N', 'Cách dùng: ほしい là tính từ đuôi いdùng để nói về ước muốn của người nói, không sử dụng để nói về mong muốn của người thứ ba.', 13, '2026-06-25 11:24:15.474', '2026-06-25 16:07:35.72', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5360, 'Bài 16', '• Ví dụ: 昨日、散歩して、ごはんをたべて、しんぶんをよみました。', 'Kinō, sanposhite, gohan wo tabete, shinbun o yomimashita。 Hôm qua, tôi đi bộ, rồi ăn cơm, sau đó đọc báo. あしたレストランでたべて、うちへかえって、べんきょうします。 Ashita resutoran de tabete, uchi e kaette, benkyō shimasu. Ngày mai, tôi ăn ở nhà hàng, rồi về nhà, sau đó sẽ học bài.', 16, '2026-06-25 11:24:16.689', '2026-06-25 11:24:16.689', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5366, 'Bài 17', 'Động từ thể ない', 'Ví dụ: あい－ます → あわ－ない かき－ます → かか－ない いそぎ－ます → いそが－ない はなし－ます → はなさ－ない まち－ます → また－ない あそび－ます → あそば－ない よみ－ます → よま－ない とり－ます → とら－ない • Nhóm II: bỏ [-ます] thêm ない Ví dụ: たべ－ます → たべ－ない み－ます → み－ない • Nhóm III: し－ます→ し－ない き－ます → こ－ない', 17, '2026-06-25 11:24:17.182', '2026-06-25 11:24:17.182', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5359, 'V ています。', '', 'Cách dùng: Một số động từ luôn chia ở thể tiếp diễn mặc dù hành động đã thực hiện trong quá khứ: 知(し)っています、住(す)んでいます、結婚(けっこん)しています、持(も)っています', 15, '2026-06-25 11:24:16.286', '2026-06-25 16:04:06.165', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5361, 'V１てから、V2 ます。', 'Sau khi làm V1 thì làm V2', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5362, 'N1 は N2 が Adj です。', '', '• Cách dùng: Dùng để miêu tả cụ thể một thành phần, một bộ phận của 1 vật hoặc người', 16, '2026-06-25 11:24:16.703', '2026-06-25 16:04:06.179', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5363, 'Cách nối 2 hay nhiều tính từ với nhau, 2 hay nhiều danh từ với nhau', '', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5364, 'どうやって：Làm thế nào?', '', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5365, 'どの N', 'Là ~ nào?', 'Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5367, 'V ないで ください', 'Không được làm gì…', '• Cách dùng: khi muốn khuyên hay yêu cầu ai không làm gì việc gì đó.', 17, '2026-06-25 11:24:17.188', '2026-06-25 16:04:06.201', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5368, 'V なければ なりません', 'phải…, bắt buộc phải…', '• Cách dùng: biểu thị một việc coi như nghĩa vụ phải làm, bất chấp ý hướng của người làm.', 17, '2026-06-25 11:24:17.196', '2026-06-25 16:04:06.207', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5369, 'V なくても いいです', 'không cần … cũng được', '• Cách dùng: biểu thị sự không cần thiết của hành vi mà động từ diễn tả.', 17, '2026-06-25 11:24:17.205', '2026-06-25 16:04:06.216', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5372, '(1) Nhóm 1', 'Là các động từ có kết thúc bởi các âm sau:', '(2) Nhóm 2: Là các động từ có dạng [-e る] [-i る] • Cách chuyển sang thể từ điển: bỏ ます thêm る • Ví dụ : Ví dụ: たべます ← たべる (ăn) みます ← みる (xem) Trừ một số động từ đặc biệt: かえります ← かえる (trở về) しります ← しる (biết) (3) Nhóm 3: Bao gồm 2 động từ: します → する きます → くる', 18, '2026-06-25 11:24:17.603', '2026-06-25 11:24:17.603', NULL, NULL, 0);
