INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5379, 'V たことが ありますか。', 'đã từng (làm)…', 'Cách dùng: nói về một kinh nghiệm đã gặp, đã từng trải qua trong quá khứ. Diễn tả việc không thường xuyên xảy ra.', 19, '2026-06-25 11:24:18.026', '2026-06-25 16:04:06.263', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5392, 'N が Adj／V', '', '• Cách dùng: biểu thị một tình trạng hay quang cảnh như nó vốn có.', 23, '2026-06-25 11:24:19.634', '2026-06-25 16:04:06.352', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5393, 'Động từ di chuyển', '', 'Cách dùng: dùng để chỉ địa điểm, vị trí nơi mà 1 người hay 1 vật nào đó đi qua.', 23, '2026-06-25 11:24:19.639', '2026-06-25 16:04:06.358', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5381, 'になります：trở nên (được)', '', 'Cách dùng: chỉ sự thay đổi một tình trạng hay một điều kiện.', 19, '2026-06-25 11:24:18.041', '2026-06-25 16:04:06.276', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5383, 'Cách thể hiện suy nghĩ, quan điểm cá nhân • Cấu trúc', 'Vる / Vない / Vた ＋ とおもいます。 Aい +', 'Cách dùng: thể hiện sự phỏng đoán, ý kiến chủ quan của cá nhân về 1 vấn đề, sự việc nào đó.', 21, '2026-06-25 11:24:18.809', '2026-06-25 16:04:06.288', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5384, 'Cách trích dẫn trực tiếp hoặc gián tiếp 1 câu nói, 1 ý kiến mà ai đó đã đưa ra', '', 'Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5382, 'Khi đổi những câu được nối với nhau bằng から hay が、けど (thường sử dụng trong hội thoại) thành thể văn thông thường thì tất cả các từ lịch sự trong câu phải được đổi sang thể thông thường.', '→ 日本の食べ物は おいしいが、高い。 * Cách dùng: – bỏ trợ từ chỉ sự nghi vấn là か ở cuối câu, thay vào đó đọc cao giọng chữ ở cuối câu để biểu thị sự nghi vấn. Ví dụ: 1) コーヒーを 飲む? ( ) …うん、飲む( ) Chú ý: cũng có những câu nghi vấn ở thể văn thông thường mà không bỏ chữ か ở sau như: 飲むか、見たか…, nhưng chỉ được sử dụng giới hạn trong phạm vi nam giới khi người trên hỏi người dưới hoặc những người quá thân nhau (như cha hỏi con trai) – Đối với câu nghi vấn danh từ hay tính từ thì chữ だ thể thông thường của です được giản lược. Ví dụ: 今晩 暇? …うん、暇(だよ) …ううん、暇ではない。 …ううん、暇じゃない。 Khi đàm thoại thường dùng じゃない – Trợ từ trong câu nghi vấn ở thể văn thông văn cũng thường được lược bỏ Ví dụ: 1)ご飯「を」食べる? 2)明日京都「へ」行かない? 3)このりんご「は」おいしいですね。 4)そこに はさみ「が」ある? – Trong thể thông thường, chữ い trong mẫu câu V ている cũng thường được lược bỏ Ví dụ 1)辞書、持って「い」る? …うん、持って「い」る。 …ううん、持って「い」ない。', 'Cách dùng: – bỏ trợ từ chỉ sự nghi vấn là か ở cuối câu, thay vào đó đọc cao giọng chữ ở cuối câu để biểu thị sự nghi vấn.', 20, '2026-06-25 11:24:18.418', '2026-06-25 16:05:46.851', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5387, 'Vる / Vない / Vた + N', '日本へ 行った人 / 行かなかった人 : Nihon e itta hito/ ikanakatta hito Người đã đi Nhật / Người đã không đi Nhật これは ミラーさんが 住(す)んでいる家(うち)です。', 'Kore wa mirā-san ga jū (su)nde iru ie (uchi)desu Đây là ngôi nhà ông Miller đang ở. (Định ngữ là vị ngữ). ミラーさんが 住(す)んでいる家(うち)は 古(ふる)いです。 Mirā-san ga jū (su)nde iru ie (uchi) wa ko (furu) idesu Ngôi nhà ông Milller đang ở thật là cũ. (Định ngữ là chủ ngữ). ミラーさんが 住(す)んでいる家(うち)を 買(か)いました。 Mirā-san ga jū (su)nde iru ie (uchi) o-kai (ka) imashita Tôi đã mua căn nhà mà ông Miller đang ở. (Định ngữ là tân ngữ). あのめがねをかけている人は山田さんです。 Ano megane wo kaketeiru hito wa Yamada-san desu. Người đang đeo kính đó là anh Yamada. 私は広い部屋あるうちがほしいです。 Watashi wa hiroi heya aru uchi ga hoshīdesu. Tôi muốn ngôi nhà mà có phòng rộng. 私は朝ご飯を食べる時間がありません。 Watashi wa asa gohan wo taberu jikan ga arimasen. Tôi không có thời gian ăn sáng.', 22, '2026-06-25 11:24:19.227', '2026-06-25 11:24:19.227', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5386, 'N1 (địa điểm)で N2 があります。 Ở N1 được tổ chức, diễn ra N2', '', '• Cách dùng: khi N2 là các sự kiện như bữa tiệc, buổi hòa nhạc, ngày hội, vụ tai nạn hay thảm họa… thì lúc đó あります có nghĩa là được tổ chức, diễn ra.', 21, '2026-06-25 11:24:18.834', '2026-06-25 16:04:06.319', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5388, 'N が', '', '• Cách dùng: Khi câu dùng động từ bổ nghĩa cho 1 danh từ (tạo ra định ngữ) thì chủ ngữ (chủ thể của hành động) trong câu bổ nghĩa đó được xác định bởi trợ từ が', 22, '2026-06-25 11:24:19.235', '2026-06-25 16:04:06.326', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5389, '～とき、～Khi ~, lúc ~ • Cấu trúc', 'Vる / Vない + とき Aい + とき Na + な + とき N', 'Cách dùng: – Nối 2 mệnh đề của câu. – Biểu thị thời điểm mà trạng thái, động tác hay hiện tượng được diễn đạt ở mệnh đề sau diễn ra. – Thời của tính từ, danh từ bổ nghĩa cho không phụ thuộc vào thời của câu chính.', 23, '2026-06-25 11:24:19.619', '2026-06-25 16:04:06.332', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5390, 'Vる / Vた + とき', '', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5391, 'Vる / Vない + と', '~ Là ~ / ~ thì ~', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5398, 'Bài 25', '• Ví dụ: お金が あったら、旅行します。', 'Okane ga attara, ryokōshimasu. Nếu có tiền tôi sẽ đi du lịch. 時間が なかったら、テレビを 見)ません。 Jikan ga nakattara, terebi wo mi masen. Nếu không có thời gian tôi sẽ không xem ti vi. 安かったら、パソコンを 買いたいです。 Yasukattara, pasokon wo kaitaidesu. Nếu rẻ tôi muốn mua 1 cái máy tính cá nhân. 暇だったら、手伝ってください。 Himadattara, tetsudatte kudasai. Nếu rỗi thì giúp tôi một tay nhé. いい天気だったら、散歩しませんか。 Ī tenki dattara, sanposhimasen ka. Nếu thời tiết đẹp thì bạn có đi bộ cùng tôi không?', 25, '2026-06-25 11:24:20.502', '2026-06-25 11:24:20.502', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5394, 'N をくれます', 'tặng, cho (người nói)', 'Cách dùng: ý nghĩa giống với あげます. Tuy nhiên: – あげます: thể hiện việc người nói tặng cho ai, người nào đó tặng cho người khác. – くれます: thể hiện việc ai đó tặng, cho người nói hoặc người thân trong gia đình người nói.', 24, '2026-06-25 11:24:20.035', '2026-06-25 16:04:06.364', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5395, 'Vてあげます', '(làm cái gì) cho ai', '• Cách dùng:
