INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5400, 'Điều kiện ngược', '', 'Cách dùng: dùng khi một hành động nào đó trong một hoàn cảnh nhất định đáng ra phải làm nhưng lại không làm, một việc nào đó đáng ra phải xảy ra nhưng lại không xảy ra, hoặc một kết quả trái với quan niệm thông thường của mọi người.', 25, '2026-06-25 11:24:20.512', '2026-06-25 16:04:06.398', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5404, 'Mẫu câu V1んですが、V2(Thể て)いただけませんか？。', '', 'Người nói muốn làm V1, và nhờ người nghe làm V2 giúp mình (V2 là hướng để giải quyết V1)
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5405, 'Mẫu câu V1んですが、V2たらいいですか？', '', '、どうしたらいいですか？
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5406, 'Bài 27', 'Động từ thể khả năng', 'Cách dùng: giống như cách dùng của「Vることができます」. Trong câu, trợ từ [を] được chuyển thành [が], Các trợ từ khác vẫn giữ nguyên. 漢字が読めます。 Kanji ga yomemasu. Tôi có thể đọc được hán tự. 漢字を読むことができます。 Kanji wo yomu koto ga dekimasu. Tôi có thể đọc được hán tự. 日本料理が作れます。 Nihon ryōri ga tsukuremasu. Tôi có thể làm các món ăn Nhật. 銀行(ぎんこう)で お金(かね)が 換(かえ)えられます。 Ginkō de okane ga kaeraremasu. Có thể đổi tiền ở ngân hàng. ここに車がとめられます。 Koko ni kuruma ga tome raremasu. Ở đây có thể đỗ xe. II. Ngữ pháp 1.Ở bài 27 này là cách nói biểu thị khả năng có thể làm được cái gì đấy hay không của mình hoặc của người khác bằng cách sử dụng thể khả năng ở trên. **Lưu ý rằng trợ từ của thể khả năng luôn luôn là が Ví dụ: -私は日本語で手紙が書けます わたしはにほんごでてがみがかけます Tôi có thể viết thư được bằng tiếng Nhật -私はラメンが１０っぱい食べられます わたしはらめんがじゅっぱいたべられます Tôi có thể ăn được 10 bát Ramen (Mì)', 27, '2026-06-25 11:24:21.341', '2026-06-25 11:24:21.341', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5402, 'N が', '', '• Cách dùng:
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5403, 'Vる / Vない / Vた＋んです。 Aい ＋んです。 Na / N ＋んです。 • Ý nghĩa', 'nhấn mạnh ý muốn nói, muốn hỏi;', 'Cách dùng: 1.1. Trong câu hỏi「～んですか。」 1.1.1. Dùng trong trường hợp xác nhận lại thông tin xem có đúng như cái mà mình đang nhìn thấy hoặc đang suy đoán không.', 26, '2026-06-25 11:24:20.93', '2026-06-25 16:04:06.417', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5407, 'Mẫu câu', '', '~~~しか　Vません
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5408, 'V1 (bỏ ます) + ながら、 V２', 'vừa làm ~ vừa làm ~', 'Cách dùng: diễn tả 2 hành động xảy ra đồng thời vào cùng một thời điểm. Trong đó, hành động thứ 2 là hành động chính, được nhấn mạnh hơn.', 28, '2026-06-25 11:24:21.777', '2026-06-25 16:04:06.435', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5409, '～んですが、～', '', 'Cách dùng: dùng để yêu cầu, nhờ ai đó làm gì giúp mình nhưng có ý nghĩa yêu cầu, nhờ vả lịch sự hơn Vてください rất nhiều.', 28, '2026-06-25 11:24:21.784', '2026-06-25 16:04:06.444', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5410, 'Thể thường し、Thể thường し、～', 'vừa thế này, lại thế kia nữa; vì thế này, và vì thế này nên …', 'Cách dùng: し được dùng để liệt kê các nội dung khác nhau của một đề tài hoặc trình bày nhiều hơn một nguyên nhân, lý do (có thể nhiều hơn 2, nhưng thường chỉ liệt kê 2)
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5411, 'Vています', 'diễn tả trạng thái phát sinh do kết quả của động tác hoặc hành động được biểu thị bởi', 'Cách dùng: Biểu thị trạng thái của đồ vật, khi miêu tả nguyên về trạng thái hiện ra trước mắt mình thì động từ hoặc chủ thể của trạng thái được biểu thị bằng trợ từ が.', 29, '2026-06-25 11:24:22.184', '2026-06-25 16:04:06.463', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5412, 'Vてしまいます', '(làm gì) hết/ xong rồi; (làm gì) mất rồi (nuối tiếc)', 'Cách dùng: dùng để nhấn mạnh sự hoàn thành thật sự của hành động, đứng trước nó thường là các trạng từ như もう、ぜんぶ.', 29, '2026-06-25 11:24:22.193', '2026-06-25 16:04:06.475', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5442, 'Ngữ pháp V る＋ のが ＋ A です。', '', '(Câu tính từ với trợ từ が)', 38, '2026-06-25 11:24:26.037', '2026-06-25 16:04:06.58', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5416, '毎日運動した ほうが いいです。', '＊ Sự khác nhau giữa ～た ほうが いい và ～たらいい： 日本のお寺が 見たいんですが……。', 'Tôi muốn đi thăm chùa của Nhật. …じゃ、 京都へ 行ったら いいですよ。 Vậy thì đi Kyoto được đấy. Ví dụ diễn tả tình huống mà là một lời gợi ý đơn giản được đưa ra. Trong những trường hợp này, ～たら いい được sử dụng. ～た ほうが いい chỉ so sánh và lựa chọn 2 vật.', 32, '2026-06-25 11:24:23.47', '2026-06-25 11:24:23.47', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5420, 'Thể mệnh lệnh tiếng Nhật là', 'Thể cấm đoán tiếng Nhật là 禁止形 (きんしけい) 1. Cách chia động từ thể mệnh lệnh. (命令形) Nhóm 2: bỏ る thêm ろ (động từ dạng –masu thì bỏ -masu và thêm –ro)', 'Thể cấm đoán tiếng Nhật là 禁止形 (きんしけい) 1. Cách chia động từ thể mệnh lệnh. (命令形) Nhóm 2: bỏ る thêm ろ (động từ dạng –masu thì bỏ -masu và thêm –ro)', 33, '2026-06-25 11:24:23.888', '2026-06-25 11:24:23.888', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5413, 'Vてあります：(diễn tả trạng thái, kết quả hành động với tha động từ) • Ý nghĩa', 'Mẫu câu「～てあります」dùng để diễn tả trạng', 'Cách dùng: 1.1. N １ に N２ が V てあります: ở đâu có … cái gì • Cách dùng: Thể hiện trạng thái của đồ vật sau khi xảy ra 1 việc gì đó và hiện giờ (thời điểm nói) kết quả của việc đó vẫn còn tồn tại và người nói nhìn thấy được. Trong đó, đặt trọng tâm ý muốn nói ở hành động và mục đích thực hiện hành động đó.', 30, '2026-06-25 11:24:22.6', '2026-06-25 16:04:06.484', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5414, 'Vておきます', '', 'Cách dùng: Diễn tả 1 hành động cần làm trước để chuẩn bị cho 1 hành động khác xảy ra.', 30, '2026-06-25 11:24:22.609', '2026-06-25 16:04:06.495', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5415, 'Chia thể ý chí động từ nhóm 2', 'bỏ る thêm よう', 'Cách dùng: dùng để biểu lộ dự định, ý muốn làm một chuyện gì cho người nghe biết.', 31, '2026-06-25 11:24:23.048', '2026-06-25 16:04:06.502', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5417, 'Mẫu ngữ pháp でしょう', '', 'Cách dùng: biểu thị suy luận của người nói căn cứ vào một số thông tin nào đó. Nó thường được sử dụng chung với phó từ như たぶん (có lẽ) hay きっと(nhất định). Khi sử dụng câu hỏi, người nói muốn biết suy luận của người nghe.', 32, '2026-06-25 11:24:23.477', '2026-06-25 16:04:06.51', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5418, 'Mẫu ngữ pháp かもしれません', '', 'Nếu でしょう diễn đạt sự việc có thể xảy ra ở mức 70 – 80% thì mẫu câu này chỉ áp dụng cho những hành động mà khả năng xảy ra tương đối thấp, chỉ khoảng 50%.', 32, '2026-06-25 11:24:23.485', '2026-06-25 16:04:06.515', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5419, 'Cách sử dụng trợ từ で', '', 'Cách dùng: で được thêm sau số từ để chỉ giới hạn giá / thời gian / số lượng… cần thiết cho một tình huống, hành động hay sự kiện được tiến hành.', 32, '2026-06-25 11:24:23.492', '2026-06-25 16:04:06.522', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5424, 'Ngữ pháp という', '', 'Cách dùng: Mẫu câu này được dùng để định nghĩa từ được biểu diễn bởi “X” (という bắt nguồn từ といいます)
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5425, 'Ngữ pháp と言いました', '', '“Câu văn” (Thể thường) と 言っていました
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5426, 'Ngữ pháp とおりに', '① 私が やったとおりに、やってください。', 'Hãy làm giống hệt tôi làm. ② 私が 言ったとおりに、書いてください。 Hãy viết theo đúng những gì tôi nói. ③ 見たとおりに、話してください。 Hãy kể đúng những gì anh thấy. ④ 線のとおりに、 紙を 切ってください。 Hãy cắt giấy theo đường. ⑤ 説明書のとおりに、 組み立てます。 Lắp ráp theo như sách hướng dẫn.', 34, '2026-06-25 11:24:24.324', '2026-06-25 11:24:24.324', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5427, 'Ngữ pháp あとで', '', 'Cách dùng: dùng để diễn tả tuần tự của các hành động. Tùy từng loại từ mà cách kết hợp sẽ khác nhau: (+) với động từ thì chia ở dạng –ta ; (+) với danh từ thì có の; (+) với số từ thì ghép trực tiếp
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5428, 'Với mẫu câu này, ở vế 「～たあとで」 động tư luôn chia ở thể ～た, không bị ảnh hưởng của thời điểm diễn ra', '', '☞ あした 勉強したあとで、見物に 行きます。
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5430, 'Phân biệt sự khác nhau giữa 「～たあとで」 và 「～てから」', '', 'Khi muốn nhấn mạnh vào tuần tự hành
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5431, 'Ngữ pháp Ｖ１ないで、Ｖ２ (CHỌN 1 TRONG 2)', '', '① 日曜日 どこも 行きません。
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5421, 'Cách chia động từ thể cấm đoán (禁止形)', '', 'Động từ thể từ điển + な (động từ dạng – masu thì phải chuyển về dạng từ điển và thêm –na)', 33, '2026-06-25 11:24:23.894', '2026-06-25 16:04:06.526', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5422, 'Trong thể văn mệnh lệnh, ngoài cách dùng thể mệnh lệnh, thì “ V ます＋なさい” cũng được dùng.', 'Nó được dùng trong trường hợp bố mẹ nói với con cái, thầy cô giáo với học sinh. Tuy nhiên sắc thái của nó nhẹ nhàng hơn thể mệnh lệnh.', 'Vì vậy, phụ nữ thường dùng mẫu câu này thay thế cho thể mệnh lệnh….Tuy nhiên, ta không sử dụng mẫu câu này với bề trên.', 33, '2026-06-25 11:24:23.898', '2026-06-25 16:04:06.536', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5423, 'Mẫu ngữ pháp Ｖて＋くれ', '', 'Cách dùng: ～てくれ là thể thông thường của ~てください, mẫu câu biểu hiện sự nhờ cậy, yêu cầu lịch sự. Mẫu câu này thể hiện ý mệnh lệnh, cấm đoán nhưng nhẹ nhàng hơn nhiều và không bao hàm ý áp đặt, ép buộc.', 33, '2026-06-25 11:24:23.904', '2026-06-25 16:04:06.541', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5429, 'Tổng hợp các cách kết hợp của 「まえに」、「あとで」、「から」', '', NULL, 34, '2026-06-25 11:24:24.341', '2026-06-25 16:05:46.853', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5435, 'Ngữ pháp ようにしてください', '', '1) 必ず 時間を 守るように して ください。
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5438, 'Mẫu 2', 'N1(người)は N2(người) に N3(vật)を+ Ukemi', 'Chủ động: どろぼうは (わたしの) お金を 取りました。  Kẻ trộm lấy tiền của tôi.
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5441, 'Cách đổi từ động từ thành danh từ bằng trợ từ の', 'Cách dùng: Thêm trợ từ の sau động từ ở thể thông thường thì có thể danh từ hóa câu hay nhóm từ có chứa động từ đó.', 'Câu hay nhóm từ được danh từ hóa có thể làm chủ ngữ hoặc tân ngữ. 1. Ngữ pháp V る＋ のは ＋ A です。 (Câu tính từ với trợ từ は) Đã học (ở bài 8) サッカーは おもしろいです。 Bóng đá thì thú vị. Bài này học cách nói cụ thể là “xem bóng đá thì thú vị” hay “chơi bóng đá thì thú vị” サッカーを するの は おもしろいです。 Chơi bóng đá thì thú vị. サッカーを 見るの は おもしろいです。 Xem bóng đá thì thú vị. Các tính từ thường được sử dụng trong mẫu câu này gồm: たのしい、おもしろい、むずかしい、やさしい、はずかしい、きもちが いい、きけん［な］、 たいへん［な］ …', 38, '2026-06-25 11:24:26.032', '2026-06-25 11:24:26.032', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5433, 'Ngữ pháp ように、～', 'Cách dùng: Khi biểu hiện một hành động nào đó có mục đích ta dùng ように.', 'Mệnh đề 1 chỉ mục đích, mệnh đề 2 chỉ hành động có chủ ý để đạt được mục đích ở mệnh đề 1 đưa ra.', 36, '2026-06-25 11:24:25.158', '2026-06-25 16:04:06.554', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5434, 'Ngữ pháp るようになる', '', 'V るように なりました。', 36, '2026-06-25 11:24:25.165', '2026-06-25 16:04:06.56', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5436, 'Cách sử dụng trạng từ かなり', '', NULL, 36, '2026-06-25 11:24:25.181', '2026-06-25 16:04:06.564', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5437, 'Động từ thể Ukemi (受身)', 'Nhóm II: Thêm られ.', '1. Mẫu 1: N1(người)は N2(người)に+ Ukemi', 37, '2026-06-25 11:24:25.609', '2026-06-25 16:04:06.567', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5439, 'Mẫu 3', 'N は + Ukemi。', NULL, 37, '2026-06-25 11:24:25.62', '2026-06-25 16:04:06.572', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5440, 'Cách sử dụng trợ từ に', '', 'Trợ từ に biểu hiện tỷ lệ:', 37, '2026-06-25 11:24:25.625', '2026-06-25 16:04:06.576', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5445, 'Cách sử dụng いき và かえり', '', 'Thể ます của một số động từ có thể được sử dụng làm danh từ.
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5446, 'Khác với ~から mà chúng ta đã học ở bài 9, mẫu câu này có nhiều hạn chế.', '◈ Tính từ, động từ biểu hiện cảm xúc: びっくりする、安心する、困る、さびしい、残念だ… ニュースを聞いて、 びっくりしました。', 'Tôi đã ngạc nhiên khi nghe tin. 暑くて、寝られませんでした。 Không thể ngủ được vì trời nóng. ◈ わからない và thể phủ định của động từ khả năng: いけない、のめない、食べられない… 土曜日は 都合が悪くて、いけません。 Tôi không thể đi được vì thứ 7 bận rồi. 話が複雑で、あまりわかりませんでした。 Tôi không hiểu lắm vì câu chuyện phức tạp. じこがあって、バスが 遅れてしまいました。 Vì có tai nạn nên xe buýt đã đến muộn. 授業に遅れて、先生にしかられました。 Vì đến muộn giờ học nên tôi bị thầy giáo mắng. 1.2 Ở mẫu câu này, mệnh đề sau không thể là sự biểu hiện hàm chứa chủ ý (ý hướng, mệnh lệnh, rủ rê, yêu cầu). Khi mệnh đề sau có nội dung bao hàm chủ ý thì mệnh đề trước không sử dụng thể て、 thay vào đó dùng thể văn から. あぶないですから、きかいに触らないで ください。 （ ○ ） Vì nguy hiểm, xin đừng sờ vào máy. あぶなくて、きかいに 触らないで ください。 （ × ） あした 会議が ありますから、今日 準備しなければ なりません。（○） Vì ngày mai có cuộc họp nên hôm nay phải chuẩn bị. あした 会議が あって、今日 準備しなければなりません。（×）', 39, '2026-06-25 11:24:26.456', '2026-06-25 11:24:26.456', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5448, 'Ngữ pháp ～ので', '', 'Cách dùng: ～ので đi tiếp ngay sau danh từ, động từ, tính ở chia ở thể thường
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5450, 'Trợ từ nghi vấn ～か', '1.1 Trợ từ ～か là trợ từ nghi vấn đã học thường được đặt cuối câu nghi vấn: A : 会議は 何時に 終わりますか。', 'Mấy giờ thì cuộc họp kết thúc B : 分かりません。 Tôi không biết. (1) A+B = 会議は 何時に 終わりますか ＋ 分かりません。 Mấy giờ thì cuộc họp kết thúc？ + không biết → 会議は 何時に 終わるか、分かりません。 Không biết mấy giờ thì cuộc họp kết thúc. (2) どうしたら いいですか ＋ 考えてください。 Nên làm thế nào thì tốt? + hãy suy nghĩ → どうしたら いいか、考えてください。 Hãy suy nghĩ xem nên làm thế nào thì tốt. (3) 神戸は どんな町ですか ＋ しりません。 Kobe là thành phố như thế nào ? + không biết → 神戸は どんな町か、しりません。 Không biết Kobe là thành phố như thế nào. Các ví dụ trên là câu hỏi với từ để hỏi được sử dụng như một thành phần trong câu. 1.3 Chú ý sự khác nhau giữa なにか trong ví dụ (1), (1’) và どこか trong ví dụ (2),(2’) sau: (1) はこの中身は なにか、調べてください。 Hãy kiểm tra xem trong hộp có cái gì. (1’) のどがかわきましたから、 なにか 飲みたいですね。 Vì khát nước nên muốn uống cái gì đó quá nhỉ (2) おてあらいは どこか、 わかりません。 Không biết nhà vệ sinh ở đâu. (2’) 今日は いい天気ですね。 どこか 行きますか。 Hôm nay trời đẹp quá. Bạn có đi đâu đó không?', 40, '2026-06-25 11:24:26.865', '2026-06-25 11:24:26.865', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5443, 'Ngữ pháp V る＋ のを ＋ わすれました。', '', '(Câu động từ)', 38, '2026-06-25 11:24:26.044', '2026-06-25 16:04:06.585', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5444, 'Trợ từ の và こと', '', 'Giống như trợ từ の, trợ từ こと mà chúng ta đã học ở bài 18, 19 cũng được sử dụng như là một cách để danh từ hóa động từ. Chú ý nhiều mẫu câu trong đó こと được sử dụng nhưng の thì không．', 38, '2026-06-25 11:24:26.052', '2026-06-25 16:04:06.595', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5447, 'Ngữ pháp N で', '', '2.1 Trợ từ で nhiều khi chỉ nguyên nhân, trong trường hợp này danh từ được sử dụng thường là các từ có đủ sức gây nên một kết quả nào đó như: じこ(tai nạn), じしん (động đất), かじ (hỏa hoạn)…', 39, '2026-06-25 11:24:26.461', '2026-06-25 16:04:06.601', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5449, 'Phân biệt 気持ちがいい và 気分がいい', '', NULL, 39, '2026-06-25 11:24:26.469', '2026-06-25 16:05:46.855', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5451, 'Ngữ pháp かどうか', '', 'Cách dùng: Giống như trường hợp của ～か、～、 mệnh đề trước かどうか
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5453, 'Ở bài 7 và bài 24, chúng ta đã học về các biểu hiện cho và nhận đồ vật hay một hành động qua việc sử dụng 3 động từ「あげます、もらいます、くれます」 .', '* Quan hệ Trong (ウチ) – Ngoài （ソト） 1.', 'Cách dùng: 「いただきます」 là khiêm nhường ngữ được dùng thay cho「もらいます」 với hàm ý thể hiện sự khiêm tốn, nhún nhường của người nhận đối với người cho khi người nói nhận gì đó từ người có tuổi tác, địa vị xã hội cao hơn mình (trừ người trong gia đình), người không thân quen lắm hoặc khi muốn thể hiện sự tôn trọng đối với người cho mình. Chú ý: chủ thể của động từ này luôn luôn là 「わたし」 (tôi) もらいます 上の人に 友達に (かぞく、父、母など) 下の人に', 41, '2026-06-25 11:24:27.263', '2026-06-25 16:04:06.61', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5454, 'Ngữ pháp ～は（が）Ｎを くださいます.', '', 'Cách dùng: 「くださいます」 là tôn kính ngữ được dùng thay cho「くれます」 với hàm ý thể hiện sự tôn trọng của người nhận khi người cho là người có tuổi tác, địa vị xã hội cao hơn mình (trừ người trong gia đình), hay người không thân quen lắm..
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5455, 'Ngữ pháp ～に Ｎを やります.', '', 'Cách dùng: 「やります」 được dùng thay cho「あげます」 trong trường hợp đối tượng nhận hành động có địa vị thấp hơn, ít tuổi hơn (em trai, em gái, con cái trong gia đình), động vật, thực vật …
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5456, 'Ngữ pháp ～ために (cách thể hiện mục đích)', 'Cách dùng: Đây là mẫu câu biểu hiện mục đích.', 'Mệnh đề trước đi với ために là mệnh đề biểu hiện mục đích, mệnh đề sau biểu hiện hành vi có ý chí để thực hiện mục đích ấy. 1.1 mẫu câu V1るために、 V2 Động từ đi trước ｢ために｣ là động từ thể từ điển và là những động từ mang tính ý chí thể hiện 1 mục đích nào đó. らいねん 世界旅行を するために、 今お金を ためています。 Bây giờ tôi đang tiết kiệm tiền để năm sau đi du lịch. 漢字を 勉 強するために、 辞書を 買いました。 Tôi đã mua từ điển để học chữ Hán 1/ Phân biệt「～ように」 (bài 36) với「～ために」 – Cả「～ように」 và「～ために」 đều đi với động từ ở thể từ điển. (Người ta không hay dùng dạng 「V ないために」 )。 Ở mệnh đề trước – mệnh đề thể hiện mục đích của mẫu câu 「～ように」 có thể sử dụng cả động từ không có tính ý chí. – Động từ có tính ý chí là động từ thể hiện những động tác, hành động mà ý chí của con người có thể điều khiển được.. VD: たべる(ăn), のむ (uống), いく (đi), つくる (tạo ra), ねる (ngủ)…. + Sự vận động, trạng thái của những vật vô tri, vô giác: ある(có), 壊れる (bị vỡ), 雨が降る (mưa rơi), 風が吹く (gió thổi), 水が出る (nước chảy)… + Các hiện tượng sinh lý của con người:痛む(đau), 病気になる (bị ốm), 老いる(già) , 若返る(trẻ lại), 目が覚める(tỉnh dậy)… + Các hiện tượng tâm lý của con người : 困る(khó khăn) , 飽きる (mệt mỏi), できる (có thể)… và các động từ ở thể khả năng.', 42, '2026-06-25 11:24:27.662', '2026-06-25 16:04:06.63', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5457, 'Ví dụ', 'Hoa sakura sắp nở. これから 寒くなりそうです。 Trời sắp lạnh. 今にも 荷物が 落ちそうです。 Hành lý sắp rơi. 煙が 少なくなりました。 火事は 消えそうです。 Khói ít đi rồi. Cơn hỏa hoạn sắp tắt.', 'もうすぐ 桜が 咲きそうです。 Hoa sakura sắp nở. これから 寒くなりそうです。 Trời sắp lạnh. 今にも 荷物が 落ちそうです。 Hành lý sắp rơi. 煙が 少なくなりました。 火事は 消えそうです。 Khói ít đi rồi. Cơn hỏa hoạn sắp tắt.', 43, '2026-06-25 11:24:28.056', '2026-06-25 16:05:46.857', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5460, 'Ngữ pháp すぎます', 'Ｖ、Ａ、Ｎａ＋すぎます Cấu trúc すぎます: Ví dụ : 昨日の晩お酒を 飲みすぎました。', 'Tối qua, tôi đã uống quá nhiều rượu. お土産を 買いすぎました。 Tôi đã mua quá nhiều quà lưu niệm. 寿司を 食べすぎました。 Tôi đã ăn quá nhiều Sushi. このシャツは 大きすぎます。 Cái áo sơ mi này quá to. この本は 複雑すぎます。 Cuốn sách này quá phức tạp. Chú ý: 「すぎます」 là động từ nhóm 2: 「すぎる、すぎて」 食べすぎて、おなかが 痛いです。 Vì tôi ăn nhiều quá nên bị đau bụng. 試験の問題は 複雑すぎて、 何も わかりませんでした。 Bài thi khó quá nên chả hiểu gì cả. いくら好きでも、 飲みすぎると、 体に悪いですよ。 Dù có thích rượu mấy đi chăng nữa nhưng nếu uống nhiều quá cũng có hại cho sức khỏe.', 44, '2026-06-25 11:24:28.484', '2026-06-25 11:24:28.484', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5462, 'Ngữ pháp Ｎに します', '', '会議は 明日に します。 Để đến mai họp (quyết định dời buổi học sang ngày mai)
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5463, 'Cấu trúc Ngữ pháp 場合 (ばあい)', 'Cách dùng: dùng để diễn đạt ý giả định về một tình huống nào đó (ý nghĩa gần giống với mẫu câu 「～たら」 ) nhưng thường chỉ', 'Cách dùng: dùng để diễn đạt ý giả định về một tình huống nào đó (ý nghĩa gần giống với mẫu câu 「～たら」 ) nhưng thường chỉ dùng trong những tình huống không hay, không mong đợi hoặc những điều hiếm khi xảy ra. Hành động ở vế sau thể hiện điều cần phải làm trong trường hợp đó hoặc kết quả do tình huống đó đem lại. Bản thân「場合」(ばあい) là một danh từ nên nó kết hợp với các loại từ khác (động từ, tính từ, danh từ) theo đúng các quy tắc đã học. 時間に遅れた 場合は、 教室に 入れません。 Trong trường hợp đến muộn giờ thì sẽ không vào lớp học được. 雨が降った 場合は、 学校を 休みます。 Tôi sẽ nghỉ học nếu trời mưa. 会議に間に合わない 場合は、 連絡してください。 Trong trường hợp không kịp giờ họp, hãy liên lạc nhé! 参加できない 場合は、 私に 言ってください。 Trường hợp không thể tham gia, hãy nói với tôi. Chú ý: trên thực tế, cũng có mẫu câu 「Ｖdict.場合は」 nhưng tính giả định của mẫu câu này không mạnh bằng 「Ｖた場合は」 và trong giáo trình này chỉ dùng mẫu câu 「Ｖた場合は」 ファックスの調子が 悪い 場合は、どうしたらいいですか。 Tôi nên làm thế nào trong trường hợp máy fax gặp trục trặc? Chú ý: ・Khi muốn nhấn mạnh, có thể thêm cụm từ 「万一」 hoặc「万が一」 (vạn nhất) vào phía đầu của vế có 「～場合は」 ・Giáo trình này không đề cập đến cách kết hợp với các dạng: quá khứ phủ định của động từ, quá khứ hay phủ định của tính từ, danh từ', 45, '2026-06-25 11:24:28.927', '2026-06-25 11:24:28.927', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5464, 'Cấu trúc ngữ pháp のに', '', 'Cách dùng: dùng khi muốn diễn đạt việc không đạt được kết quả như mong đợi trong 1 tình huống nào đó. Điểm khác biệt cần lưu ý ở mẫu câu này (so với cách nói cùng ý nghĩa như 「～が」 hay「～ても」 )là nó bao hàm những tình cảm, cảm giác mạnh mẽ của người nói như sự bất mãn, không ngờ…
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5461, 'Ngữ pháp やすい／にくい', '', 'Cách dùng: Trong bài 19, chúng ta đã học cách tạo phó từ với động từ「～なります」 với ý nghĩa “một cái gì đó chuyển sang trạng thái khác (trở nên, trở thành 1 cách tự nhiên)”
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5468, 'Ngữ pháp ようです', '', '① 彼は きょう とても いそがしいようです。
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5466, 'Ngữ pháp ばかり', '', 'Cấu trúc: V た ばかりです (cách thể hiện ý nói: hành động vừa xẩy ra)', 46, '2026-06-25 11:24:29.341', '2026-06-25 16:04:06.668', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5467, 'Trong ngữ pháp minnano nihongo bài 47 học về mẫu ngữ pháp そう, nghe thì có vẻ giống như ngữ pháp そう ở bài 43, nhưng câu trúc và ý nghĩa thì khác nhau đó nhé.', 'Ngữ pháp そう ở bài 43 là động từ bỏ masu thêm そう, ý nghĩa là hình như, có vẻ, mang tính phỏng đoán Ngữ pháp そう ở bài 47 là động từ từ điển Vる thêm そう、 mang ý nghĩa nghe nói, hình như 1.', 'Cách dùng: Dùng để truyền đạt những thông tin mà mình nghe thấy ở đâu đó đến người thứ 3 và không có nhận định của bạn. Để nhấn mạnh thêm sự chắc chắn của thông tin, có thể dẫn thêm nguồn gốc của thông tin đó với cụm từ 「～によると」', 47, '2026-06-25 11:24:29.738', '2026-06-25 16:04:06.676', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5469, 'Nhóm I', 'chuyển đuôi 「u」sang a +せる', 'Cách dùng: Biến đổi tự động từ sang thể 「使役(しえき)」 để tạo ra 1 động từ mới mang nghĩa sai khiến, mệnh lệnh yêu cầu ai đó làm gì. Trong phạm vi bài này dùng chủ yếu các tự động từ sau: 行く、来る、帰る、通う、 出 張する、 出席する、遊ぶ. Trong kiểu câu này, người thực hiện hành động, động tác sẽ đi với trợ từ 「を」。 – Kiểu câu này còn được gọi tên là kiểu câu 「を-使役文」(câu sai khiến với trợ từ を)', 48, '2026-06-25 11:24:30.136', '2026-06-25 16:04:06.681', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5472, 'Khiêm nhường ngữ tiếng Nhật là 謙譲語(けんじょうご)', 'Cách cấu tạo: V ます お V します Động từ nhóm 1: 持ちます → お持ちします Động từ nhóm 2: 調べます → お調しらべします 案内します → ご案内します 邪魔します → お邪魔します (1) 私は 毎日新聞を 読みます。', '（×） お読みします (2) A：いつ おくにへ おかえりに なりますか。 B: らいしゅう かえります。 （×） おかえりします ☞ Không dùng trong trường hợp người được nhắc tới trong câu chuyện là người thuộc nhóm mình kể cả người bề trên 父を 駅まで お送りしました。（×） 父を 駅まで 送りました。（○） ☞ Không sử dụng những động từ có 1 âm tiết ví dụ như:来ます、 見ます、います 来ます → ✖ おきします 〇まいります 見ます → ✖ おみします 〇はいけんします います → ✖ おいします 〇おります Cách danh động từ (động từ nhóm 3 có dạng「N します」 thường là những từ gốc Hán nên sẽ ghép 「ご」 và tạo thành 「ごN します」 . (nhưng không áp dụng với các động từ như 「勉強します、 実習します、 結婚します」 ) 電話します → お電話します 約束します → お約束します 電話は 階段の 横に ございます。 Điện thoại có ở bên cạnh cầu thang ạ. ＊ ～で ございます はい、 IMC で ございます。 Vâng, IMC xin nghe. …パワー電気の シュッミトですが、 ミラーさん、お願いします。 Tôi là Summit người của công ty điện lực Power, tôi xin gặp anh Miler. ＊ よろしいでしょうか お飲み物は 何が よろしいでしょうか。 Ngài sẽ dùng đồ uống gì ạ? コーヒーを お願いします。 Cho tôi cà phê.', 50, '2026-06-25 11:24:30.994', '2026-06-25 11:24:30.994', NULL, NULL, 0);
INSERT INTO public."Grammar" (id, pattern, meaning, explanation, "lessonId", "createdAt", "updatedAt", "jlptLevel", "formalityLevel", "sortOrder") VALUES (5471, 'Với những danh từ chưa bao hàm ý kính trọng thì có thể thêm 「さん（さま）」 để tăng thêm ý lịch sự', 'để tăng thêm ý lịch sự', '客→お客さん（さま） 二人→お二人さん（さま）
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14087, 'ここはじむしょです。', 'Koko wa jimusho desu', NULL, 'Chỗ này là văn phòng. Khi hỏi', 5297, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14088, 'しょくどうはどこですか。', 'Shokudō wa doko desuka', NULL, 'Nhà ăn ở đâu?', 5298, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14089, 'あそこです。', 'Asoko desu', NULL, 'Nhà ăn ở chỗ kia N１( người hoặc vật )', 5298, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14090, ') です。', 'N1 ở N2', NULL, '田中さんはどこですか。 Tanakasan wa doko desuka. Anh Tanaka ở đâu? …きょうしつです。 Kyōshitsu desu. Ở trong lớp học.', 5298, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14091, 'にほんごのほんはどちらですか。', 'Nihongo no hon wa dochira desuka', NULL, 'Quyển sách tiếng nhật ở đâu? …そちらです。 Sochira desu. Ở phía đó.', 5299, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14092, 'これはどこのえんぴつですか。', 'Kore wa doko no enpitsu desuka', NULL, 'Đây là bút chì của nước nào?', 5302, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14093, 'ベトナムのえんぴつです。', 'Betonamu desu', NULL, 'Bút chì của Việt Nam 4.2.', 5302, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14094, 'それはなんのしんぶんですか。', 'Sore wa nan no shinbun desuka', NULL, 'Đó là tờ báo gì?', 5302, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14095, 'これはでんわのしんぶんです。', 'Kore wa denwa no shinbun desu', NULL, 'Đó là tờ báo về điện thoại', 5302, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14096, 'これはえいごのしんぶんです。', 'Kore wa eigo no shinbun desu', NULL, 'Đó là tờ báo tiếng anh.', 5302, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14097, 'このほんはいくらですか。', 'Konohon wa ikura desuka', NULL, 'Quyển sách này giá bao nhiêu? ３０円です. 30 en desu. 30 Yên.', 5303, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14098, '８時３０分(8時半)です。', 'Bây giờ là 8:30 (8 rưỡi)', NULL, 'Chú ý: ～じはん ：Sử dụng khi nói giờ rưỡi.', 5304, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14099, '今日は何曜日ですか。', '', NULL, NULL, 5305, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14100, '日曜日です。', '', NULL, NULL, 5305, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14101, 'あしたは何曜日ですか。', '', NULL, NULL, 5305, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14102, '月曜日です。', '', NULL, NULL, 5305, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14103, 'まい日１１じにねます。', '', NULL, NULL, 5306, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14104, 'まいばんべんきょうします。', 'Ma iban be n kyō shimasu', NULL, 'Hàng tối tôi đều học bài.', 5307, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14105, 'あしたべんきょうしません。', 'Ashita be n kyōshimasen', NULL, 'Ngày mai tôi sẽ không học bài.', 5307, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14106, 'きのう べんきょうしました。', 'Kinō be n kyō shimashita', NULL, 'Hôm qua tôi đã học bài.', 5307, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14107, 'おととい べんきょうしませんでした。', 'Ototoi be n kyōshimasendeshita', NULL, 'Ngày kia tôi đã không học bài.', 5307, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14108, '私は１２じにたべます。', 'Watashi wa 12ji ni tabemasu', NULL, 'Tôi ăn vào lúc 12 giờ.', 5308, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14109, '土曜日（に）べんきょうしません。', 'Doyōbi (ni) be n kyōshimasen', NULL, 'Thứ 7 tôi thường không học bài.', 5308, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14110, 'きょうは何日ですか。', 'Kyō wa nan nichi desuka', NULL, 'Hôm nay là mùng mấy? １２日です。 Jūni nichi desu. Là ngày', 5310, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14111, 'あしたがっこうへなんでいきますか。', 'Ashita gakkō e nan de ikimasuka', NULL, 'Ngày mai bạn đến trường bằng gì vậy?', 5312, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14112, 'バスでいきます。', 'Basu de ikimasu', NULL, 'Tôi đi bằng xe buýt.', 5312, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14113, 'あるいていきます。', 'Aruite ikimasu', NULL, 'Tôi đi bộ. Chú ý: Trường hợp muốn nói là “đi bộ” thì dùng', 5312, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14114, 'だれとこうえんへいきましたか。', 'Dare to kōen e ikimashitaka', NULL, 'Bạn đã đi công viên với ai vậy?', 5313, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14115, 'ともだちといきました。', 'Tomodachi to ikimashita', NULL, 'Tôi đi cùng với bạn.', 5313, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14116, 'ひとりでくにへかえりました。', 'Hitori de kuni e kaerimashita', NULL, 'Tôi đã về nước một mình.', 5313, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14117, 'みずをのみます。', 'Mizu wo nomimasu', NULL, 'Tôi uống nước', 5314, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14118, 'ほんをよみました。', 'Hon wo yomimashita', NULL, 'Tôi đã đọc sách. • Chú ý: +', 5314, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14119, ') 私はにくをたべます。やさいもたべます。', 'Watashi wa niku wo tabemasu', NULL, 'Yasai mo tabemasu. Tôi ăn thịt. Tôi cũng ăn cả rau.', 5314, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14120, 'あしたなにもしません。', 'Ashita nani mo shimasen', NULL, 'Ngày mai tôi không làm gì cả.', 5315, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14121, 'スーパでかいました。', 'Sūpa de kaimashita', NULL, 'Tôi đã mua ở siêu thị.', 5316, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14122, 'いっしょにこうえんへいきませんか。', 'Issho ni kōen e ikimasenka', NULL, 'Cùng đi công viên nhé!', 5317, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14123, 'ええ、いいですね。', 'Ee, iidesune', NULL, 'Vâng tốt quá! (Ý hay đấy)', 5317, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14124, 'はじめましょう。', 'Hajimemashō', NULL, 'Nào, chúng ta bắt đầu nào!', 5318, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14125, 'なんでかきますか。', 'Nan de kakimasuka', NULL, 'Bạn viết bằng gì?', 5320, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14126, 'えんぴつでかきます。', 'Enpitsu de kakimasu', NULL, 'Tôi viết bằng bút chì', 5320, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14127, 'なんでごはんをたべますか。', 'Nan de gohan wo tabemasuka', NULL, 'Bạn ăn cơm bằng gì?', 5320, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14128, 'はしでたべます。', 'Hashi de tabemasu', NULL, 'Tôi ăn bằng đũa.', 5320, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14129, 'にほんごではなします。', 'Nihongo de hanashimasu', NULL, 'Tôi nói chuyện bằng tiếng Nhật .', 5320, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14130, '」はにほんごでなんですか。', '', NULL, NULL, 5321, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14131, '「ありがとう」です。', '', NULL, NULL, 5321, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14132, '「おやすみなさい」えいごでなんですか。', '', NULL, NULL, 5321, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14133, '」です。', '', NULL, NULL, 5321, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14134, 'だれに　てがみを　かきますか。', 'Dare ni tegami wo kakimasuka', NULL, 'Bạn viết thư cho ai vậy?', 5322, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14135, '友達に　かきます。', 'Tomodachi ni kakimasu', NULL, 'Tôi viết cho bạn.', 5322, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14136, 'だれに　にほんごを　ならいましたか。', 'Dare ni nihongo wo naraimashitaka', NULL, 'Bạn đã học tiếng nhật từ ai vậy?', 5323, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14137, 'いとながせんせいに　ならいました。', 'Itonaga sensei ni naraimashita', NULL, 'Tôi đã học từ cô Itonaga.', 5323, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14138, 'だれから　お金を　かりましたか。', 'Dare kara okane wo karimashitaka', NULL, 'Bạn đã vay tiền từ đâu?', 5323, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14139, '銀行から　借りました。', 'Ginkō kara karimashita', NULL, 'Tôi đã vay tiền từ ngân hàng.', 5323, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14140, 'もうニュースをみましたか。', 'Mō nyūsu wo mimashitaka', NULL, 'Bạn đã xem thời sự rồi à?', 5324, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14141, 'はい、もうみました。', 'Hai, mōmimashita', NULL, 'Vâng, tôi đã xem rồi.', 5324, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14142, 'いいえ、まだです。', 'Iie, madadesu', NULL, 'Không, tôi vẫn chưa xem.', 5324, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14143, 'あの人はハンサムです。', 'Anohito wa hansamu desu', NULL, 'Người kia đẹp trai.', 5326, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14144, 'このかばんはどうですか。', 'Kono kaban wa dō desuka', NULL, 'Cái cặp này như thế nào?', 5326, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14145, 'たかいです。', 'Takaidesu', NULL, 'Cái cặp đó đắt.', 5326, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14146, '田中さんどんな人ですか。', 'Tanakasan wa donna hito desuka', NULL, 'Anh Tanaka là người như thế nào?', 5327, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14147, '親切な人です。', 'Shinsetsu na hito desu', NULL, 'Anh ý là người tốt bụng', 5327, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14148, '富士山はどんな山ですか。', 'Fujisan wa donna yama desuka', NULL, 'Núi Phú Sĩ là núi như thế nào?', 5327, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14149, '高い山です。', 'Takai yama desu', NULL, 'Là núi cao.', 5327, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14150, '日本語は 難しいですか。', 'Nihongo wa muzukashī desuka', NULL, 'Tiếng Nhật khó phải không? …いいえ、あまり難しくないです。 Iie, amari muzukashiknai desu. Không, không khó lắm.', 5328, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14151, 'このでんわはべんりですが、たかいです。', 'Kono denwa wa benri desu ga takaidesu', NULL, 'Điện thoại này thuận tiện nhưng đắt.', 5329, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14152, 'この部屋はきれいです。そして、広いです。', 'Kono heya wa kirei desu', NULL, 'Soshite, hiroi desu. Phòng này đẹp và rộng.', 5330, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14153, '田中さんのほんはどれですか。', 'Tanakasan no hon wa dore desuka', NULL, 'Sách của anh Tanaka là quyển nào?', 5331, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14154, '白いのです。', 'Shiroi no desu', NULL, 'Là quyển màu trắng.', 5331, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14155, '私は あたらしい かばんが あります。', 'Watashi wa atarashi kaban ga arimasu', NULL, 'Tôi có cái cặp mới.', 5332, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14156, '私の友達は 豚肉が きらいです。', 'Watashi no tomodachi wa butaniku ga kiraidesu', NULL, 'Bạn tôi không thích thịt lợn.', 5332, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14157, '私は 日本語が へたです。', 'Watashi wa nihongo ga hetadesu', NULL, 'Tôi không giỏi (kém) tiếng Nhật.', 5332, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14158, 'どんな　飲み物が　好きですか。', 'Donna nomimono ga sukidesuka', NULL, 'Bạn thích đồ uống nào?', 5333, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14159, 'ジュースが　好きです。', 'Jūsu ga sukidesu', NULL, 'Tôi thích nước hoa quả.', 5333, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14160, '日本語が だいたい わかります。', 'Nihongo ga daitai wakarimasu', NULL, 'Tôi biết tiếng Nhật cũng đại khái thôi.', 5334, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14161, 'ぶんぽうが あまり わかりません。', 'Bunpō ga amari wakarimasen', NULL, 'Tôi không biết nhiều ngữ pháp lắm. Thong Nhat', 5334, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14162, '公園で きが たくさん あります。', 'Thống Nhất kōen de ki ga takusan arimasu', NULL, 'Ở công viên Thống Nhất có rất nhiều cây.', 5334, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14163, 'きょうは すこし 寒いです。', 'Kyō wa sukoshi samuidesu', NULL, 'Hôm nay hơi lạnh', 5334, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14164, 'どうして日本語をべんきょうしますか。', 'Dōshite nihongo　wo benkyō shimasu ka', NULL, 'Tại sao bạn nói tiếng Nhật?', 5335, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14165, '日本の文化がすきですから。', 'Nihon no bunka ga sukidesu kara', NULL, 'Bởi vì tôi thích văn hóa Nhật.', 5335, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14166, 'あしたは 休みます。', 'Ashita wa yasumimasu', NULL, 'Ngày mai tôi sẽ nghỉ làm …どうしてですか。 Dōshite desuka. Tại sao thế?', 5335, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14167, 'いそがしですから。', 'Isogashidesu kara', NULL, 'Vì tôi có việc bận.', 5335, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14168, '私は あたらしいでんわ が あります。', 'Watashi wa atarashii denwa ga arimasu', NULL, 'Tôi có điện thoại mới.', 5336, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14169, 'いもうとが います。', 'Imouto ga imasu', NULL, 'Tôi có em gái.', 5336, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14170, '庭に 何が ありますか。', 'Niwa ni nani ga arimasuka', NULL, 'Ngoài sân có gì thế?', 5337, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14171, 'さくらの木が あります。', 'Sakura ni ki ga arimasu', NULL, 'Có cây hoa anh đào.', 5337, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14172, '教室に 何が いますか。', 'Kyōshitsu ni nani ga kimasuka', NULL, 'Trong lớp học có ai vậy?', 5337, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14173, 'ゆきさんが います。', 'Yukisan ga imasu', NULL, 'Có bạn Yuki', 5337, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14174, '田中さんは 事務所に います。', 'Tanakasan wa jimusho ni imasu', NULL, 'Bạn Tanaka ở văn phòng.', 5338, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14175, '電話は かばんに あります。', 'Denwa wa kaban ni arimasu', NULL, 'Điện thoại ở trong cặp. Hoang Thanh', 5338, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14176, 'はどこにありますか。', 'Hoang Thanh wa doko ni arimasuka', NULL, 'Hoàng Thành ở đâu?', 5338, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14177, 'ハノイです。', 'Hanoi desu', NULL, 'Ở Hà Nội. Chú ý:', 5338, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14178, 'つくえのうえに はなが あります。', 'Tsukue no ue ni hana ga arimasu', NULL, 'Trên bàn có hoa.', 5339, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14179, 'えきのまえに としょかんが あります。', 'Eki no mae ni toshokan ga arimasu', NULL, 'Trước nhà ga có thư viện.', 5339, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14180, '公園の近くで 友達と 会います。', 'Kouen no chikaku de tomodachi to aimasu', NULL, 'Tôi gặp bạn ở gần công viên.', 5339, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14181, 'つくえのうえに ほん や ペンが あります。', 'Tsukue no ue ni hon ya pen ga arimasu', NULL, 'Trên bàn có sách, bút …', 5340, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14182, '私のかばんの中に でんわ や さいふが あります。', 'Watashi no kaban no naka ni denwa ya saifu ga arimasu', NULL, 'Trong cặp sách của tôi có điện thoại, ví ,…', 5340, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14183, 'かばんをいくつかいましたか。', 'Kaban wo ikutsu kaimashitaka', NULL, 'Bạn đã mua mấy cái cặp?', 5341, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14184, 'ふたつかいました。', 'Futatsu kaimashita', NULL, 'Tôi đã mua 2 cái. １００円の切手を１枚ください。 Hyaku en no kitte wo ichimai kudasai. Lấy cho tôi 1 cái tem 100 yên.', 5341, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14185, '家族は何人ですか。', 'Kazoku wa nannin desuka', NULL, 'Nhà bạn có bao nhiêu người. ３人です。 San nin desu. Nhà tôi có 3 người. １週間に何回にほんごをならいますか。 Isshūkan ni nankai nihongo wo naraimasuka. Mỗi tuần bạn học tiếng nhật mấy lần? ３かいです。 San kai desu. Tôi học 3 lần.', 5341, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14186, 'あなたはどのくらい日本語をべんきょうしましたか。', 'Anata wa donokurai nihongo wo benkyōshimashitaka', NULL, 'Bạn đã học tiếng Nhật bao lâu rồi? ３か月べんきょうしました。 Sankagetsu benkyōshimashita. Tôi đã học khoảng 3 tháng rồi.', 5342, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14187, 'あなたはうちからがっこうまでバイクでどのくらいかかりますか。', 'Anata wa uchi kara gakkō made baiku de donokurai kakarimasuka', NULL, 'Bạn đi từ nhà đến trường bằng xe máy mất bao lâu? ３０分かかります。 Sanjuppun kakarimasu. Mất khoảng 30 phút.', 5342, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14188, '昨日は雨じゃありませんでした。', 'Kinō wa ame ja arimasendeshita', NULL, 'Hôm qua không mưa.', 5343, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14189, '先週、私はひまでした。', 'Senshū, watashi wa himadeshita', NULL, 'Tuần trước tôi rảnh.', 5343, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14190, 'きのうはさむかったです。', 'Kinō wa samukattadesu', NULL, 'Hôm qua trời lạnh.', 5344, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14191, 'おととい、パンはおいしくなかったです。', 'Ototoi, pan wa oishikunakattadesu', NULL, 'Hôm kia, bánh mì không ngon.', 5344, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14192, 'このかばんは そこかば よりきれいです。', 'Kono kaban wa soko kaba yori kireidesu', NULL, 'Túi này đẹp hơn túi kia.', 5345, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14193, '日本語と 英語と どちらが すきですか。', 'Nihongo to eigo to dochira ga sukidesu ka', NULL, 'Tiếng Nhật và tiếng Anh, bạn thích tiếng nào hơn?', 5346, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14194, '日本語の ほうが すきです。', 'Nihongo no hō ga sukidesu', NULL, 'Tôi thích tiếng Nhật hơn.', 5346, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14195, '本と 映画と どちらが おもしろいですか。', 'Hon to eiga to dochira ga omoshiroidesu ka', NULL, 'Sách và phim cái nào thú vị hơn?', 5346, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14196, 'どちらも おもしろいです。', 'Dochira mo omoshiroidesu', NULL, 'Cả 2 đều thú vị.', 5346, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14197, 'ベトナムで どこが いちばん きれいですか。', 'Betonamu de doko ga ichiban kireidesu ka', NULL, 'Ở Việt Nam, nơi nào đẹp nhất?', 5347, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14198, 'ハノイが いちばん きれいです。', 'Hanoi ga ichiban kireidesu', NULL, 'Hà Nội là nơi đẹp nhất.', 5347, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14199, '日本料理の中で 何がいちばん好 きですか。', 'Nihonryōri no naka de nani ga ichiban sukidesu ka', NULL, 'Trong các món ăn của Nhật Bản, bạn thích món nào nhất.', 5347, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14200, 'たこやきがいちばん好 きです。', 'Takoyaki ga ichiban sukidesu', NULL, 'Tôi thích nhất món takoyaki.', 5347, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14201, 'あなたは何がほしいですか。', 'Anata wa nani ga hoshiidesuka', NULL, 'Bạn muốn có cái gì?', 5348, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14202, '電話がほしいです。', 'Denwa ga hoshiidesu', NULL, 'Tôi muốn có điện thoại', 5348, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14203, 'どんなうちがほしいですか。', 'Donna uchi ga hoshii desuka', NULL, 'Bạn muốn một ngôi nhà như thế nào?', 5348, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14204, '広いうちがほしいです。', 'Hiroi uchi ga hoshii desu', NULL, 'Tôi muốn một ngôi nhà rộng.', 5348, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14205, '明日、あなたは何をしたいですか。', 'Ashita anata wa nani wo shitai desuka', NULL, 'Ngày mai bạn muốn làm gì?', 5349, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14206, 'えいがをみたいです。', 'Eiga wo mitaidesu', NULL, 'Tôi muốn xem phim.', 5349, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14207, '何をかいたいですか。', 'Nani wo kaitaidesuka', NULL, 'Bạn muốn mua gì?', 5349, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14208, '花をかいたいです。', 'Hana wo kaitaidesu', NULL, 'Tôi muốn mua hoa.', 5349, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14209, 'つりをしたくないです。', 'Tsuri wo shitakunaidesu', NULL, 'Tôi không muốn câu cá.', 5349, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14210, '図書館へなにをしにいきますか。', 'Toshokan e nani wo shi ni ikimasuka', NULL, 'Bạn đến thư viện để làm gì?', 5350, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14211, 'へ本をかりにいきます。', 'Hon wo kari ni ikimasu', NULL, 'Tôi đến để mượn sách.', 5350, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14212, 'レストランへにほんりょうりをたべにいきます。', 'Resutoran e nihon ryouri wo tabe ni ikimasu', NULL, 'Tôi đến nhà hàng để ăn món ăn Nhật.', 5350, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14213, '夏休みはどこか（へ）行きますか。', 'Natsu yasumi wa dokoka (e) ikimasuka', NULL, 'Nghỉ hè bạn có đi đâu không?', 5351, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14214, 'はい。いきます。', 'Hai', NULL, 'Ikimasu. Có, tôi có đi.', 5351, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14215, '暑いですから、何か（を）飲みたいです。', 'Atsui desu kara, nanika (wo) nomitaidesu', NULL, 'Vì trời nóng nên tôi muốn uống cái gì đó.', 5351, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14216, 'ちょっと待ってください。', 'Chotto matte kudasai', NULL, 'Vui lòng/Xin hãy chờ một chút.', 5354, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14217, 'ほんをとってくだし。', 'Hon wo totte kudashi', NULL, 'Vui lòng/Xin hãy lấy cho tôi quyển sách.', 5354, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14218, '今あなたは何をしていますか。', 'Ima anata wa nani o shite imasu ka', NULL, 'Bây giờ bạn đang làm gì vậy?', 5355, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14219, '私は映画をみています。', 'Watashi wa eiga o mite imasu', NULL, 'Tôi đang xem phim.', 5355, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14220, '彼はあそんでいます。', 'Kare wa asonde imasu', NULL, 'Anh ấy đang đi chơi.', 5355, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14221, '地図をかきましょうか。', 'Chizu o kakimashou ka', NULL, 'Tôi vẽ bản đồ cho bạn nhé!', 5356, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14222, 'ええ、おねがいします。', 'E e, onegaishimasu', NULL, 'Vâng, bạn giúp tôi nhé!', 5356, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14223, '電気をけしましょうか。', 'Denki wo keshimashouka', NULL, 'Tôi tắt đèn giúp bạn nhé!', 5356, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14224, 'ここでたばこをすってはいけません。', 'Koko de tabako wo sutte wa ikemasen', NULL, 'Ở đây không được hút thuốc.', 5358, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14225, 'ここでサッカをしてもいいですか。', 'Koko de sakka o shite mo īdesuka', NULL, 'Tôi hút thuốc ở đây có được không?', 5358, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14226, '私はハノイにすんでいます。', 'Watashi wa Hanoi ni sunde imasu', NULL, 'Tôi sống ở Hà Nội', 5359, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14227, '私はリンさんの電話番をしっています。', 'Watashi wa Rinsan no denwaban wo shitte imasu', NULL, 'Tôi biết số điện thoại của Linh. 3.2. Biểu thị những tập quán, thói quen, những hành động được lặp đi lặp lại trong thời gian dài. • Ví dụ:', 5359, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14228, '私はぼうえき大学で勉強しています。', 'Watashi wa bō eki daigaku de benkyō shite imasu', NULL, 'Tôi học ở trường Đại học Ngoại thương', 5359, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14229, 'センターでにほんごをならっています。', 'Watashi wa Mina sentā de ni hon go o naratte imasu', NULL, 'Tôi học tiếng Nhật ở Trung tâm Mina.', 5359, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14230, 'うちへかえってから、ごはんをつくります。', 'Uchi e kaette kara, gohan wo tsukurimasu', NULL, 'Sau khi về nhà, tôi đun cơm.', 5361, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14231, '勉強してから、映画をみました。', 'Benkyōshite kara, eiga wo mimashita', NULL, 'Sau khi học bài, tôi đã xem phim.', 5361, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14232, '彼はあたまがいいです。', 'Kare wa atama ga īdesu', NULL, 'Anh ấy thông minh.', 5362, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14233, 'リンさんはかみがみじかいです。', 'Rinsan wa kami ga mijikaidesu', NULL, 'Linh có mái tóc ngắn.', 5362, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14234, '田中さんは元気で、親切です。', 'Tanakasan wa genkide, shinsetsudesu', NULL, 'Anh Tanaka khỏe mạnh và tốt bụng.', 5363, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14235, '山田さんは２５歳で、独身です。', 'Yamadasan wa 25 sai de, dokushindesu', NULL, 'Anh Yamada 25 tuổi và đang độc thân.', 5363, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14236, '大学までどうやっていきますか。', 'Daigaku made dō yatte ikimasu ka', NULL, 'Đến trường bạn đi như thế nào? …バス乗り場まで 5分ぐらいあるいて、２０番のバスに乗って、大学前でおります。 Basu noriba made 5pun gurai aruite, 20 ban no basu ni notte, daigaku mae de orimasu. …Tôi đi bộ khoảng 5 phút đến bến xe bus, lên xe số 16 và xuống ở đằng trước trường.', 5364, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14237, 'マイさんはどの人ですか。', 'Maisan wa dono hito desuka', NULL, 'Mai là bạn nào?', 5365, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14238, 'あの髪が短くて、背がたかい人です。', 'Ano kami ga mijikakute, se ga takai hitodesu', NULL, '… Là người tóc ngắn và dáng cao.', 5365, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14239, 'ここにじどうしゃを止まらないでください。', 'Koko ni jidōsha wo tomaranaide kudasai', NULL, 'Xin đừng đỗ xe ở đây.', 5367, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14240, 'ここでしゃしんをとらないでください。', 'Koko de shashin wo toranaide kudasai', NULL, 'Xin đừng chụp ảnh ở đây.', 5367, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14241, '早くうちへかえらなければなりません。', 'Hayaku uchi e kaeranakereba narimasen', NULL, 'Tôi phải về nhà sớm.', 5368, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14242, '病気ですから、薬をのまなければなりません。', 'Byōkidesukara, kusuri wo nomanakereba narimasen', NULL, 'Vì ốm nên tôi phải uống thuốc.', 5368, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14243, '毎日いくつもんだいをしますか。', 'Mainichi ikutsu mondai wo shimasu ka', NULL, 'Mỗi ngày, bạn phải làm mấy bài tập? １０もんだいをしなければなりません。 10 mondai wo shinakereba narimasen. Tôi phải làm 10 bài.', 5368, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14244, '名前をかかなくてもいいです。', 'Namae wo kakanakute mo īdesu', NULL, 'Không cần điền tên cũng được.', 5369, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14245, 'あしたはとしょかんへこなくてもいいです。', 'Ashita wa toshokan e konakute mo iidesu', NULL, 'Ngày mai không cần đến thư viện cũng được.', 5369, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14246, 'ここで靴をぬがなくてもいいですか。', 'Koko de kutsu wo nuga nakute mo īdesu ka', NULL, 'Ở đây không cởi giày ra được không.', 5369, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14247, 'ここに 荷物を 置かないでください。', 'Koko ni nimotsu wo okanaide kudasai', NULL, 'Đừng để hành lý ở đây. →', 5370, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14248, '荷物は ここに 置かないでください。', 'Nimotsu wa koko ni okanaide kudasai', NULL, 'Hành lý thì xin đừng để ở đây', 5370, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14249, '外でたばこをすってください。', 'Soto de tabako wo sutte kudasai', NULL, 'Vui lòng hút thuốc ở bên ngoài. →', 5370, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14250, 'たばこは外ですってください。', 'Tabako wa soto de sutte kudasai', NULL, 'Thuốc thì hãy hút ở bên ngoài.', 5370, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14251, 'レポートはいつまでに出さなければなりませんか。', 'Repōto wa itsu made ni dasanakereba narimasen ka', NULL, 'Báo cáo phải nộp chậm nhất khi nào?', 5371, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14252, '木曜日までに出してください。', 'Mokuyōbi made ni dashite kudasai', NULL, 'Nộp chậm nhất là thứ 5.', 5371, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14253, '会議は ５時(じ)までに 終(お)わります。', 'Kaigi wa 5 ji made ni owarimasu', NULL, 'Cuộc họp sẽ kết thúc trước 5 giờ.', 5371, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14254, '日本語ができます。', 'Nihongo ga dekimasu', NULL, 'Tôi biết tiếng Nhật/ có thể nói tiếng Nhật.', 5373, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14255, 'リンさんはピアノができます。', 'Rinsan wa piano ga dekimasu', NULL, 'Linh biết/ có thể chơi piano.', 5373, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14256, '絵をかくことができます。', 'E wo kakukoto ga dekimasu', NULL, 'Tôi biết/ có thể vẽ tranh (Năng lực)', 5373, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14257, 'カードで払(はら)うことが できます。', 'Kādo de haraukoto ga dekimasu', NULL, 'Có thể thanh toán/ trả tiền bằng thẻ. (Khả năng)', 5373, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14258, 'あなたの趣味は何ですか。', 'Anata no shumi wa nandesuka', NULL, 'Sở thích của bạn là gì?', 5374, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14259, 'りょこうです。', 'Ryokōdesu', NULL, 'Là đi du lịch.', 5374, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14260, 'うたをうたうことです。', 'Uta o utaukoto desu', NULL, 'Là ca hát.', 5374, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14261, 'いつこの薬をのみますか。', 'Itsu kono kusuri wo nomimasuka', NULL, 'Uống thuốc này khi nào?', 5375, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14262, 'ねるまえにのみます。', 'Neru mae ni nomimasu', NULL, 'Uống trước khi ngủ.', 5375, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14263, '会議の前に、レポートを準備しました。', 'Kaigi no mae ni, repōto wo junbi shimashita', NULL, 'Trước cuộc họp, tôi đã chuẩn bị báo cáo. ３月前に、フエへ来ました。 San tsuki mae ni, fue e kimashita. 3 tháng trước, tôi đã đến Huế.', 5375, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14264, 'バスが なかなか 来(き)ません。', 'Basu ga nakanaka kimasen', NULL, 'Xe buýt mãi mà không thấy tới', 5376, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14265, 'ハノイでなかなか雪を見ることができません。', 'Hanoi de nakanaka yuki wo mirukoto ga dekimasen', NULL, 'Ở Hà Nội, mãi mà tôi không nhìn thấy tuyết.', 5376, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14266, 'ぜひにほんへいきたいです。', 'Zehi Nihon e ikitaidesu', NULL, 'Tôi rất muốn đi Nhật Bản (nhất định sẽ đi)', 5377, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14267, 'ぜひ遊びに来てください。', 'Zehi asobi ni kite kudasai', NULL, 'Bạn nhất định phải đến nhà tôi chơi đấy nhé!', 5377, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14268, 'あなたはにほんへいったことがありますか。', 'Anata wa nihon e itta koto ga arimasuka', NULL, 'Bạn đã bao giờ đến Nhật Bản chưa?', 5379, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14269, 'おさけをのんだことがありますか。', 'Osake wo nonda koto ga arimasuka', NULL, 'Bạn đã bao giờ uống rượu chưa?', 5379, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14270, 'はい。あります。はい、２回あります。', 'Hai', NULL, 'Arimasu. Hai, 2-kai arimasu. Có, đã từng / Có, đã 2 lần.', 5379, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14271, '私はすもうをみたことがありません。', 'Watashi wa sumō wo mita koto ga arimasen', NULL, 'Tôi chưa bao giờ xem vật Sumo.', 5379, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14272, '日曜日そうじしたり、せんたくしたりします。', 'Nichiyōbi sōjishitari, sentakushitari shimasu', NULL, 'Chủ nhật, lúc thì tôi hút bụi, lúc thì tôi giặt quần áo.', 5380, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14273, 'きのう、公園を散歩したり、レストランでたべたりしました。', 'Kinō, kōen wo sanposhitari, resutoran de tabetari shimashita', NULL, 'Hôm qua lúc thì tôi đi dạo ở công viên, lúc thì ăn ở nhà hàng.', 5380, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14274, '毎晩音楽を聞いたり、幹事を書いたりします。', 'Maiban ongaku wo kiitari, kanji wo kaitari shimasu', NULL, 'Mỗi tối, lúc thì tôi nghe nhạc, lúc thì viết kanji.', 5380, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14275, '私は２１さいになりました。', 'Watashi wa 21 sai ni narimashita', NULL, 'Tôi đã được 21 tuổi.', 5381, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14276, '毎日日本語をべんきょうしましたから、日本語が上手になります。', 'Mainichi nihongo wo benkyō shimashitakara, nihongo ga jōzu ni narimasu', NULL, 'Vì mỗi ngày tôi đều học tiếng Nhật nên tôi trở nên giỏi tiếng Nhật.', 5381, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14277, '今日、かばんはやすくなります。', 'Kyō, kaban wa yasuku narimasu', NULL, 'Hôm nay túi xách trở nên rẻ hơn.', 5381, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14278, 'ううん、暇ではない。', '', NULL, NULL, 5382, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14279, 'ううん、暇じゃない。', '', NULL, NULL, 5382, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14280, '3)このりんご「は」おいしいですね。', '', NULL, NULL, 5382, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14281, 'うん、持って「い」る。', '', NULL, NULL, 5382, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14282, 'ううん、持って「い」ない。', '', NULL, NULL, 5382, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14283, '漢字はむずかしいと思います。', 'Kanji wa muzukashī to omoimasu', NULL, 'Tôi nghĩ chữ Hán khó.', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14284, 'けいたい電話は便利だと思います。', 'Keitai denwa wa benrida to omoimasu', NULL, 'Tôi nghĩ điện thoại di động tiện lợi.', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14285, 'あした雨がふらないと思います。', 'Ashita ame ga furanai to omoimasu', NULL, 'Tôi nghĩ ngày mai trời sẽ không mưa.', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14286, '田中さんは時間の使い方が上手だと思います。', 'Tanakasan wa jikan no tsukaikata ga jōzuda to omoimasu', NULL, 'Tôi nghĩ anh Tanaka rất giỏi sử dụng thời gian.', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14287, '彼女は 日本人だと 思います。', 'Kanojo wa nihonjinda to omoimasu', NULL, 'Tôi nghĩ cô ấy là người Nhật Bản. Chú ý: (1) Khi nói câu phủ định, có 2 cách thể hiện:', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14288, '日本語のテストは どうですか。', 'Nihongo no tesuto wa dōdesu ka', NULL, 'Bài kiểm tra tiếng Nhật thế nào? …', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14289, 'むずかしくないと 思います。', 'Muzukashikunaito omoimasu', NULL, 'Tôi nghĩ là không khó. …', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14290, 'むずかしいと 思いません。', 'Muzukashī to omoimasen', NULL, 'Tôi không nghĩ là khó. (2) Cách nói ngắn khi đồng ý hay không đồng ý với quan điểm của ai đó: A:', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14291, 'ファクスは 便利ですね。', 'Fakusu wa benri desu ne', NULL, 'Máy fax thuận tiện thật đấy nhỉ! B:', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14292, '私も そう思います。', 'Watashi mo sō omoimasu', NULL, 'Tôi cũng nghĩ như vậy C:', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14293, '思いません。', 'Watashi wa sō [wa] omoimasen', NULL, 'Tôi thì không nghĩ là như vậy (3) Câu hỏi: khi muốn hỏi quan điểm của ai đó về 1 vấn đề nào đó, ta dùng mẫu câu ～に', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14294, '新しい空港に ついて どう思いますか。', 'Atarashī kūkō ni tsuite dō omoimasu ka', NULL, 'Bạn nghĩ thế nào về sân bay mới? …きれいですが、ちょっと交通が', 5383, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14295, '食べる前に「いただきます」と 言います。', 'Taberu maeni [itadakimasu] to iimasu', NULL, 'Trước khi ăn thì nói “ Mời anh/chị dùng”.', 5384, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14296, 'ミラーさんは「来週 東京へ 出張 します」と 言いました。', 'Mirā-san wa [raishū Tōkyō e shutchōshimasu] to iimashita', NULL, 'Ông Miler đã nói rằng “Tuần sau tôi sẽ đi công tác Tokyo”. – Trích dẫn gián tiếp: sử dụng thể thông thường trước trợ từ', 5384, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14297, '田中さんはおかねが足らないと言いました。', 'Tanaka-san wa okane ga taranai to iimashita', NULL, 'Anh Tanaka đã nói rằng anh ý không có đủ tiền.', 5384, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14298, '田中さんは会議は大変だと言いました。', 'Tanaka-san wa kaigi wa taihenda to iimashita', NULL, 'Anh Tanaka đã nói rằng cuộc họp vất vả.', 5384, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14299, '山田さんは来月ベトナムへいくと言いました。', 'Yamada-san wa raigetsu Betonamu e iku to iimashita', NULL, 'Anh Yamada đã nói là tháng sau sẽ đến Việt Nam.', 5384, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14300, 'ハイさんはこの食べ物がおいしいと言いました。', 'Hai-san wa kono tabemono ga oishī to iimashita', NULL, 'Hải đã nói rằng món ăn này ngon.', 5384, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14301, 'ええ、行きます。', 'Ee, ikimasu', NULL, 'Ừ, đi chứ.', 5385, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14302, 'ええ、とてもしんせつです。', 'Ee, totemo shinsetsudesu', NULL, 'Ừ, rất thân thiện.', 5385, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14303, 'ハイさんは日本語の先生でしょう。', 'Hai-san wa nihongo no senseideshou', NULL, 'Anh Hải là giáo viên tiếng Nhật nhỉ?', 5385, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14304, '神戸(こうべ)で 大(おお)きい 地(じ)震(しん)が ありました。', 'Kōbe de ōkī jishin ga arimashita', NULL, 'Ở Kobe đã (có) xảy ra trận động đất lớn.', 5386, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14305, '明日、雪ちゃんのうちでパーティーがあります。', 'Ashita, yuki-chan no uchi de pātī ga arimasu', NULL, 'Ngày mai, ở nhà Mai sẽ tổ chức tiệc.', 5386, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14306, 'ミラーさんは ケーキを 作(つく)りました。', 'Mirā-san wa kēki wo tsukurimashita', NULL, 'Ông Miller đã làm bánh ngọt. →', 5388, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14307, 'これは ミラーさんが 作(つく)ったケーキです。', 'Kore wa mirā-san ga tsukutta kēkidesu', NULL, 'Đây là cái bánh ngọt ông Miller đã làm.', 5388, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14308, 'ハイさんがうまれたところはハノイです。', 'Hai-san ga umareta tokoro wa Hanoidesu', NULL, 'Nơi mà anh Hải đã sinh ra là Hà Nội.', 5388, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14309, 'これは女の人がよむざっしです。', 'Kore wa onnanohito ga yomu zasshidesu', NULL, 'Đây là tạp chí mà phụ nữ thường đọc.', 5388, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14310, '新聞を読むとき、めがねをかけます。', 'Shinbun wo yomu toki, megane wo kakemasu', NULL, 'Tôi đeo kính khi đọc báo.', 5389, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14311, '出かけるとき、「いってまいります」と言います。', 'Dekakeru toki “itte mairimasu” to iimasu', NULL, 'Khi ra ngoài thì nói là “Tôi đi đây”.', 5389, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14312, 'こないとき、私にれんらくしてください。', 'Konai toki, watashi ni renrakushite kudasai', NULL, 'Khi bạn không đến thì hãy liên lạc với tôi.', 5389, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14313, 'ひまなとき、映画をみます。', 'Himana toki, eiga wo mimasu', NULL, 'Khi rảnh rỗi thì tôi xem phim ２７歳のとき、けっこんしました。 27 sai no toki, kekkonshimashita. Khi tôi 27 tuổi, tôi đã kết hôn.', 5389, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14314, '東京へ行くとき、このかばんを 買いました。', 'Tōkyō e iku toki, kono kaban wo kaimashita', NULL, 'Tôi đã mua chiếc cặp này khi đi Tokyo。（Chiếc cặp này được mua trên đường đi đến Tokyo）', 5390, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14315, '東京へ行ったとき、このかばんを 買いました。', 'Tōkyō e itta toki, kono kaban wo kaimashita', NULL, 'Tôi đã mua chiếc cặp này khi đi Tokyo. (Chiếc cặp này được mua sau khi đã đến Tokyo ）', 5390, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14316, 'でかけるとき、電気を消してください。', 'Dekakeru toki, denki wo keshite kudasai', NULL, 'Khi ra khỏi nhà, phải tắt điện.', 5390, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14317, 'でたとき、ドアをしめてください。', 'Deta toki, doa wo shimete kudasai', NULL, 'Khi ra khỏi nhà, phải đóng cửa.', 5390, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14318, 'このボタンを 押すと、お釣りが 出ます。', 'Kono botan wo osu to, otsuri ga demasu', NULL, 'Nếu bấm nút này thì tiền thừa sẽ chạy ra.', 5391, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14319, 'これを 回すと、音が 大きく なります。', 'Kore wo mawasu to, on ga ōkiku narimasu', NULL, 'Nếu vặn cái này thì tiếng sẽ to lên.', 5391, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14320, '右へ 曲がると、郵便局が あります。', 'Migi e magaru to, yūbinkyoku ga arimasu', NULL, 'Nếu rẽ phải thì sẽ có một cái bưu điện.', 5391, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14321, '日本語が 分からないと、困りますよ。', 'Nihongo ga wakaranai to, komarimasu yo', NULL, 'Nếu không biết tiếng Nhật thì sẽ khó khăn đấy.', 5391, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14322, 'もっと がんばらないと、合格できません。', 'Motto ganbaranai to, gōkaku dekimasen', NULL, 'Nếu không cố gắng hơn nữa thì sẽ không thể đỗ được', 5391, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14323, '音(おん)が 小(ちい)さいです。', 'On ga chīsaidesu', NULL, 'Tiếng nhỏ.', 5392, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14324, '天気(てんき)が 明(あか)るくなりました。', 'Tenki ga akaru ku narimashita', NULL, 'Thời tiết trở nên quang đãng.', 5392, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14325, 'この ボタンを 押(お)すと、切符(きっぷ)が 出(で)ます。', 'Kono botan wo osu to, kippu ga demasu', NULL, 'Nếu bấm nút này thì vé sẽ ra.', 5392, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14326, '橋(はし)を 渡(わた)ります。', 'Hashi wo watarimasu', NULL, 'Đi qua cầu.', 5393, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14327, '公園(こうえん)を 散歩(さんぽ)します。', 'Kōen wo sanposhimasu', NULL, 'Đi dạo trong công viên.', 5393, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14328, '交差点(こうさてん)を 右(みぎ)へ 曲(ま)がります。', 'Kōsaten wo migi e magarimasu', NULL, 'Rẽ phải ở ngã tư.', 5393, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14329, '私は 佐(さ)藤(とう)さんに 花(はな)を あげました。', 'Watashi wa Satō-san ni hana wo agemashita', NULL, 'Tôi đã tặng hoa cho chị Sato.', 5394, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14330, '佐藤(さとう)さんは キムさんに プレゼントを あげました。', 'Satō-san wa Kimu-san ni purezento wo agemashita', NULL, 'Chị Sato đã tặng quà cho bạn Kim.', 5394, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14331, '佐藤(さとう)さんは 私に クリスマスカードを くれました。', 'Satō-san wa watashi ni kurisumasukādo wo kuremashita', NULL, 'Sato đã tặng tôi một tấm thiếp Giáng Sinh. =&gt;', 5394, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14332, '佐藤(さとう)さんは 妹(いもうと) に お菓子(かし)を くれました。', 'Satō-san wa imōto ni okashi wo kuremashita', NULL, 'Sato đã tặng kẹo cho em gái tôi.', 5394, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14333, '私はおじいさんに道を教えてあげました。', 'Watashi wa ojīsan ni michi wo oshiete agemashita', NULL, 'Tôi đã chỉ đường cho ông.', 5395, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14334, '私は雪ちゃんに日本語の本をかしてあげました。', 'Watashi wa yuki-chan ni nihongo no hon wo kashite agemashita', NULL, 'Tôi đã cho bạn Yuki mượn quyển sách tiếng Nhật.', 5395, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14335, '私はおばあさんに手紙をよんであげました。', 'Watashi wa obāsan ni tegami wo yonde agemashita', NULL, 'Tôi đã đọc thư cho bà.', 5395, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14336, '私は田中さんに日本語を教えてもらいました。', 'Watashi wa Tanaka-san ni nihongo o oshiete moraimashita', NULL, 'Tôi được anh Tanaka dạy cho tiếng Nhật.', 5396, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14337, '私はハイさんに引っ越しをてつだってもらいました。', 'Watashi wa Hai-san ni hikkoshi wo tetsudatte moraimashita', NULL, 'Tôi được anh Hải giúp chuyển nhà.', 5396, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14338, '私は友達にケーキをつくってもらいました。', 'Watashi wa tomodachi ni kekī wo tsukutte moraimashita', NULL, 'Tôi được bạn làm tặng bánh.', 5396, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14339, '私は雪ちゃんに傘を貸してもらいました。', 'Watashi wa Yuki-chan ni kasa wo kashite moraimashita', NULL, 'Tôi được Yuki cho mượn ô.', 5397, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14340, '雪ちゃんは(私に)傘を貸してくれました。', 'Yuki-chan wa (watashi ni) kasa wo kashite kuremashita', NULL, 'Yuki đã cho tôi mượn ô.', 5397, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14341, '家内は（私に）子供の写真を 送ってくれました。', 'Kanai wa (watashi ni) kodomo no shashin wo okutte kuremashita', NULL, 'Vợ tôi gửi ảnh mấy đứa con (cho tôi).', 5397, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14342, '加藤さんは（私に）宿題を 出してくれました。', 'Katō san wa (watashi ni) shukudai wo dashite kuremashita', NULL, 'Bạn Kato đã nộp bài tập (giúp tôi).', 5397, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14343, 'だれに日本語を教えてもらいましたか。', 'Dare ni nihongo wo oshiete moraimashita ka', NULL, 'Bạn được ai dạy cho tiếng Nhật?', 5397, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14344, '糸永先生に教えてもらいました。', 'Itonaga sensei ni oshiete moraimashita', NULL, 'Tôi được cô Itonaga dạy.', 5397, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14345, 'だれがお金を払ってくれましたか。', 'Dare ga okane o haratte kuremashita ka', NULL, 'Ai đã trả tiền cho bạn?', 5397, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14346, '雪ちゃんが払ってくれました。', 'Yuki-chan ga haratte kuremashita', NULL, 'Bạn Yuki đã trả tiền cho tôi.', 5397, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14347, '家へ 帰ったら、すぐ シャワーを 浴びます。', 'Uchi e kaettara, sugu shawā wo abimasu', NULL, 'Về nhà là tôi đi tắm ngay.', 5399, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14348, '何時ごろ 見学に 行きますか。', 'Nanji goro kengaku ni ikimasu', NULL, 'Khoảng mấy giờ thì đi tham quan? …昼ごはんを', 5399, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14349, '食べたら、すぐ 行きます。', 'Hiru gohan wo tabetara, sugu ikimasu', NULL, 'Sau khi ăn cơm trưa xong là đi ngay.', 5399, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14350, 'スイッチを 入れても、機械が 動きません。', 'Suitchi wo irete mo, kikai ga ugokimasen', NULL, 'Dù đã bật công tắc nhưng máy vẫn không chạy.', 5400, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14351, '高くても、このラジカセを 買いたいです。', '', NULL, NULL, 5400, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14352, '静かでも、寝ることが できません。', '', NULL, NULL, 5400, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14353, '日曜日でも、仕事を します。', '', NULL, NULL, 5400, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14354, 'もし １億円あったら、いろいろな国を 旅行したいです。', 'Moshi ichi oku en attara, iroirona kuni wo ryokōshitaidesu', NULL, 'Giả sử, nếu có 100 triệu yên tôi muốn đi du lịch thật nhiều nước.', 5401, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14355, 'いくら 考えても、分かりません。', 'Ikura kangaetemo, wakarimasen', NULL, 'Mặc dù có suy nghĩ bao nhiêu đi chăng nữa cũng chẳng hiểu được.', 5401, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14356, 'いくら安くても、いらないものを買わないほうがいいです。', 'Ikura yasukute mo, iranai mono wo kawanai hō ga īdesu', NULL, 'Dù có rẻ thế nào thì đồ không cần thiết không nên mua thì tốt hơn.', 5401, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14357, '友達が来る前に、部屋を掃除します。', 'Tomodachi ga kuru mae ni, heya wo sōji shimasu', NULL, 'Trước khi bạn đến chơi, tôi dọn phòng.', 5402, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14358, '妻が病気のとき、会社を休みます。', 'Tsuma ga byōki no toki, kaisha wo yasumimasu', NULL, 'Khi vợ bị ốm, tôi nghỉ làm.', 5402, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14359, '友達が約束の時間に来ないがったら、どうしますか。', 'Tomodachi ga yakusoku no jikan ni konai gattara,-dōshimasu ka', NULL, 'Nếu bạn không đến đúng giờ hẹn thì bạn sẽ làm gì?', 5402, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14360, '渡辺さんは ときどき 大阪べんを 使いますね。大阪に 住んでいたんですか。', 'Watanabe san wa tokidoki Ōsaka ben wo tsukaimasu ne', NULL, 'Ōsaka ni sundeitandesu ka. Anh watanabe thỉnh thoảng dùng tiếng Osaka nhỉ. Anh đã sống ở Osaka à? …ええ、１５歳まで', 5403, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14361, '大阪に 住んでいました。', 'E e, 15-sai made Ōsaka ni sunde imashita', NULL, 'Vâng, tôi đã sống ở Osaka đến năm 15 tuổi. 1.1.2. Khi người nói hỏi về thông tin mà anh ấy nghe hoặc nhìn thấy. Ví dụ:', 5403, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14362, '日本で 買いました。', 'Nihon de kaimashita', NULL, 'Tôi mua ở Nhật Bản. 1.1.3. Khi người nói muốn nghe giải thích nguyên nhân, lý do của sự việc mà anh ấy nghe hoặc nhìn thấy. Ví dụ:', 5403, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14363, 'どうして 遅れたんですか。', 'Dōshite okuretandesu ka', NULL, 'Tai sao anh lại đến muộn thế? * Chú ý: Đôi khi ～んですか biểu thị sự ngạc nhiên, mối nghi ngờ hay sự tò mò sâu sắc. Tuy nhiên, nếu không dùng đúng thì có thể làm tổn thương người nghe. Vì thế nên cẩn thận khi dùng.', 5403, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14364, '社長、帰らないんですか。', 'Shachō kaeranaindesu ka', NULL, 'Anh không về sao, giám đốc? ( Biểu hiện này có hàm ý trách móc, dễ dẫn đến thất lễ) -&gt;', 5403, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14365, '社長、帰りませんか。', 'Shachō kaerimasen ka', NULL, 'Anh không về sao, giám đốc? 1.2. Trong câu trần thuật: 「～んです。」 Biểu hiện này thường dùng trong những trường hợp sau: 1.2.1. Khi trả lời câu hỏi tại sao (phía sau không còn', 5403, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14366, 'どうして 遅れたんですか。', 'Dōshite okuretandesu ka', NULL, 'Tai sao anh lại đến muộn? …バスが', 5403, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14367, '来なかったんです。', 'Basu ga konakattandesu', NULL, 'Tại vì xe buýt không đến. 1.2.2. Khi người nói trình bày thêm nguyên nhân, lý do. (phía sau không còn', 5403, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14368, '毎朝、新聞を 読みますか。', 'Mai asa, shinbun wo yomimasu ka', NULL, 'Hàng sáng anh có đọc báo không? …いいえ。時間が', 5403, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14369, '写真はいつですか？ しゃしんはいつですか？', 'Bao giờ thì xong ảnh vậy? -午後５時ぐらいできます ごご５じぐらいできます Khoảng 5 giờ chiều thì xong', NULL, '-わたしは宿題ができました', 5407, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14370, '私は 毎朝 コーヒーを 飲みながら 新聞を 読みます。', 'Watashi wa mai asa shinbun wo yomimasu', NULL, 'Hàng sáng tôi vừa uống cà phê vừa đọc báo.', 5408, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14371, '彼は テレビを 飲みながら ご飯を 食べています。', 'Kare wa terebi wo in minagara gohan wo tabeteimasu', NULL, 'Anh ấy đang vừa ăn cơm vừa xem tivi.', 5408, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14372, '学生の時、アルバイトをしながら 大学で 勉強しました。', 'Gakusei no toki, arubaito wo shinagara daigaku de benkyōshimashita', NULL, 'Hồi học sinh, tôi vừa làm thêm vừa đi học.', 5408, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14373, '彼は 働きながら 大学に 通っています。', 'Kare wa hatarakinagara daigaku ni kayotte imasu', NULL, 'Anh ấy vừa đi làm vừa đi học đại học.', 5408, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14374, '日本語で 手紙を 書いたんですが、見て いただけませんか。', 'Nihongo de tegami wo kaitandesuga, mite itadakemasenka', NULL, 'Tôi đã viết 1 bức thư bằng’ tiếng Nhật, anh/chị xem giúp tôi được không ạ?', 5409, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14375, 'コピー機の 使い方が 分からないんですが、教えて いただけませんか。', 'Kopī　ki no　tsukai　kata ga wakaranaindesuga, oshiete itadakemasen ka', NULL, 'Tôi không biết cách sử dụng máy photo, anh/chị chỉ giúp tôi được không ạ?', 5409, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14376, '図書館へ行きたいんですが、地図を書いていただけませんか。', 'Toshokan e ikitai ndesuga, chizu wo kaite itadakemasen ka', NULL, 'Tôi muốn đến thư viện, anh/chị vẽ cho tôi bản đồ được không ạ? 2.2. ～んですが、V', 5409, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14377, '日本語を 勉強したいんですが、どうしたら いいですか。', 'Nihongo wo benkyōshitaindesuga, dōshitara īdesu ka', NULL, 'Tôi muốn học tiếng Nhật, vậy thì nên làm thế nào nhỉ? …Mina', 5409, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14378, 'センターで 勉強したら いいと思います。', 'Mina sentā de benkyōshitara ī to omoimasu', NULL, 'Tôi nghĩ anh nên học tiếng Nhật ở Trung tâm Mina.', 5409, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14379, '試験の予定を 知りたいんですが、だれに 聞いたら いいですか。', 'Shiken no yotei wo shiritaindesuga, dare ni kiitara īdesu ka', NULL, 'Tôi muốn biết kế hoạch thi, vậy tôi nên hỏi ai bây giờ? …試験部の Nga', 5409, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14380, 'さんに 聞いて ください。', 'Shikenbu no Nga-san ni kiite kudasai', NULL, 'Anh/chị hãy hỏi chị Nga phòng khảo thí.', 5409, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14381, 'ミラーさんは 親切だし、頭もいいし、それに ハンサムです。', 'Mirā-san wa shinsetsu dashi, atama mo īshi, soreni hansamudesu', NULL, 'Anh Miller vừa tốt bụng, vừa thông minh, hơn nữa lại đẹp trai.', 5410, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14382, 'ミラーさんは ピアノも 弾けるし、ダンスも できるし、それに 歌も 歌えます。', 'Mirā-san wa piano mo hikerushi, dansu mo dekirushi, soreni uta mo utaemasu', NULL, 'Anh Miller vừa chơi được piano, vừa có thể khiêu vũ, hơn nữa cũng có thể hát. 3.2. ～し、～し、（それで）～: vì… và vì… nên… • Cách dùng: cũng được dùng khi trình bày hơn một lý do hoặc nguyên nhân. • Ví dụ:', 5410, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14383, 'きょうは 雨だし、お金もないし、（それで） 出かけません。', 'Kyō wa amedashi, okane mo naishi, (sorede) dekakemasen', NULL, 'Hôm nay trời vừa mưa, hơn nữa không tiền nên tôi không đi ra ngoài.', 5410, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14384, 'この店は 食べ物も おいしいし、値段も 安いし、（それで） 人が 多いです。', 'Kono mise wa tabe mono mo oishīshi, nedan mo yasuishi,(sorede) hito ga ōidesu', NULL, 'Cửa hàng này đồ ăn ngon, hơn nữa giá lại rẻ nên rất đông người. 3.3. ～し、～し、～から: vì…, và vì… (ngoài ra còn có các nguyên nhân khác) • Cách dùng: dùng để trả lời cho câu hỏi tại sao. Với ngụ ý: ngoài những nguyên nhân người ta nêu ra còn có thể có nhiều nguyên nhân khác nữa. • Ví dụ:', 5410, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14385, 'どうして この会社に 入ったんですか。', 'Dōshite kono kaisha ni haitta ndesu ka', NULL, 'Tại sao bạn lại vào công ty này làm việc?', 5410, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14386, '残業も ないし、ボーナスも 多いですから。', 'Zangyō mo naishi, bōnasu mo ō idesukara', NULL, 'Vì không phải làm thêm giờ, và tiền thưởng lại nhiều.', 5410, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14387, '図書館へ行きたいんですが、どのバスに乗ったらいいですか。', 'Toshokan e ikitai ndesuga, dono basu ni nottara īdesu ka', NULL, 'Tôi muốn đến thư viện, vậy tôi nên lên xe bus nào?', 5410, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14388, 'まどが 閉まっています。', 'Mado ga shima tte imasu', NULL, 'Cửa sổ đóng (-&gt; cửa sổ đang trong trạng thái đóng, có thể là do gió hoặc ai đó làm nó đóng lại)', 5411, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14389, 'いすが 壊れています。', 'Isu ga kowarete imasu', NULL, 'Cái ghế bị hỏng (-&gt; cái ghế đang trong trạng thái hỏng, có thể là do ai đó làm hỏng)', 5411, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14390, 'ふくろが 破れています。', 'Fuku ro ga yaburete imasu', NULL, 'Cái túi bị rách (-&gt; cái túi đang trong trạng thái rách, có thể là do vướng vào đâu đó hoặc ai đó làm rách)', 5411, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14391, '窓のガラスが 割れていますから、危ないです。', 'Mado no garasu ga warete imasukara, abunaidesu', NULL, 'Kính cửa sổ bị vỡ nên rất nguy hiểm. (-&gt; kính cửa sổ đang trong trạng thái vỡ, có thể là do ai đó ném đá… làm vỡ) • Chú ý: Khi diễn tả trạng thái xảy ra trong quá khứ, chúng ta dùng Vていました', 5411, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14392, '今朝道が 込んでいました。', 'Kesa michi ga konde imashita', NULL, 'Sáng nay đường đông nghịt. 1.2. N', 5411, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14393, 'このいすは 壊れています。', 'Kono isu wa kowarete imasu', NULL, 'Cái ghế này thì bị hỏng rồi', 5411, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14394, 'その皿は 割れています。', 'Sono sara wa warete imasu', NULL, 'Cái đĩa đó thì vỡ rồi', 5411, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14395, 'あの皿は 汚れていますから、洗ってください。', 'Ano sara wa yogorete imasukara, aratte kudasai', NULL, 'Cái đĩa kia thì bẩn quá, đem đi rửa đi.', 5411, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14396, '宿題は もう やってしまいました。', 'Shukudai wa mō yatte shimaimashita', NULL, 'Bài tập thì tôi đã làm hết rồi.', 5412, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14397, 'お酒を 全部飲んでしまいました。', 'Osake wo zenbu nonde shimaimashita', NULL, 'Tôi đã uống hết rượu rồi. b. Vていしまいます : Sẽ hoàn thành, sẽ xong (1 hành động trong tương lai) • Cách dùng: dùng để diễn tả sự hoàn thành của hành động trong tương lai. • Ví dụ:', 5412, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14398, '明日までに レポートを 書いてしまいます。', 'Ashita made ni repōto wo kaite shimaimasu', NULL, 'Đến ngày mai tôi sẽ viết xong báo cáo. 2.2. Vてしまいました: (làm gì) mất rồi • Cách dùng: dùng để biểu thị sự hối tiếc, tâm trạng biết lỗi của người nói trong một tình huống xấu. • Ví dụ:', 5412, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14399, 'パスポートを 無くしてしまいました。', 'Pasupōto wo nakushite shimaimashita', NULL, 'Tôi làm mất hộ chiếu mất rồi.', 5412, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14400, '電車に かばんを 忘れてしまいました。', 'Densha ni kaban wo wasurete shimaimashita', NULL, 'Tôi để quên cặp trên xe điện mất rồi.', 5412, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14401, 'スーパーで 財布を 落としてしまいました。', 'Sūpā de saifu wo oto shite shimaimashita', NULL, 'Tôi đánh rơi ví tại siêu thị mất rồi.', 5412, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14402, '壁に 地図が はってあります。', 'Kabe ni chizu ga hatte arimasu', NULL, 'Trên tường có dán bản đồ. (hàm ý là một ai đó đã dán bản đồ lên tường nhằm một mục đích nào đó và kết quả là trên tường hiện có bản đồ)', 5413, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14403, '教室に テレビが 置いてあります。', 'Kyōshitsu ni terebi ga oite arimasu', NULL, 'Trong lớp học có đặt tivi. (hàm ý là một ai đó đã để cái tivi vào trong lớp học nhằm một mục đích nào đó và kết quả là trong lớp hiện có 1 cái tivi)', 5413, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14404, 'これは私の本です。名前が書いてありますから。', 'Kore wa watashi no hon desu', NULL, 'Namae ga kaite arimasukara. Đây là quyển sách của tôi. Vì có ghi tên mà. (hàm ý là tôi đã ghi tên mình vào quyển sách nhằm mục đích không lẫn với của người khác và kết quả là trong quyển sách hiện có tên của tôi) 1.2. N２は N１に V', 5413, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14405, '地図は どこですか。', 'Chizu wa dokodesu ka', NULL, 'Bản đồ ở đâu vậy? B：地図は', 5413, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14406, '壁に 張ってあります。', 'Chizu wa kabe ni watte arimasu', NULL, 'Bản đồ có dán ở trên tường.', 5413, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14407, 'パスポートは 引き出しの中に しまってあります。', 'Pasupōto wa hikidashi no naka ni shimatte arimasu', NULL, 'Hộ chiếu được cất ở trong ngăn kéo', 5413, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14408, '旅行の まえに、切符を 買っておきます。', 'Ryokō no mae ni, kippu wo katte okimasu', NULL, 'Trước khi đi du lịch tôi sẽ mua vé trước.', 5414, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14409, 'パーティの まえに、部屋を 掃除しておきます。', 'Pāti no mae ni,heya wo sōjishite okimasu', NULL, 'Trước bước tiệc, tôi sẽ dọn dẹp phòng trước.', 5414, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14410, 'パーティの まえに、料理を 作っておいたほうがいいです。', 'Pāti no mae ni, ryōri wo tsukutte oita hō ga īdesu', NULL, 'Trước bước tiệc, bạn nên chuẩn bị các món ăn trước. 2.2. （～たら、）～V', 5414, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14411, '授業が 終わったら、電気を 消しておきます。', 'Jugyō ga owattara, denki wokeshite okimasu', NULL, 'Khi kết thúc giờ học thì sẽ tắt điện.', 5414, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14412, 'パーティーが 終わったら、部屋を 片付けておきます。', 'Pātī ga owattara, heya wo ka tazukete okimasu', NULL, 'Khi bữa tiệc kết thúc thì sẽ dọn phòng.', 5414, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14413, '（１） 週 末は デパートで 買い物しよう と思っています。', 'Tôi dự định đi mua sắm vào cuối tuần', NULL, '（２）', 5415, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14414, '今から 銀行へ 行こう と思っています。', 'Tôi dự định đi đến ngân hàng bây giờ', NULL, 'Chú ý : 「~とおもっています」 cũng được dùng để chỉ dự định của người thứ ba', 5415, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14415, '来年結婚する つもりです。', 'Năm tới tôi dự định sẽ kết hôn', NULL, '明日からは', 5415, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14416, 'たばこを 吸わない つもりです。', 'Tôi định từ ngày mai sẽ không hút thuốc', NULL, 'Chú ý: so với mẫu câu V thể ý chí', 5415, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14417, '明日は 雨が 降るでしょう。', 'Có lẽ ngày mai trời sẽ mưa', NULL, '大雨ですから、タワポンさんは', 5417, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14418, '彼は 道を よく 知っていますから、たぶん 大丈夫でしょう。', 'Anh ấy biết đường rất rõ nên có lẽ sẽ ổn thôi', NULL, 'あしたの', 5417, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14419, '午後から 雪が 降る かもしれません。', 'Tuyết có thể sẽ rơi vào buổi chiều cũng nên', NULL, '約束の時間に', 5418, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14420, '間に合わない かもしれません。', 'Chúng ta có lẽ sẽ không kịp giờ hẹn cũng không biết chừng', NULL, '山田さんは', 5418, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14421, 'まだ 来ていませんね。 病気かもしれません。', 'Anh Yamada vẫn chưa đến nhỉ', NULL, 'Có lẽ là ốm cũng nên', 5418, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14422, '駅まで ３０分で 行けますか。', '', NULL, NULL, 5419, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14423, '３万円で ビデオが 買えますか。', '', NULL, NULL, 5419, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14424, '早く寝ろ。', 'Hãy ngủ sớm', NULL, '②', 5421, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14425, 'もっと勉 強しろ。', 'Phải học nhiều hơn', NULL, '③', 5421, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14426, '遅れるな。', 'Không được đến muộn', NULL, 'b) Giữa bạn bè thân thiết với nhau. Trong trường hợp này,', 5421, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14427, '逃げろ。', 'Chạy đi', NULL, '②', 5421, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14428, 'スイッチをきれ。', 'Tắt công tắc điện đi', NULL, '③', 5421, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14429, 'エレベーターを使うな。', 'Không được dùng cầu thang máy', NULL, 'Ví dụ: ①', 5421, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14430, '頑張 が ん ば れ。', 'Cố lên', NULL, '②', 5421, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14431, '走れ。', 'Chạy đi', NULL, '③', 5421, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14432, '負けるな。', 'Không được thua', NULL, 'Ví dụ: ①', 5421, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14433, '止まれ。', 'Dừng lại', NULL, '②', 5421, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14434, '勉 強しなさい。', 'Hãy học đi', NULL, '②', 5422, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14435, 'ちょっと て つ だってくれ。', 'Hãy giúp tôi một chút', NULL, '②', 5423, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14436, 'ちょっと はさみを かして。', 'Cho tôi mượn cái kéo một chút', NULL, '~と読みます =&gt; Đọc là… ~と書いてあります =&gt; Viết là… Ví dụ: ①', 5423, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14437, '1) この 説明書を よめば、 使い方が わかります。', 'Nếu đọc sách hướng dẫn này sẽ hiểu được cách sử dụng', NULL, '2)', 5432, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14438, 'カタログを 見なければ、 値段が わかりません。', 'Nếu không xem cuốn catalogue thì không biết được giá', NULL, '3)', 5432, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14439, 'やすければ、この 車を 買います。', 'Nếu rẻ sẽ mua chiếc ô tô này', NULL, '4)', 5432, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14440, '日曜日は ひまなら、 広島へ 行きます。', 'Nếu chủ nhật rỗi, tôi sẽ đi Hiroshima', NULL, '5)', 5432, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14441, '雨なら、うちで テレビを 見ます。', 'Nếu trời mưa sẽ ở nhà xem tivi', NULL, 'Chú ý: khác với 「~と」, vế sau của thể điều kiện loại này có thể là những mẫu câu diễn đạt ý chí, mong muốn như: 「~Vてください」、「Vましょう」、「Vたいです」 1)', 5432, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14442, '何か 意見が あれば、 どうぞ 言ってください。', 'Nếu có ý kiến gì, xin hãy phát biểu', NULL, '2)', 5432, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14443, '3) この洗濯機は 音が 静かなら、 買いたいです。', 'Nếu tiếng động của cái máy giặt này êm thì tôi muốn mua', NULL, '3.2. Với 「なら」thì có thêm cách sử dụng nữa, với ý: giới hạn đề tài, câu chuyện được đề cập đến (chỉ trong phạm vi nội dung được nói đến thôi) 1) A: 「ワープロが', 5432, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14444, '1) 新聞が 読めるように、漢字を 勉 強します。', '', NULL, NULL, 5433, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14445, '2) みんなが わかるように、大きな 声で 言います。', '', NULL, NULL, 5433, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14446, '3) 風を ひかないように、セーターを 着ます。', '', NULL, NULL, 5433, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14447, '1) 日本語が 話せるように なりました。', 'Tôi đã có thể nói được tiếng Nhật', NULL, '2)', 5434, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14448, 'はじめは 日本料理が あまり 食べられませんでしたが、 今は 何でも 食べられるように なりました。', 'Lúc đầu tôi không thể ăn được đồ Nhật nhiều lắm nhưng bây giờ có thể ăn được mọi thứ', NULL, 'Chú ý: ☞ Động từ V', 5434, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14449, '今年の 夏は かなり 暑いですね。', '', NULL, NULL, 5436, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14450, '課長は 私を ほめました。', 'Giám đốc khen tôi', NULL, 'Bị động:', 5437, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14451, '課長は 私を しかりました。', 'Giám đốc mắng tôi', NULL, 'Bị động:', 5437, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14452, 'あの ビールは 30 年まえに たてられました。', 'Tòa nhà kia được xây dựng 30 năm trước đây', NULL, 'Chú ý: Khi sự vật không được đặc biệt nhấn mạnh như chủ đề của câu thì', 5439, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14453, '500 台 自動車が 生産されています。', '', NULL, NULL, 5440, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14454, ') 二人に 一人は 大学へ 行きます。', '', NULL, NULL, 5440, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14455, '(1 ) 私は 花が 好きです。', 'Tôi thích hoa', NULL, '(Đã học) (1’)', 5442, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14456, '私は 花を育てるのが すきです。', 'Tôi thích việc trồng hoa', NULL, '(2)', 5442, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14457, ') あの人は タイプを うつのが はやいです。', 'Người đó làm việc đánh máy thì nhanh', NULL, 'Các tính từ thường được sử dụng trong mẫu câu này gồm:', 5442, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14458, ') 電話をかけるのを 忘れました。', 'Tôi đã quên mất việc gọi điện thoại', NULL, '(2 )', 5443, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14459, 'あの人の 名前を 忘れました。', 'Tôi đã quên mất tên của người kia', NULL, '(2&#8242;)', 5443, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14460, 'が。 先週 木村さんは 結婚しました。', 'Tuần trước chị Kimura đã kết hôn', NULL, '先週', 5443, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14461, 'いいえ、しりませんでした。', 'Ví dụ (1) sử dụng しりません vì người nghe chưa biết thông tin, và không nhận được thông tin gì từ câu hỏi', NULL, 'Còn ở Ví dụ (2) sử dụng', 5443, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14462, '(1) 娘は 北海道の 小さい町で 生まれました。', 'Con gái tôi được sinh ra tại một thành phố nhỏ ở Hokkaido', NULL, '-&gt;', 5443, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14463, '娘が 生まれたのは 北海道の 小さい町です。', 'Nơi con gái tôi được sinh ra là một thành phố nhỏ ở Hokkaido', NULL, '(2) 12', 5443, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14464, '月は 1 年で 一番 忙しいです。', 'Tháng 12 là tháng bận nhất trong một năm', NULL, '-&gt;  1', 5443, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14465, '(1) リーさんは 日本語を 話すことが できます。', '', NULL, NULL, 5444, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14466, '） (2) 私のしゅみは 映画を 見ることです。', '', NULL, NULL, 5444, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14467, '私のしゅみは 映画を 見るのです。', '', NULL, NULL, 5444, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14468, '） (3) 日本料理を 食べたことが あります。', '', NULL, NULL, 5444, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14469, '日本料理を 食べたのが あります。', '', NULL, NULL, 5444, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14470, 'じこで 電車が とまりました。', 'Tai nạn khiến xe điện ngừng chạy', NULL, 'ゆきで', 5447, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14471, '新幹線が 遅れました。', 'Tuyết rơi khiến tàu Shinkansen bị trễ', NULL, '病気で', 5447, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14472, ') 山の高さは どうやって はかるか、知っていますか。', '', NULL, NULL, 5452, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14473, 'わたしは 社 長に とけいを いただきます。', 'Tôi nhận được cái đồng hồ từ giám đốc', NULL, 'わたしは', 5453, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14474, '先生に プレゼントを いただきました。', 'Tôi đã nhận được một món quà từ thầy/cô giáo', NULL, 'わたしは', 5453, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14475, '社 長は わたしに とけいを くださいます。', 'Giám đốc cho tôi cái đồng hồ', NULL, '先生は', 5454, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14476, 'わたしに ボールペンを くださいます。', 'Cô giáo cho tôi cái bút bi', NULL, '母は', 5454, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14477, 'わたしは 弟に さいふを やります。', 'Tôi cho em trai cái ví', NULL, 'わたしは', 5455, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14478, 'わたしは 花に 水を やります。', 'Tôi tưới nước cho hoa', NULL, 'Chú ý: Cùng là hành động cho, tặng nhưng trong trường hợp người nói muốn thể hiện sự thái độ tôn kính với người nhận là người có địa vị, tuổi tác cao hơn thì dùng「さしあげます」', 5455, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14479, 'わたしは 社長に ネクタイ を さしあげます。', 'Tôi biếu ông giám đốc chiếc cà vạt', NULL, 'Giống', 5455, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14480, '私は 鈴木さんに 日本語を 教えて いただきました。', 'Tôi được cô Suzuki dạy cho tiếng Nhật', NULL, '私は', 5455, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14481, '中村さんに 本社へ 連れて 行って いただきました。', 'Tôi được anh Nakamura dẫn đến trụ sở công ty 4.2', NULL, '~は(が) ~を V', 5455, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14482, '会社の人は( 私に)この機械の使い方を 教えてく ださいました。', 'Người trong công ty đã dạy (cho tôi) cách sử dụng của chiếc máy này', NULL, '4.3.  ~に ~を V', 5455, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14483, '私は 娘に おもちゃを 買ってやりました。', 'Tôi mua đồ chơi cho con gái', NULL, '私は', 5455, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14484, 'おとうとに 誕生日のパーティーを 準備して やりました。', 'Tôi đã chuẩn bị cho em trai bữa tiệc sinh nhật', NULL, 'わたしは', 5455, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14485, '犬を 散歩に 連れて 行って やります。', 'Tôi dắt chó đi dạo', NULL, 'Chú ý: – Cũng giống như 「V', 5455, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14486, 'とけいか ラジカセを 買ってやりたいです。', 'Tôi muốn mua đồng hồ hay đài casset cho nó', NULL, 'Trường hợp này「お子さん」(con của người khác) nên người hỏi cũng phải dùng cách nói lịch sự là 「~V', 5455, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14487, '毎日雨が降ったために、 橋が 壊れた。', 'Cây cầu bị hỏng do ngày nào trời cũng mưa 1.2', NULL, 'Mẫu câu N', 5456, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14488, 'るために」) 健康のために、たばこを やめた。', 'Tôi bỏ thuốc lá (để) cho khỏe', NULL, '発表の', 5456, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14489, '台風のために、木が 倒れた。', 'Cây đổ tại (vì) bão', NULL, '家族のために、一生懸命働かなければなりません。 Tôi phải cố làm việc hết sức vì gia đình.', 5456, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14490, '奥さんのために、 新しいバイクを買うつもりです。', 'Tôi định mua 1 chiếc xe máy mới vì/cho vợ', NULL, 'V', 5456, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14491, 'このはさみは 紙を 切るのに 使います。', 'Cái kéo này dùng để cắt giấy', NULL, '②この', 5456, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14492, 'ミキサーは 何に 使うんですか。', 'Cái máy trộn này dùng để làm gì thế?', NULL, '…原', 5456, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14493, '料を まぜるのに 使います。', 'Dùng để trộn nguyên liệu', NULL, 'b) （N', 5456, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14494, 'この辞書は 漢字を調べるのに 便利です。', 'Cuốn từ điển này rất tiện cho việc tra chữ Hán', NULL, 'この本は', 5456, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14495, '日本のことを知るのに 役に立ちます。', 'Quyển sách này có ích cho việc tìm hiểu NB', NULL, 'c) （N', 5456, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14496, 'この時計は 直すのに １週間 かかります。', 'Cái đồng hồ này phải mất 1 tuần để sửa', NULL, '1/ Chúng ta đã từng gặp trợ từ 「に」 thể hiện mục đích trong những bài trước như: ①', 5456, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14497, '今晩雨が 降るでしょう。', 'Có lẽ tối nay trời mưa', NULL, '(Người nói có thể nghe thông tin qua đài, báo..rồi nói)', 5458, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14498, '今晩雨が 降りそうです。', 'Có vẻ tối nay trời mưa', NULL, '(Người nói quan sát thấy trời âm u rồi nói)', 5458, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14499, 'ちょっと たばこを 買って来ます。', 'Tôi đi mua thuốc lá một chút (rồi về)', NULL, 'ちょっと', 5459, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14500, '教 室に 時計を 忘れたので、ちょっと 取って来ます。', 'Vì quên đồng hồ ở lớp học nên tôi sẽ đi lấy', NULL, 'Chú ý: Địa điểm đi đến và thực hiện hành động ở đó được thể hiện bằng trợ từ 「で」. Tuy nhiên, khi địa điểm đó là nơi lấy đi (hoặc di chuyển) một vật thì ta dùng trợ từ 「から」.', 5459, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14501, 'スーパーで 牛 乳を 買って来ます。', 'Tôi đi đến mua sữa ở siêu thị', NULL, '台', 5459, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14502, '所から コップを 取って来ます。', 'Tôi đi lấy cốc từ nhà bếp', NULL, 'Sự khác nhau giữa  「(場所)へVに行く」  「(場所)でVて来る」', 5459, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14503, ') 髪を 短くします。', 'Tôi sẽ cắt tóc', NULL, '(làm cho tóc ngắn)', 5461, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14504, '今 勉強しているところですから、あとで 行きます。', 'Vì bây giờ tôi đang học bài, nên tôi sẽ đi sau', NULL, 'A:', 5465, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14505, 'すみません。今 コピーしているところですから、もう少し 待ってください。', 'Xin lỗi', NULL, 'Vì bây giờ đang phôtô nên hãy chờ thêm chút nữa. 1.3. Mẫu câu V', 5465, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14506, 'はい、たった今 出たところです。', 'Vâng, vừa mới đi', NULL, '良子さんは', 5465, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14507, 'たった今 うちへ 帰ったところです。', 'Yoshiko vừa trở về nhà', NULL, 'A:', 5465, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14508, 'はい、たった今 着いたところだ。', 'Vâng, tôi vừa đến', NULL, '– Tất cả các mẫu câu ～ところです đều mang ý tả lại trạng thái tại 1 thời điểm 1 cách đơn thuần. Ví dụ:', 5465, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14509, '山田さんと山本さんは ３か月まえに 結婚したばかりです。', 'Cô Yamada và anh Yamamoto vừa kết hôn 3 tháng trước', NULL, '田中さんは ３週間まえに', 5466, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14510, 'ベトナムへ 来たばかりです。', 'Anh Tanaka vừa đến Việt Nam 3 tuần trước', NULL, 'このカメラは', 5466, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14511, '」 さっき 食べたばかりですから、まだ おなかが いっぱいです。', 'Bởi vì vừa ăn nên tôi vẫn còn no', NULL, 'ペンキを', 5466, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14512, '」 この時計は 買ったばかりなのに、 もう壊れてしまいました。', 'Cái đồng hồ này vừa mới mua vậy mà đã hỏng mất rồi', NULL, 'きのう', 5466, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14513, '雨が 降りそうです。', 'Có vẻ như trời sắp mưa', NULL, '②', 5467, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14514, '雨が 降るそうです。', 'Tôi nghe nói là trời sẽ mưa', NULL, 'Thể ý chí（しよう） , cấm đoán（するな） , mệnh lệnh（しろ） , suy đoán（するでしょう） , nhờ vả（してください、しないでください） . Ngoài ra, các mẫu câu khác đều có thể kết hợp được với mẫu câu này. （ × ）', 5467, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14515, '(1)部長は 加藤さんを 大阪へ 出 張させます。', 'Trưởng phòng sai anh Kato đi công tác Osaka', NULL, '(Trưởng phòng là chủ thể của câu nhưng người thực hiện hành động đi công tác Osaka là anh Kato) (2)', 5469, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14516, '私は 娘を 自由に 遊ばせました。', 'Tôi để cho con gái chơi tự do', NULL, '(Tôi là chủ thể của câu nhưng đối tượng thực hiện hành động chơi là con gái tôi) 2.2. Trường hợp #1: đối với “tha động từ” (他動詞) Câu trúc: ~に ~を V(さ)せる Cách dùng: biến đổi tha động từ sang thể 「使役(しえき)」 để tạo ra 1 động từ mới mang nghĩa sai khiến, mệnh lệnh yêu cầu ai đó làm gì. Trong kiểu câu này, người thực hiệnhành động, động tác sẽ đi với trợ từ 「に」, còn tân ngữ (đối tượng tác động của động từ) vẫn được xác định bởi trợ từ 「を」. – Kiểu câu này còn được gọi tên là kiểu câu 「に-使役文」(câu sai khiến với trợ từ', 5469, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14517, '(5)先生は 生徒に まどを 開けさせました。', 'Giáo viên sai (bảo) sinh viên mở cửa sổ', NULL, '(6)', 5469, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14518, '「を」 先生は 学生を 歩かせた。 先生は 学生に 山道を 歩かせた。', 'b', NULL, 'Trường hợp 2: Những động từ như「答える、しゃべる、言う、質問する、反対する、発言する」 là những tự động từ thực hiện hành vi có hướng đến 1 đối tượng nào đó nhưng có nhiều khi dùng trợ từ 「に」 thay cho trợ từ「を」', 5469, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14519, '・彼に 答えさせた。 ・山田くんに 言わせよう。', 'C', NULL, 'Mẫu câu', 5469, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14520, '８じから（１１じまで）べんきょうします.', '8-Ji kara (11ji made) benkyō shimasu', NULL, NULL, 5309, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14521, 'のみます -&gt; のんで: đọc', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14522, 'よびます -&gt; よんで: gọi', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14523, 'しにます -&gt; しんで: chết', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14524, '• Vい/り/ち ます－＞ Vって', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14525, 'Ví dụ: かいます -&gt; かって: mua', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14526, 'とります -&gt; とって: lấy', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14527, 'まちます -&gt; まって: đợi', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14528, '* いきます－＞いって: đi', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14529, '• Vします－＞ Vして (はなします -&gt; はなして : nói chuyện)', '(2) Nhóm 2', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14530, '• V (e) ます－＞ V (e)て', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14531, 'Ví dụ: 食べます -&gt;食べて: ăn', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14532, 'ねます -&gt; ねて: ngủ', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14533, '• V (i)ます－＞ V (i)て', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14534, 'Ví dụ: みます -&gt; みて: xem', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14535, 'おきます -&gt; おきて : thức dậy', '(3) Nhóm 3', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14536, 'します －＞ して ( べんきょうします -&gt; べんきょうして: học)', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14537, 'きます －＞ きて : đến', '', NULL, NULL, 5353, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (14538, '1.', '', NULL, NULL, 5470, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11733, 'わたしは たなかです。', '', NULL, 'Tôi là Tanaka.', 3672, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11734, 'わたしは 学生 がくせいです。', '', NULL, 'Tôi là sinh viên.', 3672, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11735, 'ラオさんは エンジニアでは（じゃ）ありません。', '', NULL, 'Anh Rao không phải là kỹ sư.', 3673, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11736, 'マイさんは ベトナム人ですか。', '', NULL, NULL, 3674, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11737, 'マイさんは ベトナムじ んですか。', '', NULL, 'Bạn Mai là người Việt Nam phải không?', 3674, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11738, '…はい、ベトナム人です。', '', NULL, NULL, 3674, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11739, '…はい、ベトナムじ んです。…', '', NULL, 'Đúng, (bạn ấy) là người Việt Nam.', 3674, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11740, 'ミラさんは 学生ですか。', '', NULL, NULL, 3674, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11741, 'ミラさんは がくせいですか。', '', NULL, 'Bạn Mira là học sinh phải không?', 3674, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11742, '…いいえ、学生ではありません。', '', NULL, NULL, 3674, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11743, '…いいえ、がくせいではありません。 …Không, (bạn ấy) không phải là học sinh.', '', NULL, NULL, 3674, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11744, '…(あの人は) 山田さんです。 …(あの人は) やまださんです。…(Người kia)', '', NULL, 'Là anh Yamada.', 3674, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11745, 'わたしは ベトナム人です。 わたしは ベトナムじ んです。', '', NULL, 'Tôi là người Việt Nam.', 3675, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11746, 'タンさんも ベトナム人です。 タンさんも ベトナムじ んです。', '', NULL, 'Anh Tân cũng là người Việt Nam.', 3675, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11747, 'わたしは', '', NULL, 'Ha Noi大学 だいがくの学生です。 Tôi là sinh viên của trường Đại học Ha Noi.', 3676, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11748, 'わたしは たなかです。', '', NULL, 'Tôi là Tanaka.', 3677, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11749, 'あのかたは きむらさんです。', '', NULL, 'Vị kia là Kimura.', 3677, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11750, 'わたしは 20さいです。', '', NULL, 'Tôi 20 tuổi.', 3678, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11751, 'お子さんは なんさいですか。', '', NULL, 'Con bạn mấy tuổi?', 3678, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11752, 'これは 本ですか。 これは ほ んですか。Đây là quyển sách à? …いいえ、それはノートです。 …', '', NULL, 'Không, đó là quyển vở.', 3679, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11753, 'あれは じどうしゃです。', '', NULL, 'Kia là cái ô tô.', 3679, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11754, '2) この', '', NULL, 'N／その N／あの N', 3679, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11755, 'あの人は 山田さんです。 あのひ とは やまださんです。', '', NULL, 'Người kia là anh Yamada.', 3679, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11756, 'この', '', NULL, 'N/その N/あの N?', 3679, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11757, '1) これは なんですか。', '', NULL, 'Đây là cái gì? …それは いすです。 … Đó là cái ghế.', 3679, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11758, '2) このひとは だれですか。', '', NULL, 'Người này là ai? …そのひとは 田中(たなか)さんです。 … Người đó là anh Tanaka.', 3679, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11759, '1) これは えんぴつですか。', '', NULL, 'Đây là cái bút chì phải không? …はい、えんぴつです。 …Vâng, đó là cái bút chì. Hoặc …はい、そうです。 …Vâng, đúng vậy. 2) それは テレホンカードですか。 Đó là cái th ẻ điện thoại phải không? …いいえ、テレホンカードではありません。 …Không, không phải cái thẻ điện thoại. Hoặc …いいえ、そうではありません。 …Không, không phải thế.', 3680, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11760, 'これは わたしの ほんです。', '', NULL, 'Đây là quyển sách của tôi.', 3682, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11761, '1) あれは だれのかばんですか。', '', NULL, 'Kia là cái cặp của ai? … わたしのです。 … Là của tôi.', 3682, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11762, '2) そのつくえは ラオさんのですか。', '', NULL, 'Cái bàn đó là của Rao phải không? … いいえ、ラオさんのではありません。 … Không, không phải của Rao.', 3682, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11763, '3) ミラーさんは', '', NULL, 'IMCのしゃいんですか。 Mira là nhân viên công ty IMC phải không? … はい、IMCのしゃいんです。 (Không dùng : IMCのです) … Vâng, (anh ấy) là nhân viên công ty IMC.', 3682, NULL, 0);
INSERT INTO public."Example" (id, jp, romaji, en, vi, "grammarId", "audioUrl", "sortOrder") VALUES (11764, 'A: このかさは あなたのですか。', '', NULL, 'Cái ô này là của bạn à? B: いいえ、タンさんのです。 …Không, của anh Tân. A: そうですか。 À, ra vậy.', 3683, NULL, 0);
