INSERT INTO public."JlptRoadmapLevel" (id, "externalKey", label, badge, color, duration, "vocabTarget", "kanjiTarget", "passScore", summary, "sortOrder", "createdAt", "updatedAt") VALUES (1, 'n5', 'JLPT N5', 'Sơ cấp', '#22c55e', '4–6 tháng', '~800 từ', '~100 chữ', '80/180 điểm', 'N5 là cấp độ đầu tiên — đủ để giao tiếp cơ bản, giới thiệu bản thân, mua sắm, hỏi đường đơn giản.', 0, '2026-06-25 10:52:31.299', '2026-06-25 10:52:31.299');
INSERT INTO public."JlptRoadmapLevel" (id, "externalKey", label, badge, color, duration, "vocabTarget", "kanjiTarget", "passScore", summary, "sortOrder", "createdAt", "updatedAt") VALUES (2, 'n4', 'JLPT N4', 'Sơ cấp cao', '#3b82f6', '4–6 tháng (sau N5)', '~1.500 từ', '~300 chữ', '90/180 điểm', 'N4 mở rộng giao tiếp hàng ngày — nói về kinh nghiệm, lịch trình, ý kiến đơn giản, đọc tin ngắn.', 1, '2026-06-25 10:52:31.379', '2026-06-25 10:52:31.379');
INSERT INTO public."JlptRoadmapLevel" (id, "externalKey", label, badge, color, duration, "vocabTarget", "kanjiTarget", "passScore", summary, "sortOrder", "createdAt", "updatedAt") VALUES (3, 'n3', 'JLPT N3', 'Trung cấp', '#a855f7', '6–9 tháng (sau N4)', '~3.750 từ', '~650 chữ', '95/180 điểm', 'N3 là cầu nối trung cấp — hiểu tin tức, hội thoại công việc, văn viết không quá trang trọng.', 2, '2026-06-25 10:52:31.426', '2026-06-25 10:52:31.426');
