INSERT INTO public."JlptRoadmapMaterial" (id, "levelId", title, description, scope, "inAppPath", "inAppLabel", "externalUrl", "externalLabel", "sortOrder") VALUES (1, 1, 'Minna no Nihongo I', 'Giáo trình chính — từ vựng, ngữ pháp, bài tập.', 'Bài 1 → 25', '/vocab', 'Học từ vựng', NULL, NULL, 0);
INSERT INTO public."JlptRoadmapMaterial" (id, "levelId", title, description, scope, "inAppPath", "inAppLabel", "externalUrl", "externalLabel", "sortOrder") VALUES (2, 1, 'Shin Nihongo no Kiso (新日本語の基礎)', 'Sách bài tập đi kèm Minna — luyện đọc, viết, nghe cơ bản song song giáo trình.', 'Bài 1 → 25 (song song Minna I)', '/grammar', 'Ngữ pháp Minna', NULL, NULL, 1);
INSERT INTO public."JlptRoadmapMaterial" (id, "levelId", title, description, scope, "inAppPath", "inAppLabel", "externalUrl", "externalLabel", "sortOrder") VALUES (3, 1, 'Kanji Look and Learn', '512 kanji N5–N3 — giai đoạn N5 học 160 chữ đầu.', 'Bài 1 → 10 (N5)', '/kanji', 'Học kanji', NULL, NULL, 2);
INSERT INTO public."JlptRoadmapMaterial" (id, "levelId", title, description, scope, "inAppPath", "inAppLabel", "externalUrl", "externalLabel", "sortOrder") VALUES (4, 1, 'Shin Kanzen Master N5 (新完全マスター)', 'Bộ luyện thi chuyên sâu N5 — ngữ pháp, từ vựng, nghe, đọc; phù hợp giai đoạn ôn đề.', 'Toàn bộ 4 kỹ năng · trước kỳ thi 2–3 tháng', NULL, NULL, 'https://jlpt.jp/e/samples/forlearners.html', 'Đề mẫu JLPT (tham khảo format)', 3);
INSERT INTO public."JlptRoadmapMaterial" (id, "levelId", title, description, scope, "inAppPath", "inAppLabel", "externalUrl", "externalLabel", "sortOrder") VALUES (5, 1, 'Nihongo Sō-Matome N5 · Ngữ pháp (文法)', 'Ôn ngữ pháp N5 theo từng ngày — gọn, dễ lập kế hoạch 6–8 tuần.', '1 chương/ngày · ~42 chủ điểm', NULL, NULL, NULL, NULL, 4);
INSERT INTO public."JlptRoadmapMaterial" (id, "levelId", title, description, scope, "inAppPath", "inAppLabel", "externalUrl", "externalLabel", "sortOrder") VALUES (6, 1, 'Nihongo Sō-Matome N5 · Từ vựng (語彙)', 'Từ vựng N5 theo chủ đề — kèm collocations hay gặp trong đề JLPT.', 'Ôn kèm flashcard & bảng từ sai trong app', '/vocab-review', 'Bảng từ sai', NULL, NULL, 5);
INSERT INTO public."JlptRoadmapMaterial" (id, "levelId", title, description, scope, "inAppPath", "inAppLabel", "externalUrl", "externalLabel", "sortOrder") VALUES (7, 1, 'Nihongo Sō-Matome N5 · Kanji (漢字)', 'Kanji N5 theo ngày — bổ sung cho Kanji Look and Learn trước kỳ thi.', 'Song song KLL bài 1–10', '/kanji', 'Kanji KLL', NULL, NULL, 6);
INSERT INTO public."JlptRoadmapMaterial" (id, "levelId", title, description, scope, "inAppPath", "inAppLabel", "externalUrl", "externalLabel", "sortOrder") VALUES (8, 1, 'Đề thử Choukai N5 (聴解 · Nghe hiểu)', 'Bộ đề luyện nghe N5 — làm có giới hạn thời gian, nghe 1 lần như thi thật.', '3–5 đề/tuần · 4 tuần cuối', '/daily-listening', 'Nghe mỗi ngày', 'https://jlpt.jp/e/samples/forlearners.html', 'Audio đề mẫu JLPT', 7);
INSERT INTO public."JlptRoadmapMaterial" (id, "levelId", title, description, scope, "inAppPath", "inAppLabel", "externalUrl", "externalLabel", "sortOrder") VALUES (9, 1, 'Đề thử Dokkai N5 (読解 · Đọc hiểu)', 'Bộ đề đọc hiểu N5 — đoạn ngắn, trả lời câu hỏi chi tiết & tìm thông tin.', '2–3 đề/tuần · 4 tuần cuối', '/mock-exam', 'Thi thử trong app', 'https://jlpt.jp/e/samples/forlearners.html', 'Đề mẫu đọc JLPT', 8);
