INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (704, '真', 'CHÂN', 'しん, ま, まこと', NULL, 'chân lí, chân thực', 'テレビは本当（ほんとう）のイメージを映（うつ）し出（だ）します。', 'Tivi phản chiếu hình ảnh thật', NULL, 16, 45, '2026-06-25 09:22:04.237', '2026-06-25 09:22:04.237', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (570, '父', 'PHỤ', 'ふ, ちち', NULL, 'phụ tử, phụ thân, phụ huynh', '父（ちち）にはひげがあります', 'Cha tôi có râu.', '/media/kanji/kanji512/bai4/father.jpg', 10, 37, '2026-06-25 09:22:01.262', '2026-06-25 09:22:01.262', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (652, '手', 'THỦ', 'しゅ', 'て, て-, -て, た-', 'tay, thủ đoạn', '手（て）の形（かたち）です', 'Hình dạng của bàn tay.', '/media/kanji/kanji512/bai9/hand.jpg', 12, 42, '2026-06-25 09:22:02.829', '2026-06-25 09:22:02.829', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (959, '々', NULL, NULL, NULL, '', 'これは繰（く）り返（かえ）しを表（あらわ）します', 'Ký hiệu này biểu thị sự lặp lại.', '/media/kanji/kanji512/bai28/symbol_of_repetition.jpg', 15, 61, '2026-06-25 09:22:10.311', '2026-06-25 09:22:10.311', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (513, '一', 'NHẤT', 'いち, いつ', 'ひと-つ', 'một, đồng nhất, nhất định', '一本（いっぽん）の指（ゆび）で示（しめ）したのが「一」です', 'Một ngón tay trỏ biểu thị cho số 1. (Nhất)', '/media/kanji/kanji512/bai1/one.jpg', 1, 34, '2026-06-25 09:21:59.781', '2026-06-25 09:21:59.781', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (514, '二', 'NHỊ', 'に', 'ふた-つ', '2', '二本（にほん）の指（ゆび）で示（しめ）したのが「二」です', 'Hai ngón tay biểu thị cho số 2. (Nhị)', '/media/kanji/kanji512/bai1/two.jpg', 2, 34, '2026-06-25 09:21:59.818', '2026-06-25 09:21:59.818', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (515, '三', 'TAM', 'さん', 'み、みっ-つ', '3', '三本（さんぼん）の指（ゆび）で示（しめ）したのが「三」です', 'Ba ngón tay biểu thị cho số 3. (Tam)', '/media/kanji/kanji512/bai1/three.jpg', 3, 34, '2026-06-25 09:21:59.839', '2026-06-25 09:21:59.839', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (516, '四', 'TỨ', 'し', 'よん、よ-つ', '4', '四角（しかく）には四（よっ）つの角（かど）があります', 'Hình tứ giác có 4 góc biểu thị cho số 4.', '/media/kanji/kanji512/bai1/four.jpg', 4, 34, '2026-06-25 09:21:59.864', '2026-06-25 09:21:59.864', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (517, '五', 'NGŨ', 'ご', 'いつ-つ', '5', '五本（ごほん）のマッチで［五（ご）」の形（かたち）が作（つく）れますか', 'Bạn có thể tạo thành hình chữ 「五」với 5 que diêm không?', '/media/kanji/kanji512/bai1/five.jpg', 5, 34, '2026-06-25 09:21:59.899', '2026-06-25 09:21:59.899', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (518, '六', 'LỤC', 'ろく', 'む-つ', '6', '中国（ちゅうごく）の人（ひと）は、６をこうやって表（あらわ）します', 'Người Trung Quốc biểu thị số 6 bằng cách như vầy.', '/media/kanji/kanji512/bai1/six.jpg', 6, 34, '2026-06-25 09:21:59.932', '2026-06-25 09:21:59.932', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (519, '七', 'THẤT', 'しち', 'し,なな, なな-つ, なの, しっ, な, ひち', '7', '2たす５は７です', '2 cộng 5 bằng 7.', '/media/kanji/kanji512/bai1/seven.jpg', 7, 34, '2026-06-25 09:21:59.964', '2026-06-25 09:21:59.964', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (520, '八', 'BÁT', 'はち', 'や、や-つ', '8', 'カタカナの「ハチ」は［八（はち）］です', 'Nó là chữ「ハ」 trong từ katakana「ハチ」(số 8).', '/media/kanji/kanji512/bai1/eight.jpg', 8, 34, '2026-06-25 09:22:00.002', '2026-06-25 09:22:00.002', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (521, '九', 'CỬU', 'きゅう, く', 'ここの-つ', '9', '10回（かい）腕（うで）立（た）て伏（ふ）せができますか。「７，８，９…だめだ」', '”Bạn có thể hít đất 10 lần không?”', '/media/kanji/kanji512/bai1/nine.jpg', 9, 34, '2026-06-25 09:22:00.043', '2026-06-25 09:22:00.043', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (522, '十', 'THẬP', 'じゅう, じ, とお', NULL, 'mười', '常（じょう）本（ほん）を束（たば）ねましょう', 'Chúng ta hãy bó 10 que lại.', '/media/kanji/kanji512/bai1/ten.jpg', 10, 34, '2026-06-25 09:22:00.089', '2026-06-25 09:22:00.089', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (523, '百', 'BÁCH', 'ひゃく, もも', NULL, 'trăm, bách niên', '100を90度（ど）右（みぎ）へ回転（かいてん）すると、［百（ひゃく）］のようになります', 'Xoay số ”100 ” 90 độ về bên phải thì nó sẽ trở thành chữ 「百」', '/media/kanji/kanji512/bai1/hundred.jpg', 11, 34, '2026-06-25 09:22:00.132', '2026-06-25 09:22:00.132', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (524, '千', 'THIÊN', 'せん, ち', NULL, 'nghìn, nhiều, thiên lí', '十（じゅう）に［ノ］を足（た）して、もっと多（おお）い、［千（せん）］になりました', 'Cộng nét 「ノ」vào số 10「十」 ta sẽ có một số lớn hơn rất nhiều, số 1000', '/media/kanji/kanji512/bai1/thousand.jpg', 12, 34, '2026-06-25 09:22:00.172', '2026-06-25 09:22:00.172', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (525, '万', 'VẠN', 'まん, ばん, →萬［萬', NULL, 'vạn, nhiều, vạn vật', '一万（いちまん）は5桁（けた）の数字（すうじ）です', 'Số 10.000 là số có 5 chữ số.', '/media/kanji/kanji512/bai1/ten_thousand.jpg', 13, 34, '2026-06-25 09:22:00.21', '2026-06-25 09:22:00.21', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (526, '円', 'VIÊN', 'えん', 'つぶら,まる-い, まる, まど, まど-か, まろ-やか, のぶ, まどか, みつ', 'viên mãn, tiền Yên', '円（えん）の形（かたち）です', 'Hình dạng của hình tròn', '/media/kanji/kanji512/bai1/yen_circle.jpg', 14, 34, '2026-06-25 09:22:00.239', '2026-06-25 09:22:00.239', NULL, NULL, NULL, NULL, NULL);
