INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (554, '午', 'NGỌ', 'ご, うま', NULL, 'chính ngọ', 'この漢字（かんじ）には、［十（じゅう）」と［二（に）」が入（はい）っています。十二時（じゅうにじ）は正午（しょうご）です', 'Chữ hán này gồm có số 10「十」 và số 2「二」. 12 giờ là buổi trưa.', '/media/kanji/kanji512/bai3/noon.jpg', 10, 36, '2026-06-25 09:22:00.924', '2026-06-25 09:22:00.924', NULL, NULL, NULL, NULL, NULL);
