INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (591, '周', 'CHU', 'しゅう', 'まわ-り', 'chu vi, chu biên', '食（た）べたものは土（つち）に返（かえ）ります。すべてのものは循環（じゅんかん）します', 'Những thứ mình đã ăn sẽ trở về với đất. Mọi vật đều tuần hoàn.', '/media/kanji/kanji512/bai5/go_around.jpg', 15, 38, '2026-06-25 09:22:01.64', '2026-06-25 09:22:01.64', NULL, NULL, NULL, NULL, NULL);
