INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (593, '大', 'ĐẠI', 'だい, たい', 'おお-きい', 'to lớn, đại dương, đại lục', '手足（てあし）を広（ひろ）げると、大（おお）きく見（み）えます', 'Khi bạn dang rộng chân tay trông bạn rất lớn.', '/media/kanji/kanji512/bai6/big.jpg', 1, 39, '2026-06-25 09:22:01.676', '2026-06-25 09:22:01.676', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (594, '小', 'TIỂU', 'しょう', 'ちい-さい', 'nhỏ, ít', '手足（てあし）を曲（ま）げれば、小（ちい）さく見（み）えます', 'Khi bạn co chân tay lại trông bạn nhỏ hơn.', '/media/kanji/kanji512/bai6/small.jpg', 2, 39, '2026-06-25 09:22:01.691', '2026-06-25 09:22:01.691', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (595, '高', 'CAO', 'こう', 'たか、たか-い', 'cao đẳng, cao thượng', '建物（たてもの）の上（うえ）に高（たか）い塔（とう）が立（た）っています', 'Có một cái tháp cao ở trên toà nhà.', '/media/kanji/kanji512/bai6/high.jpg', 3, 39, '2026-06-25 09:22:01.711', '2026-06-25 09:22:01.711', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (596, '安', 'AN', 'あん', 'やす-い', 'an bình, an ổn', 'おんなの人（ひと）は家（いえ）の中（なか）で安心（あんしん）しています', 'Phụ nữ cảm thấy an tâm hơn khi ở trong nhà.', '/media/kanji/kanji512/bai6/cheap_ease.jpg', 4, 39, '2026-06-25 09:22:01.733', '2026-06-25 09:22:01.733', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (597, '新', 'TÂN', 'しん', 'あたら-しい、あら-た、にい', 'mới, cách tân, tân thời', '新（あたら）しいことを始（はじ）めるには、立（た）って、おので道（みち）を開（ひら）きます', 'Để bắt đầu điều mới, ta đứng lên, đốn cây mở đường bằng rìu.', '/media/kanji/kanji512/bai6/new.jpg', 5, 39, '2026-06-25 09:22:01.752', '2026-06-25 09:22:01.752', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (623, '病', 'BỆNH', 'びょう, へい, やまい', NULL, 'bệnh nhân, bệnh viện, bệnh tật', '病院（びょういん）で病気（びょうき）の人（ひと）が寝（ね）ています', 'Người bệnh đang ngủ ở bệnh viện.', '/media/kanji/kanji512/bai7/sick.jpg', 15, 40, '2026-06-25 09:22:02.327', '2026-06-25 09:22:02.327', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (598, '古', 'CỔ', 'こ', 'ふる-い', 'cũ, cổ điển, đồ cổ', '同（おな）じ話（はなし）を十回（じゅうかい）聞（き）くと、その話（はなし）は古（ふる）くなります', 'Khi ta nghe cùng một câu chuyện 10 （十）lần thì câu chuyện đó sẽ trở nên cũ đi.', '/media/kanji/kanji512/bai6/old.jpg', 6, 39, '2026-06-25 09:22:01.768', '2026-06-25 09:22:01.768', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (599, '元', 'NGUYÊN', 'げん, がん, もと', NULL, 'gốc', '二人（ふたり）で走（はし）れば、もっと元気（げんき）になります', 'Nếu 2 người chạy cùng nhau thì họ sẽ trở nên khoẻ mạnh hơn.', '/media/kanji/kanji512/bai6/origin.jpg', 7, 39, '2026-06-25 09:22:01.793', '2026-06-25 09:22:01.793', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (600, '気', 'KHÍ', 'き, け', NULL, 'không khí, khí chất, khí khái, khí phách', '息（いき）を強（つよ）く吐（は）きすぎると、「気（き）」が出（で）てくるかもしれません', 'Nếu bạn thở ra quá mạnh thì không chừng tinh thần bạn sẽ xuất hiện.', '/media/kanji/kanji512/bai6/spirit.jpg', 8, 39, '2026-06-25 09:22:01.823', '2026-06-25 09:22:01.823', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (601, '多', 'ĐA', 'た', 'おお-い', 'đa số', '「タ」がたくさんあります', 'Có nhiều chữ「タ」', '/media/kanji/kanji512/bai6/many_much.jpg', 9, 39, '2026-06-25 09:22:01.846', '2026-06-25 09:22:01.846', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (602, '少', 'THIẾU, THIỂU', 'しょう', 'すく-ない、すこ-し', 'thiếu niên; thiểu số', '小（ちい）さいものを分（わ）けると、少（すこ）ししかもらえます', 'Khi bạn phân chia một vật nhỏ, bạn chỉ có thể nhận được một ít.', '/media/kanji/kanji512/bai6/little.jpg', 10, 39, '2026-06-25 09:22:01.874', '2026-06-25 09:22:01.874', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (603, '広', 'QUẢNG', 'こう', 'ひろ-い］ →廣［廣', 'quảng trường, quảng đại', '私（わたし）の家（うち）です。広（ひろ）いでしょう', '”Đây là nhà của tôi. Nó rộng phải không?”', '/media/kanji/kanji512/bai6/spacious.jpg', 11, 39, '2026-06-25 09:22:01.896', '2026-06-25 09:22:01.896', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (604, '早', 'TẢO', 'そう, さ', 'はや-い', 'sớm, tảo hôn', '日曜日（にちようび）に十時（じゅうじ）に起（お）きるのは早（はや）すぎます', 'Việc dậy lúc 10 giờ vào ngày chủ nhật là quá sớm.', '/media/kanji/kanji512/bai6/early.jpg', 12, 39, '2026-06-25 09:22:01.917', '2026-06-25 09:22:01.917', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (605, '長', 'TRƯỜNG, TRƯỞNG', 'ちょう', 'なが-い', 'trường giang, sở trường; hiệu trưởng', '髪（かみ）が長（なが）い人（ひと）の姿（すがた）です', 'Hình dáng của một người có mái tóc dài.', '/media/kanji/kanji512/bai6/long.jpg', 13, 39, '2026-06-25 09:22:01.936', '2026-06-25 09:22:01.936', NULL, NULL, NULL, NULL, NULL);
