INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (624, '院', 'VIỆN', 'いん', NULL, 'học viện, y viện', '元気（げんき）になって病院（びょういん）を出（で）て家（いえ）に帰（かえ）りました', 'Đã khoẻ （元気）lại và ra viện về nhà.', '/media/kanji/kanji512/bai7/institution.jpg', 16, 40, '2026-06-25 09:22:02.349', '2026-06-25 09:22:02.349', NULL, NULL, NULL, NULL, NULL);
