INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (628, '貝', 'BỐI', 'かい', '-', 'vỏ sò', '貝（かい）の形（かたち）です', 'Hình dạng của của con sò.', '/media/kanji/kanji512/bai8/shellfish.jpg', 4, 41, '2026-06-25 09:22:02.404', '2026-06-25 09:22:02.404', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (629, '買', 'MÃI', 'ばい', 'か-う', 'mua, khuyến mãi', '昔（むかし）、貝（かい）を使（つか）ってものを買（か）いましたが、今（いま）は紙幣（しへい）を使（つか）っています', 'Ngày xưa người ta sử dụng vỏ sò để mua hàng hoá còn bây giờ ta đang sử dụng tiền giấy.', '/media/kanji/kanji512/bai8/buy.jpg', 5, 41, '2026-06-25 09:22:02.419', '2026-06-25 09:22:02.419', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (630, '売', 'MẠI', 'ばい', 'う-る', 'thương mại', '人（ひと）が何（なに）か売（う）っています', 'Một người đang bán cái gì đó.', '/media/kanji/kanji512/bai8/sell.jpg', 6, 41, '2026-06-25 09:22:02.432', '2026-06-25 09:22:02.432', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (631, '読', 'ĐỘC', 'どく, とく, とう', 'よ-む', 'độc giả, độc thư', '「このベストセラーの本（ほん）を読（よ）んでください」と彼（かれ）は言（い）いました', 'Anh ấy đã nói rằng ”Hãy đọc quyển sách bán chạy nhất này.”', '/media/kanji/kanji512/bai8/read.jpg', 7, 41, '2026-06-25 09:22:02.447', '2026-06-25 09:22:02.447', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (632, '書', 'THƯ', 'しょ', 'かき,か-く, -が-き, -がき', 'thư đạo, thư tịch, thư kí', '筆（ふで）をもって、「日（ひ）」をかきます', 'Cầm bút lông viết chữ Nhật 「日」.', '/media/kanji/kanji512/bai8/write.jpg', 8, 41, '2026-06-25 09:22:02.467', '2026-06-25 09:22:02.467', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (633, '帰', 'QUY', 'き', 'かえ-る', 'hồi quy', 'つばめが巣（す）に帰（かえ）ります', 'Chim én quay về tổ.', '/media/kanji/kanji512/bai8/return.jpg', 9, 41, '2026-06-25 09:22:02.486', '2026-06-25 09:22:02.486', NULL, NULL, NULL, NULL, NULL);
