INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (642, '夏', 'HẠ', 'か, げ, なつ', NULL, 'mùa hè', '夏（なつ）は暑（あつ）いので、人（ひと）が日陰（ひかげ）でぐったりしています', 'Vì mùa hè quá nóng, nên con người mệt lử dưới bóng râm.', '/media/kanji/kanji512/bai9/summer.jpg', 2, 42, '2026-06-25 09:22:02.636', '2026-06-25 09:22:02.636', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (643, '秋', 'THU', 'しゅう, あき, とき', NULL, 'mùa thu', '秋（あき）になると、稲（いね）が実（みの）り、葉（は）は日（ひ）の色（いろ）になります', 'Thu đến, lúa đơm bông, lá cây chuyển sang màu của lửa.', '/media/kanji/kanji512/bai9/autumn.jpg', 3, 42, '2026-06-25 09:22:02.654', '2026-06-25 09:22:02.654', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (644, '冬', 'ĐÔNG', 'とう, ふゆ', NULL, 'mùa đông', '冬（ふゆ）は氷（こおり）の上（うえ）を歩（ある）くと滑（すべ）ります', 'Sẽ rất trơn trượt khi đi trên băng vào mùa đông.', '/media/kanji/kanji512/bai9/winter.jpg', 4, 42, '2026-06-25 09:22:02.674', '2026-06-25 09:22:02.674', NULL, NULL, NULL, NULL, NULL);
