INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (646, '昼', 'TRÚ', 'ちゅう, ひる', NULL, 'buổi trưa', '昼（ひる）、日（ひ）が高（たか）くなると、日（ひ）よけをつるします', 'Khi mặt trời lên cao vào buổi trưa chúng ta sẽ treo những tấm bạt che nắng lên.', '/media/kanji/kanji512/bai9/daytime.jpg', 6, 42, '2026-06-25 09:22:02.714', '2026-06-25 09:22:02.714', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (647, '夕', 'TỊCH', 'せき, ゆう, ゆうべ', NULL, 'tịch dương', '夕方（ゆうがた）、月（つき）と鳥（とり）が見（み）えます', 'Vào xế chiều bạn sẽ thấy mặt trăng và chim chóc.', '/media/kanji/kanji512/bai9/early_evening.jpg', 7, 42, '2026-06-25 09:22:02.728', '2026-06-25 09:22:02.728', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (648, '方', 'PHƯƠNG', 'ほう, かた', NULL, 'phương hướng, phương pháp', '旗（はた）のある方（ほう）へ行（い）ってください', 'Vui lòng đi theo hướng của lá cờ.', '/media/kanji/kanji512/bai9/direction_person.jpg', 8, 42, '2026-06-25 09:22:02.752', '2026-06-25 09:22:02.752', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (649, '晩', 'VÃN', 'ばん', NULL, 'buổi tối', '晩（ばん）にならないうちに、急（いそ）いで家（いえ）に帰（かえ）ります', 'Hối hả về nhà trong lúc trời chưa tối.', '/media/kanji/kanji512/bai9/evening.jpg', 9, 42, '2026-06-25 09:22:02.774', '2026-06-25 09:22:02.774', NULL, NULL, NULL, NULL, NULL);
