INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (718, '糸', 'MỊCH', 'し, いと', NULL, 'sợ chỉ', '糸巻（いとま）きの形（かたち）です', 'Hình dạng của cuộn chỉ.', '/media/kanji/kanji512/bai13/thread.jpg', 14, 46, '2026-06-25 09:22:04.559', '2026-06-25 09:22:04.559', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (719, '氏', 'THỊ', 'し, うじ', NULL, 'họ', '名札（なふだ）に名前（なまえ）が書（か）いてあります', 'Có ghi tên trên bảng tên.', '/media/kanji/kanji512/bai13/surname.jpg', 15, 46, '2026-06-25 09:22:04.571', '2026-06-25 09:22:04.571', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (720, '紙', 'CHỈ', 'し, かみ', NULL, 'giấy', '髪（かみ）に名前（なまえ）を書（か）いて、糸（いと）で縫（ぬ）い付（つ）けましょう', 'Viết họ tên lên giấy và luồn sợi chỉ qua.', '/media/kanji/kanji512/bai13/paper.jpg', 16, 46, '2026-06-25 09:22:04.596', '2026-06-25 09:22:04.596', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (721, '教', 'GIÁO', 'きょう', 'おし-える', 'giáo dục, giáo viên', '老人（ろうじん）が子（こ）どもを教（おし）えます', 'Ông lão dạy đứa trẻ.', '/media/kanji/kanji512/bai14/teach.jpg', 1, 47, '2026-06-25 09:22:04.626', '2026-06-25 09:22:04.626', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (722, '室', 'THẤT', 'しつ, むろ', NULL, 'phòng, giáo thất', '土曜日（どようび）はいつも室内（しつない）にいます', 'Thứ bảy nào tôi cũng ở trong phòng của tôi.', '/media/kanji/kanji512/bai14/room.jpg', 2, 47, '2026-06-25 09:22:04.653', '2026-06-25 09:22:04.653', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (723, '羽', 'VŨ', 'う, はね', NULL, 'lông vũ', '羽（はね）の形（かたち）です', 'Hình dạng của đôi cánh.', '/media/kanji/kanji512/bai14/wing.jpg', 3, 47, '2026-06-25 09:22:04.685', '2026-06-25 09:22:04.685', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (724, '習', 'TẬP', 'しゅう', 'なら-う', 'học tập', '鳥（とり）は白（しろ）い建物（たてもの）の上（うえ）で羽（はね）を動（うご）かして、飛（と）び方（かた）を習（なら）います', 'Trên toà nhà màu trắng, những con chim vỗ cánh tập bay.', '/media/kanji/kanji512/bai14/learn.jpg', 4, 47, '2026-06-25 09:22:04.706', '2026-06-25 09:22:04.706', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (725, '漢', 'HÁN', 'かん', NULL, 'hảo hán', '中国（ちゅうごく）人（じん）の夫（おっと）が草（くさ）を頭（あたま）の上（うえ）に載（の）せて川（かわ）を渡（わた）っています', 'Ông chồng người Trung Quốc chất cỏ lên đầu rồi băng qua sông.', '/media/kanji/kanji512/bai14/chinese.jpg', 5, 47, '2026-06-25 09:22:04.736', '2026-06-25 09:22:04.736', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (726, '字', 'TỰ', 'じ, あざ', NULL, 'chữ, văn tự', '子（こ）どもは家（いえ）の中（なか）で字（じ）を習（なら）います', 'Đứa trẻ học chữ ở trường.', '/media/kanji/kanji512/bai14/letter_character.jpg', 6, 47, '2026-06-25 09:22:04.756', '2026-06-25 09:22:04.756', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (727, '式', 'THỨC', 'しき', NULL, 'hình thức, phương thức, công thức', '私（わたし）の結婚式（けっこんしき）です', 'Đây là lễ cưới của tôi.', '/media/kanji/kanji512/bai14/ceremony_style.jpg', 7, 47, '2026-06-25 09:22:04.793', '2026-06-25 09:22:04.793', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (728, '試', 'THÍ', 'し', 'こころ-みる', 'thí nghiệm, thí điểm', '式（しき）で：「この人（ひと）を一生（いっしょう）愛（あい）しますか」 「やってみます」', 'Tại buổi lễ: ”Con sẽ yêu người này đến hết cuộc đời không?”', '/media/kanji/kanji512/bai14/try.jpg', 8, 47, '2026-06-25 09:22:04.815', '2026-06-25 09:22:04.815', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (729, '験', 'NGHIỆM', 'けん, げん', 'ため-す、しるし、げん', 'thí nghiệm, hiệu nghiệm, kinh nghiệm', '山（やま）に登（のぼ）る前（まえ）に、馬（うま）を調（しら）べます', 'Ta sẽ kiểm tra con ngựa trước khi leo núi.', '/media/kanji/kanji512/bai14/examine.jpg', 9, 47, '2026-06-25 09:22:04.828', '2026-06-25 09:22:04.828', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (730, '宿', 'TÚC', 'しゅく', 'やど-る、やど', 'tá túc, kí túc xá', 'この宿（やど）は百人（ひゃくにん）泊（と）まれます', 'Nhà trọ này có thể cho 100 khách trọ lại.', '/media/kanji/kanji512/bai14/inn.jpg', 10, 47, '2026-06-25 09:22:04.851', '2026-06-25 09:22:04.851', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (731, '題', 'ĐỀ', 'だい', NULL, 'đề tài, đề mục, chủ đề', '記者（きしゃ）は頭（あたま）と足（あし）を使（つか）って題材（だいざい）を探（さが）します', 'Nhà báo sử dụng đầu và chân để tìm kiếm đề tài.', '/media/kanji/kanji512/bai14/topic.jpg', 11, 47, '2026-06-25 09:22:04.866', '2026-06-25 09:22:04.866', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (732, '文', 'VĂN', 'ぶん, もん, ふみ, あや', NULL, 'văn chương, văn học', '古（ふる）い土器（どき）の模様（もよう）が文字（もじ）になりました', 'Hoa văn của chiếc bình cổ đã trở thành văn tự.', '/media/kanji/kanji512/bai14/letter_character1.jpg', 12, 47, '2026-06-25 09:22:04.897', '2026-06-25 09:22:04.897', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (733, '英', 'ANH', 'えい, はなぶさ', NULL, 'anh hùng, anh tú, anh tuấn', '真（ま）ん中（なか）の人（ひと）が英雄（えいゆう）です。草（くさ）の根（ね）運動（うんどう）から生（う）まれました', 'Người ở chính giữa là anh hùng. Đã được sinh ra từ sự chuyển động của cội rễ cỏ cây.', '/media/kanji/kanji512/bai14/english_excellent.jpg', 13, 47, '2026-06-25 09:22:04.924', '2026-06-25 09:22:04.924', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (734, '質', 'CHẤT', 'しつ, しち, ち, たち', NULL, 'vật chất, phẩm chất, khí chất', '大（おお）きい貝（かい）を2本（ほん）のおので割（わ）り、その質（しつ）を調（しら）べます', 'Làm vỡ vỏ sò lớn bằng rìu và kiểm tra chất lượng của nó.', '/media/kanji/kanji512/bai14/quality.jpg', 14, 47, '2026-06-25 09:22:04.944', '2026-06-25 09:22:04.944', NULL, NULL, NULL, NULL, NULL);
