INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (736, '説', 'THUYẾT', 'せつ, ぜい', 'と-く', 'tiểu thuyết, học thuyết, lí thuyết', 'お兄（にい）さんが説明（せつめい）しています', 'Anh trai đang giải thích.', '/media/kanji/kanji512/bai14/explain.jpg', 16, 47, '2026-06-25 09:22:04.982', '2026-06-25 09:22:04.982', NULL, NULL, NULL, NULL, NULL);
