INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (739, '者', 'GIẢ', 'しゃ, もの', NULL, 'học giả, tác giả', '誰（だれ）でも、日（ひ）ごとに老（お）いていきます', 'Ngày qua ngày, ai rồi cũng sẽ già đi.', '/media/kanji/kanji512/bai15/person.jpg', 3, 48, '2026-06-25 09:22:05.04', '2026-06-25 09:22:05.04', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (740, '暑', 'THỬ', 'しょ', 'あつ-い', 'hè nóng', '太陽（たいよう）の下（した）の人（ひと）は暑（あつ）いです', 'Người đứng dưới mặt trời sẽ thấy nóng.', '/media/kanji/kanji512/bai15/hot.jpg', 4, 48, '2026-06-25 09:22:05.082', '2026-06-25 09:22:05.082', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (741, '寒', 'HÀN', 'かん', 'さ,さむ-い, さん', 'lạnh', '寒（さむ）い日（ひ）に、雪（ゆき）の上（うえ）に足跡（あしあと）を残（のこ）してあなたの家（いえ）まで来（き）ました', 'Vào những ngày lạnh giá, tôi đến nhà bạn và để lại những dấu chân trên tuyết.', '/media/kanji/kanji512/bai15/cold.jpg', 5, 48, '2026-06-25 09:22:05.093', '2026-06-25 09:22:05.093', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (742, '重', 'TRỌNG, TRÙNG', 'じゅう, ちょう', 'おも-い、かさ-なる', 'trọng lượng; trùng phùng', '1000冊（さつ）の本（ほん）は重（おも）いです', 'Một ngàn quyển sách （千）sẽ rất nặng.', '/media/kanji/kanji512/bai15/heavy.jpg', 6, 48, '2026-06-25 09:22:05.116', '2026-06-25 09:22:05.116', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (743, '軽', 'KHINH', 'けい', 'かる-い、かろ-やか', 'khinh suất, khinh khi', '軽（かる）い車（くるま）は手（て）で押（お）せば走（はし）ります', 'Chiếc xe hơi nhẹ sẽ chạy nếu ta đẩy bằng tay.', '/media/kanji/kanji512/bai15/light.jpg', 7, 48, '2026-06-25 09:22:05.144', '2026-06-25 09:22:05.144', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (744, '低', 'ĐÊ', 'てい', 'ひく-い', 'thấp, đê hèn, đê tiện', '「どうして私（わたし）の名前（なまえ）に下線（かせん）を付（つ）けたんですか」「点数（てんすう）が低（ひく）かったからです」', '”Vì sao cô gạch dưới tên của em vậy?”', '/media/kanji/kanji512/bai15/low.jpg', 8, 48, '2026-06-25 09:22:05.161', '2026-06-25 09:22:05.161', NULL, NULL, NULL, NULL, NULL);
