INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (778, '業', 'NGHIỆP', 'ぎょう, ごう, なり, わざ, のぶ', NULL, 'nghề nghiệp, công nghiệp, sự nghiệp', '羊（ひつじ）を囲（かこ）いの中（なか）で飼（か）っています。これが私（わたし）の仕事（しごと）です', 'Nuôi cừu bên trong hàng rào. Đây là công việc của tôi.', '/media/kanji/kanji512/bai17/business.jpg', 10, 50, '2026-06-25 09:22:05.815', '2026-06-25 09:22:05.815', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (779, '薬', 'DƯỢC', 'やく, くすり', NULL, 'thuốc', 'この薬草（やくそう）を飲（の）んで、元気（げんき）になって、楽（たの）しみましょう', 'Hãy uống thảo dược này để cảm thấy khoẻ lên và cùng nào vui chơi nào!', '/media/kanji/kanji512/bai17/medicine.jpg', 11, 50, '2026-06-25 09:22:05.841', '2026-06-25 09:22:05.841', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (780, '働', 'ĐỘNG', 'どう', 'はたら-く', 'lao động', '人（ひと）が動（うご）いて働（はたら）きます', 'Mọi người di chuyển làm việc.', '/media/kanji/kanji512/bai17/work.jpg', 12, 50, '2026-06-25 09:22:05.868', '2026-06-25 09:22:05.868', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (781, '員', 'VIÊN', 'いん', NULL, 'thành viên, nhân viên', 'お金（かね）を払（はら）って、会員（かいいん）カードを手（て）に入（い）れます', 'Trả tiền và nhận được thẻ hội viên.', '/media/kanji/kanji512/bai17/member.jpg', 13, 50, '2026-06-25 09:22:05.884', '2026-06-25 09:22:05.884', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (782, '士', 'SĨ', 'し', NULL, 'chiến sĩ, sĩ tử, bác sĩ', '十一人（じゅういちにん）のさむらい', 'Mười một võ sĩ đạo （十一）.', '/media/kanji/kanji512/bai17/warrior_samurai.jpg', 14, 50, '2026-06-25 09:22:05.913', '2026-06-25 09:22:05.913', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (783, '仕', 'SĨ', 'し, じ', 'つか-える', 'làm việc', 'さむらいは殿様（とのさま）にお仕（つか）えします', 'Võ sĩ đạo phục vụ cho ông chủ của anh ta.', '/media/kanji/kanji512/bai17/serve.jpg', 15, 50, '2026-06-25 09:22:05.942', '2026-06-25 09:22:05.942', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (784, '事', 'SỰ', 'じ, ず', 'ろ,こと, つか-う, つか-える', 'sự việc', 'することを全部（ぜんぶ）書（か）きます', 'Tôi viết toàn bộ những việc sẽ làm.', '/media/kanji/kanji512/bai17/thing.jpg', 16, 50, '2026-06-25 09:22:05.955', '2026-06-25 09:22:05.955', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (785, '図', 'ĐỒ', 'ず, と', 'づ,え, はか-る', 'bản đồ, đồ án, địa đồ', 'これがだれかがかいた絵（え）です。「ツ、メ」のように見（み）えます', 'Đây là bức tranh ai đó đã vẽ. Trông như là chữ 「ツ、メ」 vậy.', '/media/kanji/kanji512/bai18/drawing.jpg', 1, 51, '2026-06-25 09:22:05.982', '2026-06-25 09:22:05.982', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (786, '管', 'QUẢN', 'かん, くだ', NULL, 'ống, mao quản, quản lí', '太（ふと）った役人（やくにん）が家（いえ）の中（なか）にいます', 'Một quan chức mập đang ở trong nhà.', '/media/kanji/kanji512/bai18/government_offical.jpg', 2, 51, '2026-06-25 09:22:06.008', '2026-06-25 09:22:06.008', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (787, '館', 'QUÁN', 'かん, たち, たて, やかた', NULL, 'đại sứ quán, hội quán', 'この建物（たてもの）で、役人（やくにん）たちへ食事（しょくじ）をします', 'Các quan chức sẽ dùng bữa ở toà nhà này.', '/media/kanji/kanji512/bai18/building.jpg', 3, 51, '2026-06-25 09:22:06.039', '2026-06-25 09:22:06.039', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (788, '昔', 'TÍCH', 'せき, しゃく, むかし', NULL, 'ngày xưa', '二十一人（にじゅういちにん）前（まえ）は昔（むかし）です', 'Cách đây 21 ngày là chuyện của xưa kia.', '/media/kanji/kanji512/bai18/long_time_ago.jpg', 4, 51, '2026-06-25 09:22:06.073', '2026-06-25 09:22:06.073', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (789, '借', 'TÁ', 'しゃく', 'か-りる', 'mượn, tá điền', '昔（むかし）、だれかに何（なに）かを借（か）りました', 'Khi xưa （昔）tôi đã mượn cái gì đó từ một ai đó.', '/media/kanji/kanji512/bai18/borrow.jpg', 5, 51, '2026-06-25 09:22:06.096', '2026-06-25 09:22:06.096', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (790, '代', 'ĐẠI', 'だい, たい', 'かわ-る', 'đại biểu, thời đại, đại diện, đại thế', '代（か）わりましょう', '”Để tôi thay thế anh.”', '/media/kanji/kanji512/bai18/replace.jpg', 6, 51, '2026-06-25 09:22:06.111', '2026-06-25 09:22:06.111', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (791, '貸', 'THẢI', 'たい', 'か-す', 'cho mượn', '彼（かれ）の代（か）わりに私（わたし）がお金（かね）を貸（か）しましょう', 'Tôi sẽ cho bạn mượn tiền thay cho anh ấy.', '/media/kanji/kanji512/bai18/lend.jpg', 7, 51, '2026-06-25 09:22:06.14', '2026-06-25 09:22:06.14', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (792, '地', 'ĐỊA', 'ち, じ', NULL, 'thổ địa, địa đạo', 'この土地（とち）には、土（つち）の下（した）にサンリがいます', 'Ở vùng đất này, có con bò cạp ở dưới lòng đất.', '/media/kanji/kanji512/bai18/land.jpg', 8, 51, '2026-06-25 09:22:06.144', '2026-06-25 09:22:06.144', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (793, '世', 'THẾ', 'せい, せ, よ', NULL, 'thế giới, thế gian, thế sự', '「せかい」の「せ」はこの漢字（かんじ）から作（つく）られました', 'Chữ 「せ」 trong từ 「せかい」 (thế giới) được tạo thành từ chữ Hán này.', '/media/kanji/kanji512/bai18/world.jpg', 9, 51, '2026-06-25 09:22:06.169', '2026-06-25 09:22:06.169', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (794, '界', 'GIỚI', 'かい', NULL, 'thế giới, giới hạn, địa giới', 'あなたの田（た）んぼと私（わたし）の田（た）んぼの間（あいだ）には、境界（きょうかい）があります', 'Có ranh giới giữa ruộng của bạn và ruộng của tôi.', '/media/kanji/kanji512/bai18/boundary.jpg', 10, 51, '2026-06-25 09:22:06.208', '2026-06-25 09:22:06.208', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (795, '度', 'ĐỘ', 'ど, と, たく, たび', NULL, 'mức độ, quá độ, độ lượng', '家（いえ）の中（なか）が二十一度（にじゅういちど）だと、手（て）は温（あたた）かいです', 'Khi nhiệt độ trong nhà là 21 độ thì bàn tay ta sẽ rất ấm.', '/media/kanji/kanji512/bai18/degree.jpg', 11, 51, '2026-06-25 09:22:06.23', '2026-06-25 09:22:06.23', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (796, '回', 'HỒI', 'かい, え', 'まわ-す', 'vu hồi, chương hồi', '回（まわ）っています', 'Xoay vòng quanh.', '/media/kanji/kanji512/bai18/turning_around.jpg', 12, 51, '2026-06-25 09:22:06.264', '2026-06-25 09:22:06.264', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (797, '用', 'DỤNG', 'よう', 'たから,もち-いる', 'sử dụng, dụng cụ, công dụng', '私（わたし）たちが使（つか）っている作（さく）です', 'Đây là hàng rào cọc mà chúng tôi đang sử dụng.', '/media/kanji/kanji512/bai18/use1.jpg', 13, 51, '2026-06-25 09:22:06.3', '2026-06-25 09:22:06.3', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (798, '民', 'DÂN', 'みん, たみ', NULL, 'quốc dân, dân tộc', '人（ひと）は口（くち）と氏名（しめい）を持（も）っています', 'Con người có miệng và họ tên.', '/media/kanji/kanji512/bai18/people1.jpg', 14, 51, '2026-06-25 09:22:06.32', '2026-06-25 09:22:06.32', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (799, '注', 'CHÚ', 'ちゅう', 'そそ-ぐ', 'chú ý, chú thích', '「ご主人（しゅじん）様（さま）に水（みず）を掛（か）けないように注意（ちゅうい）して」', '”Cẩn thận đừng làm đổ nước vào ông chủ!”', '/media/kanji/kanji512/bai18/pour.jpg', 15, 51, '2026-06-25 09:22:06.348', '2026-06-25 09:22:06.348', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (800, '意', 'Ý', 'い', NULL, 'ý nghĩa, ý thức, ý kiến, chú ý', '心（こころ）の音（おと）を聞（き）きなさい。自分（じぶん）の気持（きも）ちがわかるでしょう', 'Lắng nghe âm thanh của trái tim! Có lẽ bạn sẽ hiểu được tâm tình của chính mình.', '/media/kanji/kanji512/bai18/mind.jpg', 16, 51, '2026-06-25 09:22:06.369', '2026-06-25 09:22:06.369', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (801, '頭', 'ĐẦU', 'とう, ず, と, あたま, かしら', NULL, 'đầu não', '豆（まめ）みたいな頭（あたま）でしょ', 'Đầu của tôi trông giống hạt đậu.', '/media/kanji/kanji512/bai19/head.jpg', 1, 52, '2026-06-25 09:22:06.398', '2026-06-25 09:22:06.398', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (802, '顔', 'NHAN', 'がん, かお', NULL, 'nhan sắc, hồng nhan', '頭（あたま）から帽子（ぼうし）を取（と）ると、頭（あたま）の傷（きず）が見（み）えます', 'Khi gỡ nón ra khỏi đầu thì thấy các vết xước trên mặt.', '/media/kanji/kanji512/bai19/face.jpg', 2, 52, '2026-06-25 09:22:06.429', '2026-06-25 09:22:06.429', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (803, '声', 'THANH', 'せい, しょう', 'こえ, こわ-', 'âm thanh, thanh điệu', 'さむらいが戸（と）のところで「エロ」と声（こえ）を出（だ）している', 'Võ sĩ đạo （士）cất giọng phát ra âm thanh 「コエ」ở bên cửa.', '/media/kanji/kanji512/bai19/voice.jpg', 3, 52, '2026-06-25 09:22:06.444', '2026-06-25 09:22:06.444', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (804, '特', 'ĐẶC', 'とく', NULL, 'đặc biệt, đặc công', 'ヒンズー今日（きょう）の寺院（じいん）では、牛（うし）は特別（とくべつ）な動物（どうぶつ）です', 'Bò là một con vật đặc biệt ở đền thờ của đạo Hindu.', '/media/kanji/kanji512/bai19/special.jpg', 4, 52, '2026-06-25 09:22:06.464', '2026-06-25 09:22:06.464', NULL, NULL, NULL, NULL, NULL);
