INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (809, '正', 'CHÍNH', 'せい, しょう', 'ただ-しい、まさ-に', 'chính đáng, chính nghĩa, chân chính', '赤信号（あかしんごう）で止（と）まるのは、正（ただ）しいことです', 'Việc dừng lại khi đèn đỏ là việc làm đúng đắn.', '/media/kanji/kanji512/bai19/right1.jpg', 9, 52, '2026-06-25 09:22:06.537', '2026-06-25 09:22:06.537', NULL, NULL, NULL, NULL, NULL);
