INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (870, '受', 'THỤ', 'じゅ', 'う-ける', 'nhận, tiếp thụ', '手（て）から手（て）へものを受（う）け取（と）ります', 'Truyền tay nhau nhận lấy vật.', '/media/kanji/kanji512/bai23/to_receive.jpg', 6, 56, '2026-06-25 09:22:07.673', '2026-06-25 09:22:07.673', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (871, '授', 'THỤ', 'じゅ', 'さず-ける', 'đưa cho, truyền thụ, giáo thụ', '教（おし）えてもらうことは何（なに）かを受（う）け取（と）ることです', 'Được chỉ bảo là việc nhận lấy cái gì đó từ người khác.', '/media/kanji/kanji512/bai23/to_instruct.jpg', 7, 56, '2026-06-25 09:22:07.687', '2026-06-25 09:22:07.687', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (872, '練', 'LUYỆN', 'れん', 'ね-る', 'rèn luyện, luyện tập', '弟子（でし）が道（みち）を走（はし）っています', 'Đệ tử đang chạy trên đường', '/media/kanji/kanji512/bai23/elaborate.jpg', 8, 56, '2026-06-25 09:22:07.701', '2026-06-25 09:22:07.701', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (873, '徒', 'ĐỒ', 'と, かち', NULL, 'môn đồ, đồ đệ', '東洋（とうよう）で、私（わたし）を紡（つむ）ぐ練習（れんしゅう）をしました', 'Tôi đã luyện kéo sợi ở Đông Dương.', '/media/kanji/kanji512/bai23/follow.jpg', 9, 56, '2026-06-25 09:22:07.716', '2026-06-25 09:22:07.716', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (874, '復', 'PHỤC', 'ふく', NULL, 'phục thù, hồi phục', '人（ひと）は同（おな）じ道（みち）を毎日（まいにち）歩（ある）きます', 'Con người cứ bước đi trên cùng con đường mỗi ngày.', '/media/kanji/kanji512/bai23/repetition.jpg', 10, 56, '2026-06-25 09:22:07.759', '2026-06-25 09:22:07.759', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (875, '表', 'BIỂU', 'ひょう', 'おもて、あらわ-す', 'biểu hiện, bảng biểu, biểu diễn', '木（き）が大（おお）きく育（そだ）ったので、喜（よろこ）びを表現（ひょうげん）しています', 'Con người cứ bước đi trên cùng con đường mỗi ngày.', '/media/kanji/kanji512/bai23/to_express_surface.jpg', 11, 56, '2026-06-25 09:22:07.795', '2026-06-25 09:22:07.795', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (876, '卒', 'TỐT', 'そつ, →卆［卆', NULL, 'tốt nghiệp', '住人（じゅうにん）の人（ひと）が卒業（そつぎょう）しました', '10 （十）người đã tốt nghiệp.', '/media/kanji/kanji512/bai23/to_granduate.jpg', 12, 56, '2026-06-25 09:22:07.833', '2026-06-25 09:22:07.833', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (877, '違', 'VI', 'い', 'ちが-う', 'vi phạm, tương vi', '道（みち）が複雑（ふくざつ）なので、間違（まちが）えたみたいです', 'Vì đường sá phức tạp nên dường như tôi đã đi nhầm đường.', '/media/kanji/kanji512/bai23/different.jpg', 13, 56, '2026-06-25 09:22:07.873', '2026-06-25 09:22:07.873', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (878, '役', 'DỊCH', 'えき, やく', NULL, 'chức vụ, nô dịch', '私（わたし）の役目（やくめ）は石（いし）を運（はこ）ぶことです', 'Nhiệm vụ của tôi là mang hòn đá.', '/media/kanji/kanji512/bai23/duty.jpg', 14, 56, '2026-06-25 09:22:07.883', '2026-06-25 09:22:07.883', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (879, '皆', 'GIAI', 'かい, みな', NULL, 'tất cả', '白（しろ）い建物（たてもの）の上（うえ）の人（ひと）を比（くら）べてください。みんなよく似（に）ています', 'Hãy so sánh （比）những người trên toà nhà màu trắng（白）. Mọi người trông giống nhau.', '/media/kanji/kanji512/bai23/everyone.jpg', 15, 56, '2026-06-25 09:22:07.911', '2026-06-25 09:22:07.911', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (880, '彼', 'BỈ', 'ひ, かの, かれ', NULL, 'anh ta', '彼（かれ）の腕（うで）を捕（つか）まえようとしたけれど、彼（かれ）は行（い）ってしまいました', 'Tôi đã định nắm lấy tay anh ấy nhưng anh ấy đã đi rồi.', '/media/kanji/kanji512/bai23/he.jpg', 16, 56, '2026-06-25 09:22:07.945', '2026-06-25 09:22:07.945', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (881, '全', 'TOÀN', 'ぜん', 'すべ-て、まった-く、まっと-う', 'toàn bộ', '王様（おうさま）は山（やま）にある全部（ぜんぶ）の物（もの）を統治（とうち）しています', 'Nhà vua thống trị toàn bộ những thứ có trên núi.', '/media/kanji/kanji512/bai24/all.jpg', 1, 57, '2026-06-25 09:22:07.98', '2026-06-25 09:22:07.98', NULL, NULL, NULL, NULL, NULL);
