INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (898, '和', 'HÒA', 'わ, お', 'やわ-らぐ、なご-む', 'hòa bình, tổng hòa, điều hòa', '和食（わしょく）にはご飯（はん）が付（つ）いてきます', 'Đồ ăn Nhật đi kèm với cơm.', '/media/kanji/kanji512/bai25/peace.jpg', 2, 58, '2026-06-25 09:22:08.398', '2026-06-25 09:22:08.398', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (899, '戦', 'CHIẾN', 'せん', 'いくさ、たたか-う］ →戰［單', 'chiến tranh, chiến đấu', '戦争（せんそう）ではいろいろな武器（ぶき）が使（つか）われます', 'Nhiều loại vũ khí được sử dụng trong chiến tranh.', '/media/kanji/kanji512/bai25/war.jpg', 3, 58, '2026-06-25 09:22:08.435', '2026-06-25 09:22:08.435', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (900, '争', 'TRANH', 'そう', 'あらそ-う］ 競争(きょうそう)→爭［爭', 'đấu tranh, chiến tranh, tranh luận, cạnh tranh', 'その人（ひと）は武器（ぶき）を手（て）に持（も）ち、争（あらそ）いに備（そな）えています', 'Người đó cầm vũ khí trong tay chuẩn bị đánh nhau.', '/media/kanji/kanji512/bai25/conflict.jpg', 4, 58, '2026-06-25 09:22:08.473', '2026-06-25 09:22:08.473', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (901, '政', 'CHÍNH', 'せい, しょう, まつりごと', NULL, 'chính phủ, chính sách, hành chính', '政府（せいふ）は正（ただ）しいことをするべきです', 'Chính phủ nên thực thi những điều đúng đắn（正）.', '/media/kanji/kanji512/bai25/government.jpg', 5, 58, '2026-06-25 09:22:08.492', '2026-06-25 09:22:08.492', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (902, '治', 'TRỊ', 'ち, じ', 'おさ-める', 'cai trị, trị an, trị bệnh', '私（わたし）は海岸（かいがん）地帯（ちたい）を納（おさ）めています', 'Tôi quản lý vùng ven biển.', '/media/kanji/kanji512/bai25/to_govern_cure.jpg', 6, 58, '2026-06-25 09:22:08.532', '2026-06-25 09:22:08.532', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (903, '経', 'KINH', 'けい, きょう', 'へ-る、た-つ', 'kinh tế, sách kinh, kinh độ', '土（つち）を耕（たがや）したり、糸（いと）を紡（つむ）いだりして、長（なが）い時間（じかん）が経（た）ってしまいました', 'Khi thì cày đất, khi thì kéo sợi, thời gian khá dài đã trôi qua.', '/media/kanji/kanji512/bai25/to_pass_through.jpg', 7, 58, '2026-06-25 09:22:08.55', '2026-06-25 09:22:08.55', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (904, '済', 'TẾ', 'さい', 'す-む］ 終わる、助ける→濟［齊', 'kinh tế, cứu tế', '看板（かんばん）に文（ぶん）を書（か）いて、仕事（しごと）を済（す）ませました', 'Tôi đã viết câu văn lên bảng hiệu và hoàn tất công việc.', '/media/kanji/kanji512/bai25/to_finish.jpg', 8, 58, '2026-06-25 09:22:08.583', '2026-06-25 09:22:08.583', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (905, '法', 'PHÁP', 'ほう, は, ほ', 'のり、のっと-る', 'pháp luật, phương pháp', '去年（きょねん）、水（みず）の法律（ほうりつ）が施行（しこう）されました', 'Năm ngoái, các luật về nước đã được thi hành.', '/media/kanji/kanji512/bai25/law_method.jpg', 9, 58, '2026-06-25 09:22:08.599', '2026-06-25 09:22:08.599', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (906, '律', 'LUẬT', 'りつ, りち', NULL, 'luật pháp', '交通（こうつう）規則（きそく）を書（か）きました', 'Tôi đã viết các luật lệ giao thông.', '/media/kanji/kanji512/bai25/regulation.jpg', 10, 58, '2026-06-25 09:22:08.631', '2026-06-25 09:22:08.631', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (907, '際', 'TẾ', 'さい, きわ', NULL, 'quốc tế', '祭（まつ）りは特別（とくべつ）な行事（ぎょうじ）です', 'Lễ hội là sự kiện đặc biệt.', '/media/kanji/kanji512/bai25/occasion.jpg', 11, 58, '2026-06-25 09:22:08.647', '2026-06-25 09:22:08.647', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (908, '関', 'QUAN', 'かん, せき', NULL, 'hải quan, quan hệ', 'いい関係（かんけい）を作（つく）るために贈（おく）り物（もの）を門（もん）まで持（も）って来（き）ました', 'Tôi đã mang quà tặng đến tận cổng để tạo mối quan hệ tốt.', '/media/kanji/kanji512/bai25/to_relate.jpg', 12, 58, '2026-06-25 09:22:08.681', '2026-06-25 09:22:08.681', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (909, '係', 'HỆ', 'けい', 'かか-る、かかり', 'quan hệ, hệ số', '人々（ひとびと）は糸（いと）のように結（むす）びついています', 'Mọi người kết nối với nhau giống như sợi chỉ （糸）vậy.', '/media/kanji/kanji512/bai25/to_connect.jpg', 13, 58, '2026-06-25 09:22:08.716', '2026-06-25 09:22:08.716', NULL, NULL, NULL, NULL, NULL);
