INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (929, '吉', 'CÁT', 'きち, きつ', NULL, 'tốt lành, cát tường', '侍（さむらい）が「幸運（こううん）を祈（いの）る」と叫（さけ）びます', 'Võ sĩ đạo hét to: ”Chúc may mắn!”', '/media/kanji/kanji512/bai27/goodluck.jpg', 1, 60, '2026-06-25 09:22:09.344', '2026-06-25 09:22:09.344', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (930, '結', 'KẾT', 'けつ', 'むす-ぶ、ゆ-う', 'đoàn kết, kết thúc', '糸（いと）を結（むす）んで、幸運（こううん）のお守（まも）りを作（つく）りました', 'Kết chỉ làm bùa may mắn.', '/media/kanji/kanji512/bai27/to_tie.jpg', 2, 60, '2026-06-25 09:22:09.376', '2026-06-25 09:22:09.376', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (931, '婚', 'HÔN', 'こん', NULL, 'kết hôn, hôn nhân', '女（おんな）の人（ひと）は結婚（けっこん）後（ご）、姓（せい）を変（か）えました', 'Phụ nữ đổi họ sau khi kết hôn.', '/media/kanji/kanji512/bai27/marriage.jpg', 3, 60, '2026-06-25 09:22:09.402', '2026-06-25 09:22:09.402', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (932, '共', 'CỘNG', 'きょう, とも', NULL, 'tổng cộng, cộng sản, công cộng', 'あなたと共（とも）に', 'Cùng với bạn.', '/media/kanji/kanji512/bai27/together.jpg', 4, 60, '2026-06-25 09:22:09.438', '2026-06-25 09:22:09.438', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (933, '供', 'CUNG', 'きょう, く', 'そな-える、とも', 'cung cấp, cung phụng', '一緒（いっしょ）にあなたを助（たす）けます', 'Cùng nhau giúp đỡ bạn.', '/media/kanji/kanji512/bai27/offer.jpg', 5, 60, '2026-06-25 09:22:09.476', '2026-06-25 09:22:09.476', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (934, '両', 'LƯỠNG', 'りょう, →兩［兩', NULL, 'hai, lưỡng quốc', '魚屋（さかなや）が両肩（りょうかた）にさおを担（かつ）いでいます', 'Người bán cá vác quang gánh trên cả hai vai.', '/media/kanji/kanji512/bai27/both.jpg', 6, 60, '2026-06-25 09:22:09.507', '2026-06-25 09:22:09.507', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (935, '若', 'NHƯỢC', 'じゃく, にゃく', 'わか-い、も-し', 'trẻ, nhược niên', '出（で）たばかりの若葉（わかば）を右手（みぎて）で掴（つか）みます', 'Hái những chiếc lá non bằng tay phải.', '/media/kanji/kanji512/bai27/young.jpg', 7, 60, '2026-06-25 09:22:09.542', '2026-06-25 09:22:09.542', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (936, '老', 'LÃO', 'ろう', 'お-いる、ふ-ける', 'già, lão luyện', 'おじさんは杖（つえ）を持（も）って、おばあさんは座（すわ）っています', 'Ông lão cầm cây gậy còn bà lão thì đang ngồi.', '/media/kanji/kanji512/bai27/old_age.jpg', 8, 60, '2026-06-25 09:22:09.566', '2026-06-25 09:22:09.566', NULL, NULL, NULL, NULL, NULL);
