INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (939, '奥', 'ÁO', 'うう, →奧［奧', NULL, 'trong cùng', '米（こめ）を大（おお）きい箱（はこ）に入（い）れ、億（おく）にしまっていきます', 'Tôi bỏ gạo （米）vào trong cái hộp lớn （大）rồi cất nó vào trong góc.', '/media/kanji/kanji512/bai27/back.jpg', 11, 60, '2026-06-25 09:22:09.657', '2026-06-25 09:22:09.657', NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (940, '将', 'TƯỚNG', 'しょう', 'まさ-に］ 今にも、助ける、養う→將［將', 'tướng quân', '将軍（しょうぐん）が将来（しょうらい）について考（かんが）えています', 'Tướng quân đang suy nghĩ về tương lai.', '/media/kanji/kanji512/bai27/commander.jpg', 12, 60, '2026-06-25 09:22:09.677', '2026-06-25 09:22:09.677', NULL, NULL, NULL, NULL, NULL);
