INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (995, '様', 'DẠNG', 'よう, さま', NULL, 'đa dạng, hình dạng', '木（き）、羊（ひつじ）、水（みず）のある喉（のど）かな様子（ようす）です', 'Cái cây, con cừu, dòng nước tạo ra dáng vẻ thanh bình.', '/media/kanji/kanji512/bai31/situation.jpg', 3, 64, '2026-06-25 09:22:11.414', '2026-06-25 09:22:11.414', NULL, NULL, NULL, NULL, NULL);
