INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (997, '調', 'ĐIỀU, ĐIỆU', 'ちょう', 'しら-べる、ととの-える', 'điều tra, điều hòa; thanh điệu, giai điệu', '周（まわ）りを調査（ちょうさ）うすと言（い）っています', 'Họ bảo sẽ điều tra xung quanh.', '/media/kanji/kanji512/bai31/to_investigate_tone.jpg', 5, 64, '2026-06-25 09:22:11.54', '2026-06-25 09:22:11.54', NULL, NULL, NULL, NULL, NULL);
