INSERT INTO public."KanjiEntry" (id, "character", "hanViet", onyomi, kunyomi, "meaningVi", "mnemonicJp", "mnemonicVi", "imageUrl", "sortOrder", "lessonId", "createdAt", "updatedAt", "meaningEn", "jlptLevel", "strokeCount", frequency, grade) VALUES (1000, '談', 'ĐÀM', 'だん', NULL, 'hội đàm, đàm thoại', '火（ひ）のそばで話（はな）しましょう', 'Chúng ta hãy trò chuyện bên đống lửa（火）', '/media/kanji/kanji512/bai31/talk.jpg', 8, 64, '2026-06-25 09:22:11.612', '2026-06-25 09:22:11.612', NULL, NULL, NULL, NULL, NULL);
