INSERT INTO public."PronunciationRuleSection" (id, slug, title, summary, "sortOrder", "createdAt", "updatedAt") VALUES (1, 'vowels', 'Năm nguyên âm あ・い・う・え・お', 'Nền tảng của mọi âm tiếng Nhật.', 0, '2026-06-28 09:04:53.529', '2026-06-28 09:04:53.529');
INSERT INTO public."PronunciationRuleSection" (id, slug, title, summary, "sortOrder", "createdAt", "updatedAt") VALUES (2, 'mora', 'Mora — nhịp phát âm', 'Tiếng Nhật đếm theo mora, không phải âm tiết.', 1, '2026-06-28 09:04:53.54', '2026-06-28 09:04:53.54');
INSERT INTO public."PronunciationRuleSection" (id, slug, title, summary, "sortOrder", "createdAt", "updatedAt") VALUES (3, 'yoon', 'Âm ghép きゃ・しゅ・ちょ…', 'Ghép âm i-row + や・ゆ・よ nhỏ.', 2, '2026-06-28 09:04:53.544', '2026-06-28 09:04:53.544');
INSERT INTO public."PronunciationRuleSection" (id, slug, title, summary, "sortOrder", "createdAt", "updatedAt") VALUES (4, 'sokuon', 'Âm đôi っ (sokuon)', 'Dấu nhỏ — tạo khoảng dừng / phụ âm kép.', 3, '2026-06-28 09:04:53.549', '2026-06-28 09:04:53.549');
INSERT INTO public."PronunciationRuleSection" (id, slug, title, summary, "sortOrder", "createdAt", "updatedAt") VALUES (5, 'long-vowel', 'Trường âm (chouon)', 'Kéo dài nguyên âm — đổi nghĩa nếu đọc sai độ dài.', 4, '2026-06-28 09:04:53.553', '2026-06-28 09:04:53.553');
INSERT INTO public."PronunciationRuleSection" (id, slug, title, summary, "sortOrder", "createdAt", "updatedAt") VALUES (6, 'dakuten', 'Âm đục が・ざ & yếu ぱ', 'Dấu ゛ (dakuten) và ゜ (handakuten).', 5, '2026-06-28 09:04:53.557', '2026-06-28 09:04:53.557');
INSERT INTO public."PronunciationRuleSection" (id, slug, title, summary, "sortOrder", "createdAt", "updatedAt") VALUES (7, 'special', 'Âm đặc biệt: ら・ふ・つ・ん', 'Hay sai với người Việt.', 6, '2026-06-28 09:04:53.561', '2026-06-28 09:04:53.561');
INSERT INTO public."PronunciationRuleSection" (id, slug, title, summary, "sortOrder", "createdAt", "updatedAt") VALUES (8, 'pitch', 'Pitch accent (âm cao–thấp)', 'Cùng kana nhưng cao độ khác → nghĩa khác (ít gặp N5).', 7, '2026-06-28 09:04:53.565', '2026-06-28 09:04:53.565');
INSERT INTO public."PronunciationRuleSection" (id, slug, title, summary, "sortOrder", "createdAt", "updatedAt") VALUES (9, 'practice', 'Luyện trên app', 'Cách dùng tab Phát âm hiệu quả.', 8, '2026-06-28 09:04:53.569', '2026-06-28 09:04:53.569');
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (1, 1, 'あめ', 'ame', 'mưa / kẹo', NULL, 0);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (2, 1, 'いぬ', 'inu', 'chó', NULL, 1);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (3, 1, 'うみ', 'umi', 'biển', NULL, 2);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (4, 2, 'にほん', 'ni-ho-n', 'Nhật Bản', '4 mora', 0);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (5, 2, 'がっこう', 'ga-k-ko-u', 'trường học', 'っ = mora dừng', 1);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (6, 3, 'きょう', 'kyou', 'hôm nay', NULL, 0);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (7, 3, 'しゃしん', 'shashin', 'ảnh', NULL, 1);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (8, 3, 'ちょっと', 'chotto', 'một chút', NULL, 2);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (9, 4, 'いっぷん', 'ippun', 'một phút', NULL, 0);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (10, 4, 'きって', 'kitte', 'tem', NULL, 1);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (11, 4, 'ざっし', 'zasshi', 'tạp chí', NULL, 2);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (12, 5, 'おばさん', 'obasan', 'cô, dì', NULL, 0);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (13, 5, 'おばあさん', 'obaasan', 'bà', NULL, 1);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (14, 5, 'ビール', 'biiru', 'bia', NULL, 2);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (15, 6, 'かぎ', 'kagi', 'chìa khóa', NULL, 0);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (16, 6, 'ぱん', 'pan', 'bánh mì', NULL, 1);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (17, 6, 'じかん', 'jikan', 'thời gian', NULL, 2);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (18, 7, 'ふろ', 'furo', 'bồn tắm', NULL, 0);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (19, 7, 'つき', 'tsuki', 'mặt trăng', NULL, 1);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (20, 7, 'せんせい', 'sensei', 'thầy/cô', NULL, 2);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (21, 8, 'はし', 'hashi', 'đũa / cầu', 'Pitch khác nhau', 0);
INSERT INTO public."PronunciationRuleExample" (id, "sectionId", japanese, romaji, meaning, note, "sortOrder") VALUES (22, 8, 'いま', 'ima', 'bây giờ / phòng', NULL, 1);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (1, 1, NULL, 'あ い う え お', 'a i u e o', 'Năm nguyên âm thuần. Mỗi âm một mora, độ dài ổn định. う môi tròn nhẹ, không phải "u" mím chặt.', 0);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (2, 1, 'Bảng kana', NULL, NULL, 'Hiragana dùng cho từ gốc Nhật; katakana cho từ mượn. Cùng âm, khác cách viết.', 1);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (3, 2, NULL, NULL, NULL, 'Mỗi kana (trừ っ, ん đặc biệt) thường = 1 mora. きょう (kyo) = 3 mora: き + ょ + う.', 0);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (4, 2, NULL, NULL, NULL, 'Nói đều nhịp, không nhấn mạnh từng âm tiết như tiếng Việt. Thời lượng mỗi mora gần bằng nhau.', 1);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (5, 3, NULL, 'きゃ きゅ きょ', 'kya kyu kyo', 'Ghép trong một mora — không đọc "ki-ya" tách đôi.', 0);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (6, 3, NULL, 'しゃ しゅ しょ', 'sha shu sho', 'Âm sh — môi tròn, lưỡi nâng. Không đọc "si-ya".', 1);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (7, 3, NULL, 'ちゃ ちゅ ちょ', 'cha chu cho', 'Gần "chi" + y nhỏ; khác với しゃ (sh).', 2);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (8, 4, NULL, 'っ', NULL, 'Không phát âm riêng — tạm dừng rồi phát âm phụ âm kế tiếp mạnh hơn (kk, pp, tt…).', 0);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (9, 4, NULL, NULL, NULL, 'Ví dụ がっこう: dừng nhẹ trước こ, như "gak-kou" chứ không "gatsukou".', 1);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (10, 5, NULL, NULL, NULL, 'おばさん (cô) vs おばあさん (bà) — mora あ kéo dài gấp đôi. きょう vs きよう cũng khác mora.', 0);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (11, 5, NULL, NULL, NULL, 'Katakana dùng ー để kéo dài: コーヒー (koohii). Hiragana thường lặp nguyên âm.', 1);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (12, 6, NULL, 'か → が', NULL, 'Thêm rung thanh hầu — ga, không phải ka.', 0);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (13, 6, NULL, 'は → ば / ぱ', NULL, 'ば đục; ぱ yếu (p gần b). は đọc "wa" khi là trợ từ.', 1);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (14, 6, NULL, 'ざ じ ず ぜ ぞ', NULL, 'じ ≈ "ji", ず ≈ "zu" — không giống "di", "du" tiếng Việt.', 2);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (15, 7, NULL, 'らりるれろ', 'ra ri ru re ro', 'Một âm r lẫn l — lưỡi chạm vòm, không lắc.', 0);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (16, 7, NULL, 'ふ', 'fu', 'Thổi nhẹ qua môi, gần "hu".', 1);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (17, 7, NULL, 'つ', 'tsu', 'Âm xát nhẹ, một mora duy nhất.', 2);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (18, 7, NULL, 'ん', 'n', 'Âm mũi cuối âm tiết; trước b/p/m là mũi môi.', 3);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (19, 8, NULL, NULL, NULL, 'Tiếng Nhật dùng cao độ mora, không nhấn trọng âm như tiếng Anh. Mỗi từ có kiểu lên–xuống riêng.', 0);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (20, 8, NULL, NULL, NULL, 'N5: nghe mẫu và bắt chước. は trợ từ thường thấp; một số từ danh từ cao ở mora đầu.', 1);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (21, 9, NULL, NULL, NULL, 'Tab Kana: luyện từng âm hiragana/katakana. Bật "Phát âm mẫu khi chuyển thẻ" để nghe ngay.', 0);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (22, 9, NULL, NULL, NULL, 'Tab Từ vựng Minna: luyện theo bài. Ghi âm → nghe lại → so với mẫu.', 1);
INSERT INTO public."PronunciationRulePoint" (id, "sectionId", label, japanese, romaji, explanation, "sortOrder") VALUES (23, 9, NULL, NULL, NULL, 'Lật thẻ xem gợi ý romaji/nghĩa. Lặp lại âm khó (ら, つ, っ, trường âm) mỗi ngày.', 2);
INSERT INTO public."PronunciationRuleTip" (id, text, "sortOrder", "createdAt", "updatedAt") VALUES (1, 'Giữ miệng mở vừa phải; âm あ gần âm "a" ngắn, không kéo dài như "a" trong "ba".', 0, '2026-06-28 09:04:53.523', '2026-06-28 09:04:53.523');
INSERT INTO public."PronunciationRuleTip" (id, text, "sortOrder", "createdAt", "updatedAt") VALUES (2, 'Âm ら hàng r không lắc lưỡi — lưỡi chạm vòm miệng nhẹ rồi buông.', 1, '2026-06-28 09:04:53.523', '2026-06-28 09:04:53.523');
INSERT INTO public."PronunciationRuleTip" (id, text, "sortOrder", "createdAt", "updatedAt") VALUES (3, 'Âm ふ/フ gần "hu" thổi nhẹ, không phải "ph" hay "f" cứng như tiếng Anh.', 2, '2026-06-28 09:04:53.523', '2026-06-28 09:04:53.523');
INSERT INTO public."PronunciationRuleTip" (id, text, "sortOrder", "createdAt", "updatedAt") VALUES (4, 'Âm つ nhỏ, sát răng — không phát âm như "ts" tách rời hai âm.', 3, '2026-06-28 09:04:53.523', '2026-06-28 09:04:53.523');
INSERT INTO public."PronunciationRuleTip" (id, text, "sortOrder", "createdAt", "updatedAt") VALUES (5, 'Âm ん là mũi — cuối từ, không thêm nguyên âm sau.', 4, '2026-06-28 09:04:53.523', '2026-06-28 09:04:53.523');
INSERT INTO public."PronunciationRuleTip" (id, text, "sortOrder", "createdAt", "updatedAt") VALUES (6, 'Kéo dài nguyên âm (おばあさん) khác hẳn nguyên âm ngắn (おばさん) — sai độ dài là sai nghĩa.', 5, '2026-06-28 09:04:53.523', '2026-06-28 09:04:53.523');
INSERT INTO public."PronunciationRulesMeta" (id, intro, "createdAt", "updatedAt") VALUES (1, 'Tiếng Nhật có khoảng 46 âm cơ bản (mora). Mỗi chữ hiragana/katakana thường tương ứng một mora — phát âm đều, không nhấn âm tiết như tiếng Việt.', '2026-06-28 09:04:53.515', '2026-06-28 09:04:53.515');
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (1, 'たなかさんのメール', 'やまださんへ
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (2, '天気予報', 'きょうの天気予報です。
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (3, 'レストランで', 'すみません。メニューをください。
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (4, '学校のお知らせ', 'みなさんへ
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (5, '服を買う', '店員：いらっしゃいませ。何をお探しですか。
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (6, 'わたしの家族', 'はじめまして。わたしはサトウです。家族を紹介します。
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (7, '京都への旅行', '来月、友達と京都へ旅行に行く予定です。新幹線で行きます。ホテルは駅の近くに予約しました。
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (8, 'アルバイトの面接', 'コンビニでアルバイトの面接を受けました。店長に自己紹介をして、週に何日働けるか聞かれました。
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (9, '健康のために', '最近、パソコンの前に長時間座っている人が増えています。健康のために、一時間に一度は立ってストレッチをしましょう。
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (10, '引っ越しの準備', '来月末、東京から大阪へ引っ越すことになりました。新しいアパートは会社から徒歩十五分の場所です。部屋は二部屋あって、日当たりもいいです。
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (11, '文化祭のお知らせ', '十一月三日と四日に、学校で文化祭を行います。入場は無料ですが、各クラスの出店では食べ物や飲み物を販売します。
INSERT INTO public."ReadingPassage" (id, title, content, "jlptLevel", source, "estimatedMin", "sortOrder", "createdAt", "updatedAt") VALUES (12, '会議の変更について', '各位
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (1, 1, 'たなかさんは何をしようとしていますか。', '土曜日に映画を見る', '「いっしょにえいがを見ませんか」と誘っています。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (2, 1, '映画は何時からですか。', '午後2時', '本文に「午後二時からです」とあります。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (3, 1, 'ごはんは誰が払いますか。', 'たなかさん', '「わたしのおごりです」＝たなかさんが払います。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (4, 2, '午前中の天気はどうですか。', '晴れ', '「午前中は晴れです」とあります。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (5, 2, '夜はどうなりますか。', '雨が降る', '「夜は雨がふるでしょう」と予報されています。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (6, 2, '何を持っていくべきですか。', '傘', '「傘を持っていってください」と書いてあります。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (7, 3, '何を注文しましたか。', 'ラーメンと餃子', '「ラーメンを一つと、餃子を二つ」と注文しています。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (8, 3, '飲み物は何ですか。', 'お茶', '「飲み物はお茶でいいです」と言っています。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (9, 3, 'お会計はいくらですか。', '1200円', '最後に「お会計は千二百円です」とあります。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (10, 4, '月曜日は何の授業がありますか。', '体育', '「月曜日は体育の授業があります」とあります。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (11, 4, '月曜日に何を持ってきますか。', '運動靴と水筒', '「運動靴と水筒を持ってきてください」と書いてあります。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (12, 4, '水曜日はどうなりますか。', '図書館が休み', '「水曜日は図書館が休みです」とお知らせされています。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (13, 5, 'きむらさんは何を探していますか。', '青いシャツ', '「青いシャツを探しています」と言っています。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (14, 5, 'セールの値段はいくらですか。', '2800円', '「セールで二千八百円です」とあります。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (15, 5, 'どうやって払いますか。', 'クレジットカード', '「クレジットカードで払えますか」と聞いています。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (16, 6, '父は何をしていますか。', '会社員', '「父は会社員です」とあります。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (17, 6, '母はどこで働いていますか。', '病院', '母は看護師で「病院で働いています」。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (18, 6, 'サトウさんは何が好きですか。', 'サッカー', '「サッカーが好きです」と書いてあります。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (19, 7, 'どうやって京都へ行きますか。', '新幹線', '「新幹線で行きます」と書いてあります。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (20, 7, '二日目に行きたい場所はどこですか。', '嵐山と天龍寺', '二日目は「嵐山で竹林を歩いて、天龍寺にも行きたい」とあります。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (21, 7, '特に食べたいものは何ですか。', '湯豆腐と抹茶スイーツ', '「湯豆腐と抹茶のスイーツを食べたい」とあります。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (22, 7, '一人の予算はいくらぐらいですか。', '3万円', '「一人三万円ぐらいです」と書いてあります。', 4);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (23, 8, 'どこで面接を受けましたか。', 'コンビニ', '最初の文に「コンビニでアルバイトの面接」とあります。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (24, 8, '働ける日はいつですか。', '火・木の午後と土曜終日', '火曜・木曜の午後と土曜の終日と答えています。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (25, 8, '時給はいくらですか。', '1100円', '「時給は千一百円」とあります。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (26, 8, 'いつから働き始めますか。', '来週の月曜日', '最後に「来週の月曜日から働き始める」とあります。', 4);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (27, 9, 'パソコンの前で長時間座る人に何を勧めていますか。', '一時間に一度立ってストレッチ', '「一時間に一度は立ってストレッチをしましょう」とあります。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (28, 9, '食事について何と言っていますか。', '野菜と果物を毎日食べる', '「野菜と果物を毎日食べて」と勧めています。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (29, 9, '大人は何時間寝るのが理想的ですか。', '7〜8時間', '「七時間から八時間寝ることが理想的」と書いてあります。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (30, 9, 'よく眠るために何をしない方がいいですか。', '寝る前にスマホを見る', '「寝る前にスマホを見ないようにすると、よく眠れる」とあります。', 4);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (31, 10, 'どこからどこへ引っ越しますか。', '東京から大阪へ', '「東京から大阪へ引っ越す」とあります。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (32, 10, '新しいアパートは会社からどのくらいですか。', '徒歩15分', '「会社から徒歩十五分の場所」と書いてあります。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (33, 10, '引っ越しの日はいつですか。', '3月10日', '「引っ越しの日は三月十日です」とあります。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (34, 10, '何をしなければなりませんか。', '銀行と市役所に届け出', '「銀行と市役所に届け出をしなければなりません」とあります。', 4);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (35, 11, '文化祭はいつですか。', '11月3日と4日', '「十一月三日と四日に」とあります。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (36, 11, '二年生は何を販売しますか。', 'たこ焼きとフルーツジュース', '二年生は「たこ焼きとフルーツジュースを用意しています」。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (37, 11, '迷ったら誰に聞けばいいですか。', '赤いリボンのスタッフ', '「赤いリボンをつけたスタッフに聞いてください」とあります。', 3);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (38, 11, '雨天の場合はどうなりますか。', '屋外イベントが中止になることがある', '「一部の屋外イベントが中止になることがあります」と書いてあります。', 4);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (39, 12, '会議が変更された理由は何ですか。', '資料の準備が間に合わない', '「資料の準備が間に合わないため」と理由が書いてあります。', 1);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (40, 12, '新しい会議の日はいつですか。', '再来週の火曜日', '「再来週の火曜日に変更」とあります。', 2);
INSERT INTO public."ReadingQuestion" (id, "passageId", question, answer, explanation, "sortOrder") VALUES (41, 12, '会議室はどこですか。', '三階のB室', 'A室ではなくB室を使用すると書いてあります。', 3);
